-- Poems batch 300
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bb1241dc-1db2-4f92-a363-f87abfd46dc4','句','李復圭','宋','宋诗','song-poetry','','[]','老鳳池邊蹲不去，饑烏臺上噤無聲。',16,'全唐诗/poet.song.33000.json','["老鳳池邊蹲不去，饑烏臺上噤無聲。"]'),
('36663058-1b72-47d8-a106-a361062b0937','題西巖寺三絕  其一','裴大亮','宋','宋诗','song-poetry','','[]','清溪如鑑照行人，谷鳥山花景漸新。',32,'全唐诗/poet.song.33000.json','["清溪如鑑照行人，谷鳥山花景漸新。", "五馬頻來無別事，爲思江上若邪春。"]'),
('0ef55aa7-c0ee-4863-9bc4-e97fd826a1df','題西巖寺三絕  其二','裴大亮','宋','宋诗','song-poetry','','[]','幾領笙歌來賞勝，爲憐山水每忘歸。',32,'全唐诗/poet.song.33000.json','["幾領笙歌來賞勝，爲憐山水每忘歸。", "洞中時與林僧語，不信紅塵有是非。"]'),
('02ad561e-8837-48f1-89c5-67357e633979','題西巖寺三絕  其三','裴大亮','宋','宋诗','song-poetry','','[]','□□□□送行人，山水清音益愴神。',32,'全唐诗/poet.song.33000.json','["□□□□送行人，山水清音益愴神。", "莫惜少留題石□，□□□□□紅塵。"]'),
('15475443-7755-43ad-96ad-21dcb93c55a3','廣慧教寺','裴大亮','宋','宋诗','song-poetry','','[]','政餘飛棹入煙村，數里菰蒲接寺門。',32,'全唐诗/poet.song.33000.json','["政餘飛棹入煙村，數里菰蒲接寺門。", "惟愛弁峰供醉眼，役人詩思到黄昏。"]'),
('1d1c85e1-0b73-4bac-98c0-c9e39d00c8e6','遊安樂山','魯某','宋','宋诗','song-poetry','','[]','苔徑傍巖斜，林間是道家。',24,'全唐诗/poet.song.33000.json','["苔徑傍巖斜，林間是道家。", "夜潭魚戲月，春地鹿眠花。"]'),
('560f28bf-fa9c-4d2c-8db8-4039d7ab1d00','百丈甘','魯某','宋','宋诗','song-poetry','','[]','碧玉纖纖百丈高，仙家曾用醖香醪。',32,'全唐诗/poet.song.33000.json','["碧玉纖纖百丈高，仙家曾用醖香醪。", "至今綠葉挼成酒，不使劉伶更藉糟。"]'),
('14a0fb01-447f-48fc-a886-a3db5f61aa2e','句  其一','魯某','宋','宋诗','song-poetry','','[]','錦步斜開四十里。',8,'全唐诗/poet.song.33000.json','["錦步斜開四十里。"]'),
('7492ecbb-feef-422d-9308-f0621a419648','句  其二','魯某','宋','宋诗','song-poetry','','[]','萬仞青崖碧玉寒，巖蘿相引徹仙壇。',16,'全唐诗/poet.song.33000.json','["萬仞青崖碧玉寒，巖蘿相引徹仙壇。"]'),
('98ef71b0-532f-4491-893b-462fdb24782d','句  其三','魯某','宋','宋诗','song-poetry','','[]','一條仙帔織青霓，松雪巖前伴鶴棲。',16,'全唐诗/poet.song.33000.json','["一條仙帔織青霓，松雪巖前伴鶴棲。"]'),
('fe4ed788-3923-4446-b08f-2e22bfc1a13a','食粥歌','朱申','宋','宋诗','song-poetry','','[]','龍平江水清洋洋，尉山高兮秋葉黄。',87,'全唐诗/poet.song.33000.json','["龍平江水清洋洋，尉山高兮秋葉黄。", "釣翁落落兮棲山房，偕室人兮甘糟糠。", "丈夫壯圖兮在四方，道豈終窮兮業不彰。", "芻蕘有謀兮懷廟堂，一言而興兮悟君王。", "榮祿不計兮德有常，饘粥供飧兮何可忘。"]'),
('70550c9f-d055-48d2-af70-f330f08593dc','題棋山','徐俛','宋','宋诗','song-poetry','','[]','風馭雲轉□渺茫，石奇松老尚蒼蒼。',32,'全唐诗/poet.song.33000.json','["風馭雲轉□渺茫，石奇松老尚蒼蒼。", "留題盡有爭先意，誰識棋山是道場。"]'),
('9baa4b3b-ec57-4656-b698-5b787927b2c2','董奉山','陳師韓','宋','宋诗','song-poetry','','[]','院宇蕭蕭鎖暮烟，昔人曾見此昇仙。',64,'全唐诗/poet.song.33000.json','["院宇蕭蕭鎖暮烟，昔人曾見此昇仙。", "靜看今日流渠水，應是當年煉藥泉。", "座上山川疑改舊，林中僧行盡長年。", "我來寄宿應懷古，始信鄉民不妄傳。"]'),
('a222442a-8c1d-4407-bc54-8e9022bf94b7','題清遠峽和光洞','安昌期','宋','宋诗','song-poetry','','[]','蕙帳將辭去，猨猱不忍啼。',48,'全唐诗/poet.song.33000.json','["蕙帳將辭去，猨猱不忍啼。", "琴書自爲樂，朋友孰相携。", "丹竈非無藥，青雲別有梯。", "峽山余暫隠，人莫擬夷齊。"]'),
('ba68eccc-fd8c-4378-8570-a39a18030811','賦新繁周表權如詔亭','閻灝','宋','宋诗','song-poetry','','[]','承家愛以義，能誨仕之忠。',48,'全唐诗/poet.song.33000.json','["承家愛以義，能誨仕之忠。", "故里推全德，先生有古風。", "中郎銀組白，刺史錦衣紅。", "浩矣無窮樂，春熙醉笑中。"]'),
('f1d700b6-4a09-42ea-8fcb-43c20d87d46e','詩一首','員安輿','宋','宋诗','song-poetry','','[]','國初吾鄉民，萬戶一逢掖。',24,'全唐诗/poet.song.33000.json','["國初吾鄉民，萬戶一逢掖。", "蓋自咸平後，俊髦始接迹。"]'),
('5c9b5f1c-78b6-4a30-9142-dca88f81d032','和周茂叔席上酬孟翱太博','傅耆','宋','宋诗','song-poetry','','[]','古人務樂善，見士即推轂。',192,'全唐诗/poet.song.33000.json','["古人務樂善，見士即推轂。", "今也多忌才，對面遠賢蜀。", "顧予嘗喜學，幽室未偶燭。", "幸會才翹翹，深慚識碌碌。", "升堂聽高論，惟愁日景促。", "經義許叩擊，詩章容往復。", "荷公引重語，玞珉變良玉。", "一違几席來，羲娥變昏旭。", "遠聞落帽節，賓朋相追逐。", "剩摘籬下黄，痛飲杯中醁。", "清談已忘倦，佳篇又相勗。", "畢力爲徒弟，强勉攀高躅。", "異時公行道，其勢不可獨。", "首願策疲蹇，助公施藴蓄。", "舒張太平策，散作蒼生福。", "此心答此惠，庶幾不忝辱。"]'),
('a1c547d1-2a0a-4fc6-876a-37895aaba82c','矸軒','陳寶之','宋','宋诗','song-poetry','','[]','謝公樓上風流客，紫髯蕭疏雙鬢白。',64,'全唐诗/poet.song.33000.json','["謝公樓上風流客，紫髯蕭疏雙鬢白。", "胸中有氣吐虹霓，床頭無金失顔色。", "問君借取騎鶴錢，更欲吸盡長鯨川。", "出門雙槳破寒碧，去學五湖風月仙。"]'),
('956ad363-7af3-419f-ba4c-3e85f23afe68','自述','陳寶之','宋','宋诗','song-poetry','','[]','少年落魄走京華，老大無錢赴酒家。',32,'全唐诗/poet.song.33000.json','["少年落魄走京華，老大無錢赴酒家。", "羞作寺丞門裏客，一片明月照梅花。"]'),
('7333a016-0d4d-4379-a1ad-3293a40ce64b','漫興','陳寶之','宋','宋诗','song-poetry','','[]','二十年前學採樵，採樵只採嫩枝條。',32,'全唐诗/poet.song.33000.json','["二十年前學採樵，採樵只採嫩枝條。", "何如斫倒大松樹，勾得三年兩載燒。"]'),
('fbbbb0a4-2d96-4b38-a43e-95c574b75a02','遊東禪院','王某','宋','宋诗','song-poetry','','[]','曲曲青溪疊疊山，石門深處有禪關。',32,'全唐诗/poet.song.33000.json','["曲曲青溪疊疊山，石門深處有禪關。", "我心自得閒滋味，坐聽風口盡日還。"]'),
('b0a2a8b5-cd40-4006-bad2-ee6580d98537','偈二首  其一','舜禪師','宋','宋诗','song-poetry','','[]','無端被譖枉遭迍，卷載有餘作俗人。',32,'全唐诗/poet.song.33000.json','["無端被譖枉遭迍，卷載有餘作俗人。", "今日再歸三峽寺，幾多道好幾多嗔。"]'),
('d672773e-42a7-4137-8d16-2702b70efa52','偈二首  其二','舜禪師','宋','宋诗','song-poetry','','[]','尋求就理兩俱愆，不涉二途病亦然。',32,'全唐诗/poet.song.33000.json','["尋求就理兩俱愆，不涉二途病亦然。", "孰謂箇中端的處，椎胸貧子一分錢。"]'),
('9b856f41-0537-40c7-ad8f-f2775f85f62f','化前題壁','釋自在','宋','宋诗','song-poetry','','[]','邑尉非常氣勢豪，因談真教反稱褒。',32,'全唐诗/poet.song.33000.json','["邑尉非常氣勢豪，因談真教反稱褒。", "吾家微密皆彰露，又往西天去一遭。"]'),
('06cfb81f-21c0-482c-be3c-5b1f47bac2b6','襄陽','賈黯','宋','宋诗','song-poetry','','[]','带水依山一萬家，襄陽自古富豪奢。',32,'全唐诗/poet.song.33000.json','["带水依山一萬家，襄陽自古富豪奢。", "北軒二月回頭望，紅日連城盡是花。"]'),
('41639b99-7b70-4d72-8277-2094eb253741','重建羊侯祠和王原叔句','賈黯','宋','宋诗','song-poetry','','[]','古郡襄水陽，群山繞郛郭。',144,'全唐诗/poet.song.33000.json','["古郡襄水陽，群山繞郛郭。", "其間峴首者，羊公最所樂。", "登臨見洲渚，氣象真磅礴。", "公乎既已沒，高碑此鑱鑿。", "廟食有遺像，當時盛丹雘。", "到今僅千載，碑廟皆頹落。", "喬木荒榛間，廟址存依約。", "碑倒石屢易，文字免缺錯。", "我侯至之初，亭廟皆新作。", "爲詩道其意，風化思所託。", "侯慕羊公心，仁政及物博。", "將見襄陽治，與古相侔若。"]'),
('6638fea2-6583-48c6-b12a-e7a53bb4bdc4','寄夾山芳別圃','趙世延','宋','宋诗','song-poetry','','[]','本來包却太虛空，萬象森羅立下風。',32,'全唐诗/poet.song.33000.json','["本來包却太虛空，萬象森羅立下風。", "假使悠悠千百世，聖人復出此心同。"]'),
('473a655d-ea96-4945-a874-d30da63bbd88','舒州寄王介甫','曾宰','宋','宋诗','song-poetry','','[]','官居隠几望灊山，不似茅檐舊日閑。',64,'全唐诗/poet.song.33000.json','["官居隠几望灊山，不似茅檐舊日閑。", "顧我塵沙添白髮，憐君道路失朱顔。", "江涵秋老鱸魚美，岸入春風荻笋斑。", "此味縱佳吾不樂，惟思一馬返鄉關。"]'),
('13fea458-95c9-4db9-8ce7-2db7af3b3d91','雜興三首  其一','鄭獬','宋','宋诗','song-poetry','','[]','女媧鍊五石，上補天之缺。',96,'全唐诗/poet.song.33000.json','["女媧鍊五石，上補天之缺。", "如錮黄金液，萬古無由裂。", "堯舜首制度，巨防高巀嵲。", "後世日破穿，通爲萬鼠穴。", "譬彼果蓏蟲，熟爛恣攻嚙。", "豈無良工手，一起爲施設。", "非若天之難，前輩有夔卨。", "苟或不關心，女媧亦爲拙。"]'),
('6fa4a43d-cb6d-4861-9fce-f7a5a2863a37','雜興三首  其二','鄭獬','宋','宋诗','song-poetry','','[]','塊泥封兩耳，師曠亦爲聾。',84,'全唐诗/poet.song.33000.json','["塊泥封兩耳，師曠亦爲聾。", "離朱捏兩目，觸面不得通。", "折弓斷其臂，安得爲逢蒙。", "白日照六合，光耀當天中。", "苟爲物所蝕，齯齒猶成童。", "君子誠其意，默通大化工。", "所以虞舜明，不在雙重瞳。"]'),
('91987060-99cf-4639-a83b-ce115d328207','雜興三首  其三','鄭獬','宋','宋诗','song-poetry','','[]','秦皇按長劍，殺人如刈草。',96,'全唐诗/poet.song.33000.json','["秦皇按長劍，殺人如刈草。", "何獨李斯輩，竟以丞相老。", "漢元服儒衣，收諫如蓄寶。", "何獨蕭望之，誅鉏恨不早。", "滄海飛天波，枯澤淤行潦。", "劉累嬰其喉，蛟龍不爲暴。", "魯士固多賢，親師仲尼道。", "至於出處間，惟有顔生到。"]'),
('dd85e5e2-b580-4886-a29c-6b05691d626e','感秋六首  其一','鄭獬','宋','宋诗','song-poetry','','[]','落日在高木，輝輝淡秋容。',96,'全唐诗/poet.song.33000.json','["落日在高木，輝輝淡秋容。", "白雲起天鏡，飛去忽無蹤。", "雨蘚爛漫紫，幽徑誰相從。", "孤慮如有根，糾結生心胸。", "良時忽已晚，撇耳過晨鐘。", "事業餘濩落，撫己真何庸。", "投箸不能食，却立倚長松。", "酒敲百萬兵，此憂不可攻。"]'),
('cbae606e-880f-4297-a263-785faa9a2922','感秋六首  其二','鄭獬','宋','宋诗','song-poetry','','[]','短松青鐵幹，童童三尺餘。',96,'全唐诗/poet.song.33000.json','["短松青鐵幹，童童三尺餘。", "花實少姿媚，獨與寒心俱。", "暴霜時侵凌，奮怒張雄鬚。", "長楸擁腫材，旁蔭可容車。", "秋風一夕來，解剝惟朽株。", "物性在堅柔，何必長短殊。", "楸葉已泥滓，松幹猶青膚。", "無煩問高下，且辨榮與枯。"]'),
('c0c022b7-7140-4e5c-9ce9-12e40c5daadc','感秋六首  其三','鄭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我思洞庭橘，赤金三寸圓。',84,'全唐诗/poet.song.33000.json','["我思洞庭橘，赤金三寸圓。", "磊落火齊珠，綴樹團紫烟。", "病肺燥不治，噓吐氣欲然。", "玉醴埋九地，鑿井不得泉。", "我欲涉洞庭，採橘秋雲邊。", "駭浪破我舟，蛟龍怒騰騫。", "安得萬里風，吹落墮我前。"]'),
('4c82d2bc-c533-4978-a671-7b8b18c6caa1','感秋六首  其四','鄭獬','宋','宋诗','song-poetry','','[]','日車輾東井，一陰穿土生。',96,'全唐诗/poet.song.33000.json','["日車輾東井，一陰穿土生。", "死草出飛火，殺機從此萌。", "况及八月秋，大昴騰光精。", "氣勢日發勵，乾坤露崢嶸。", "萬木赤立死，百蟲相弔鳴。", "菲菲黄菊花，幽叢發孤英。", "採擷對樽酒，悲歌不能傾。", "所悲陽德消，日與群陰爭。"]'),
('93752a1b-0afd-47a5-aff4-ff1bf7874431','感秋六首  其五','鄭獬','宋','宋诗','song-poetry','','[]','林杪一蟬噪，翛翛凉風來。',84,'全唐诗/poet.song.33000.json','["林杪一蟬噪，翛翛凉風來。", "清響斷復連，裂耳增餘哀。", "浩露洗明月，珠樹凉璀璀。", "蛻飛各有時，詎能人力裁。", "儒生守文字，舌腐猶蒿萊。", "空腸貯古書，獨立誰爲媒。", "咄哉丈夫氣，胡爲久徘徊。"]'),
('17a154f6-02f6-481c-877b-f2045cfa75a2','感秋六首  其六','鄭獬','宋','宋诗','song-poetry','','[]','軒軒蒼角鷹，殺氣淩高秋。',96,'全唐诗/poet.song.33000.json','["軒軒蒼角鷹，殺氣淩高秋。", "一息一萬里，獨與長風遊。", "獵騎走霹靂，落臂無虛投。", "古冢白鼻狐，立死不得留。", "飛霜未殺草，擁翅寒胡愁。", "畜力以待奮，仁如林中鳩。", "今茲順天誅，狡穴破奸謀。", "美哉青骹姿，識時誰與儔。"]'),
('3a0b4a45-156c-4a8f-8fef-91fa4dc7dd9f','秋聲','鄭獬','宋','宋诗','song-poetry','','[]','蚯蚓如嘒管，逢時土中鳴。',48,'全唐诗/poet.song.33000.json','["蚯蚓如嘒管，逢時土中鳴。", "秋蟬抱枝死，不敢鼓秋聲。", "聽者何無厭，忽如鳴秦箏。", "大雨漂九土，曠蕩空太清。"]'),
('7ba03306-bb79-4189-8ec5-87dbfdd6cfe1','回次媯川大寒','鄭獬','宋','宋诗','song-poetry','','[]','地風如狂兕，來自黑山旁。',168,'全唐诗/poet.song.33000.json','["地風如狂兕，來自黑山旁。", "坤維欲傾動，冷日青無光。", "飛沙擊我面，積雪沾我裳。", "豈無玉壺酒，飲之冰滿腸。", "鳥獸不留迹，我行安可當。", "雲中本漢土，幾年非我疆。", "元氣遂隳裂，老陰獨盛强。", "東日拂滄海，此地埋寒霜。", "况在窮臘後，墮指乃爲常。", "安得天子澤，浩蕩漸窮荒。", "掃去妖氛俗，沐以楚蘭湯。", "東風十萬家，畫樓春日長。", "草踏錦靴緣，花入羅衣香。", "行人卷雙袖，長歌歸故鄉。"]'),
('a6285d36-ec31-4e46-82ac-d429112771ee','大寒呈張太博','鄭獬','宋','宋诗','song-poetry','','[]','寒風怒蓬勃，排戶入吾室。',264,'全唐诗/poet.song.33000.json','["寒風怒蓬勃，排戶入吾室。", "沙灰漲天黑，白日赤黄色。", "捉衣擁肩坐，心脾寒憀慄。", "須臾天氣變，陰黯如塗漆。", "跳空雨雹飛，四走珠璣出。", "數子方嘆驚，共怪天公逸。", "先生携書來，昂頤杖飛策。", "乃召二三子，環坐與之席。", "呼童令取酒，盤飣雜梨栗。", "酒行寒氣除，春陽生四壁。", "先生說大義，馳騖何纖悉。", "洞徹人精神，兩耳飛霹靂。", "老語植根節，九牛不可屈。", "堯眉與舜目，緬若曾相識。", "如當夜黑中，光耀見赤日。", "退思聖賢業，所積在劘剔。", "韋皮畫山龍，塊泥亦瓦礫。", "人固有識智，非如物之植。", "而不自刻苦，晝夜如刀尺。", "年齒方壯健，男兒宜努力。", "方今太平民，尚未獲蘇息。", "誰能拱兩手，看人樹勳績。"]'),
('caaabf31-3e3b-4b3b-9dba-5525bd79cd49','迫晚風雪出省咏張公達紅梅之句','鄭獬','宋','宋诗','song-poetry','','[]','雪花障路飛，飄濕紅杏韉。',180,'全唐诗/poet.song.33000.json','["雪花障路飛，飄濕紅杏韉。", "歸馬碧蹄疾，踏破白玉田。", "攬轡獨長想，物境真可憐。", "朝紱未掛身，豪逸倚少年。", "結客上高樓，珠箔遮碧天。", "燒酒紫煙沸，割炙白膏鮮。", "美人挪素手，笑弄琵琶絃。", "醉眼生亂雲，不省到家眠。", "俊遊或如失，倒指還摻然。", "薄莫出華省，下馬燈已燃。", "强笑破老顔，寄恨揮華箋。", "翫世張公子，嗜酒真神仙。", "拋擲咏紅梅，負伊清樽前。", "再讀再三嘆，心斷空悁悁。", "起予如繭絲，織愁成短篇。"]'),
('43b6d1ce-c112-4d7d-8d47-1731ad16b77f','雷震','鄭獬','宋','宋诗','song-poetry','','[]','四月老陽盡，蟄雷方發聲。',156,'全唐诗/poet.song.33000.json','["四月老陽盡，蟄雷方發聲。", "七月連大雨，碾天三日鳴。", "夜或發狂震，卧者皆起驚。", "奔電曄然作，忽如烈火明。", "高樹大百尺，霹倒燒其根。", "往往光曜中，時見怪物形。", "飛雹大如指，萬弩相奔傾。", "椎擊鳥雀群，掩地交縱橫。", "雷者主號令，爲天之常經。", "奮豫既過時，及此何匉訇。", "無乃號令失，安得四時平。", "春秋書震電，推之在五行。", "天道儻可信，使我心不寧。"]'),
('2cae358d-44e1-4708-ad5d-265ef5a2edea','冬日同仲巽及府寮遊萬壽寺','鄭獬','宋','宋诗','song-poetry','','[]','峻阜如蟠虹，蓄泄氣象靈。',240,'全唐诗/poet.song.33000.json','["峻阜如蟠虹，蓄泄氣象靈。", "紺宇隠紅樹，繚若畫在屏。", "聯騎轉城角，沙步俯回汀。", "野寺對寒水，白壁敞雲扃。", "嶚深松桂黑，地古莓苔青。", "朱橘擁繁梢，懸綴黄金鈴。", "橫梯出虛閣，古像銅青熒。", "眺聽揖秋境，豁露無藏形。", "清氣換俗骨，蕭爽毛髮醒。", "汲泉煮露芽，却坐竹間亭。", "高談落四座，金石朗衆聽。", "脫落見逸調，驟如馬在坰。", "眇然遺組紱，太山一浮萍。", "落景不我顧，檐角出寒星。", "燕客未渠央，歸鞍安得停。", "歲宴幸豐樂，楚人飽且寧。", "蟋蟀刺褊陋，及時灑子庭。", "傳聞落帽山，風凉久凋零。", "已釀白玉泉，連車載百瓶。", "行期一佳賞，相與快煩冥。"]'),
('95fcb188-0c46-44b3-9ba1-83c8837bea8b','直宿省中','鄭獬','宋','宋诗','song-poetry','','[]','娟娟海棠花，小蕊春來瘦。',48,'全唐诗/poet.song.33000.json','["娟娟海棠花，小蕊春來瘦。", "斑斑青竹枝，疏葉未生就。", "碧砌畫欄干，雨斷黄昏後。", "厭酒未能眠，時拾殘花嗅。"]'),
('5794b710-a23a-479c-8345-c0fd981ca434','奉使過居庸關  其一','鄭獬','宋','宋诗','song-poetry','','[]','鐵山五十里，𤡑獸不能逾。',190,'全唐诗/poet.song.33000.json','["鐵山五十里，𤡑獸不能逾。", "兩壁如夾城，行人貫衆魚。", "巨關隔元氣，寒暑南北殊。", "一夫扼其鍵，萬馬不能趨。", "石氏窺三川，荒唐誰與謨。", "不能仗大義，割地事匈奴。", "封樹未拱把，敵騎已長驅。", "後嗣竟銜璧，白衣拜穹廬。", "自此失天險，一柱折坤輿。", "世宗有英氣，手撼崑崙墟。", "關南下六城，卧病歸東都。", "太祖得天下，僭竊即爲誅。", "右顧取蜀漢，左顧平荆吳。", "欲藏百萬縑，萬里購頭顱。", "可用一赤組，坐使縛單于。", "奇策秘九地，白日忽。"]'),
('7787aceb-638d-426f-a134-7866b095c996','奉使過居庸關  其二','鄭獬','宋','宋诗','song-poetry','','[]','西徂。',123,'全唐诗/poet.song.33000.json','["西徂。", "壯士折其弓，痛哭望鼎湖。", "先帝務養民，束箒不忍除。", "歲時遺繒絮，天府藏丹書。", "桑柘入燕山，牛羊卧平蕪。", "我行謬使節，踏冰出中塗。", "路傍二三老，幅巾垂白鬚。", "喜見漢衣冠，叩首或欷歔。", "不能自拔掃，百年落鬼區。", "天數終有合，行上督亢圖。", "酹酒弔遺民，淚濕蒼山隅。"]'),
('99a48ad9-0bb8-4d9a-82f8-45f454af26a6','湖上','鄭獬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋影落西湖，淥波浄如眼。',72,'全唐诗/poet.song.33000.json','["秋影落西湖，淥波浄如眼。", "摇船入芰荷，船裏清香滿。", "花深不見人，但聽歌聲遠。", "還從過船處，折倒青荷傘。", "爲採秋芳多，不覺飛霞晚。", "回船未到堤，更引金蓮盞。"]'),
('9ef9801a-dd8e-48b3-85f3-4a3ecde566de','湖上遇雨','鄭獬','宋','宋诗','song-poetry','','[]','老龍怒相搏，快雨忽噴灑。',132,'全唐诗/poet.song.33000.json','["老龍怒相搏，快雨忽噴灑。", "天公白羽箭，竦竦射萬瓦。", "電眼窺人屋，狂雷震欲下。", "直疑惡溪山，掃除重造化。", "頃之蒼雲裂，天光出縫罅。", "變怪忽寂寥，乾坤似新畫。", "秀靄翠堪包，清風健可跨。", "林影走群龍，溪聲回萬馬。", "更無一塵飛，清光熨平野。", "沙路浄無泥，侵凉宜早駕。", "高堂應念歸，屈指期到舍。"]'),
('29ec57a0-e75a-408b-9dc1-b11468545de7','入采石','鄭獬','宋','宋诗','song-poetry','','[]','始飲秦淮水，已湔京洛纓。',48,'全唐诗/poet.song.33000.json','["始飲秦淮水，已湔京洛纓。", "自嫌塵土迹，恐污江山清。", "太虛淡秋影，霜物尤疏明。", "擬問白雲公，貰此秋岩耕。"]'),
('6e25ee28-ff0a-4f13-86bf-9b4addc89702','汴河曲','鄭獬','宋','宋诗','song-poetry','','[]','朝漕百舟金，暮漕百舟粟。',216,'全唐诗/poet.song.33000.json','["朝漕百舟金，暮漕百舟粟。", "一歲漕幾舟，京師猶不足。", "此河百餘年，此舟日往復。", "自從有河來，宜積萬千屋。", "如何尚虛乏，僅若填空谷。", "歲或數未登，飛傳日逼促。", "嗷嗷衆兵食，已憂不相屬。", "東南雖奠安，亦宜少儲蓄。", "奈何盡取之，曾不留斗斛。", "秦漢都關中，厥田號衍沃。", "二渠如肥膏，凶年亦生穀。", "公私富囷倉，何必收珠玉。", "因以轉實邊，邊兵皆飽腹。", "不聞漕汴渠，尾尾舟銜軸。", "關中地故存，存渠失淘斸。", "或能尋舊源，鳩工鑿其陸。", "少緩東南民，俾之具饘粥。", "茲豈少利哉，可爲天下福。"]'),
('58529651-2280-4fa6-aff5-2515ce4b03a8','寄題辰州沅陽館','鄭獬','宋','宋诗','song-poetry','','[]','張侯守辰溪，作館清溪上。',228,'全唐诗/poet.song.33000.json','["張侯守辰溪，作館清溪上。", "峻趾擁崇岡，跋海鰲足壯。", "石嶝盤山回，遊人出屏障。", "林壑互蔽虧，昏明各異狀。", "辰溪俯洞夷，登臨少佳况。", "不知自何人，於此廢真賞。", "漥池失蛟龍，破屋藏魍魎。", "如持萬黄金，棄之在污壤。", "張侯一芟掃，耳目復清曠。", "坤倪伏詼譎，閃倐見氣象。", "素壁照清秋，檐牙屹相望。", "啼鳥共徘徊，飛雲自來往。", "携樽聽鳴泉，便可傾佳釀。", "煙披舞袖潤，谷應歌聲響。", "客醉未容歸，明月纖纖上。", "幽懷儻自得，所適即爲放。", "茲地雖陋僻，境靜猶足尚。", "壯士偃旗眠，落日惟樵唱。", "緩带一來遊，清風日蕭爽。"]'),
('7c85acac-f366-4cb3-83d1-a7d282a3319a','戍邕州','鄭獬','宋','宋诗','song-poetry','','[]','兵符下西州，將軍催部伍。',204,'全唐诗/poet.song.33000.json','["兵符下西州，將軍催部伍。", "鳴鑼張大旗，早發邕州戍。", "家家送出城，走哭遮行路。", "邕州萬里餘，北人那可去。", "毒草見人摇，雄虺大如樹。", "二月瘴煙發，薰蒸劇甑釜。", "病者如倒林，十纔起四五。", "偶有脫死歸，扶杖皆病僂。", "逃生既不暇，安能捕寇虜。", "跳踴一蠻來，取之易攫鼠。", "顧彼有土人，揮金可召募。", "狃練得精卒，亦足爲爪距。", "妻兒蓄里閭，於心必愛護。", "較之勇怯間，相去猶豚虎。", "一朝有緩急，伸縮用臂股。", "何必遣戍兵，觳觫就死所。", "願留中州人，無填嶺南土。"]'),
('d0a59837-fa8d-4f84-b148-d7d049436979','留侯廟','鄭獬','宋','宋诗','song-poetry','','[]','留侯仗奇策，十年藏下邳。',240,'全唐诗/poet.song.33000.json','["留侯仗奇策，十年藏下邳。", "狙擊秦始皇，獨袖紫金椎。", "茲爲少年戲，聊夸游俠兒。", "退學黄石書，始見事業奇。", "兩龍鬥不解，天地血淋漓。", "攝袖見高祖，成敗由指麾。", "重寶啗諸將，嶢關遂不支。", "斥去六國謀，輟食駡食其。", "卒言信布越，可以爲騎馳。", "餘策及太子，四老前致詞。", "立談天下事，坐作帝王師。", "功名竟糠粃，撥去曾亡遺。", "往從赤松遊，世網不能羈。", "韓彭死鐵鉞，蕭樊困囚纍。", "榮辱兩不及，孤翮愈難追。", "陳留本故封，道左空遺祠。", "兩鬼守其門，帳坐盤蛟螭。", "威靈動風雲，飄爽回旌旗。", "我來謁祠下，文章竟何爲。", "長嘯咏高風，三日不知饑。"]'),
('96739984-b0af-414f-b2d0-c265fbef5738','遊清凉寺','鄭獬','宋','宋诗','song-poetry','','[]','野思不可收，瞥若孤雲生。',48,'全唐诗/poet.song.33000.json','["野思不可收，瞥若孤雲生。", "船頭插芳草，閒踏飛花行。", "春江摇夕陽，綠波鱗鱗明。", "更欲待潮歸，高城聞鼓聲。"]'),
('e39622dd-84ea-4d9a-9b9b-28e79766e976','夜半','鄭獬','宋','宋诗','song-poetry','','[]','夜半群動息，高車始停輪。',48,'全唐诗/poet.song.33000.json','["夜半群動息，高車始停輪。", "白日苦不沒，役死天下人。", "黄金埋九地，家家惡賤貧。", "安得充所欲，不蹈通衢塵。"]'),
('2ffc1fd6-0a6b-417c-8c29-9f03a81c9a14','記夢','鄭獬','宋','宋诗','song-poetry','','[]','赤城老仙翁，面發日月華。',48,'全唐诗/poet.song.33000.json','["赤城老仙翁，面發日月華。", "獨立石巖下，手把蟠桃花。", "授我碧簡文，奇篆蟠丹砂。", "讀之不可曉，翻身淩紫霞。"]'),
('35849a5f-e39d-40e3-88fd-3ddc8e5b462f','蘇刑部自湖北移漕淮南','鄭獬','宋','宋诗','song-poetry','','[]','先公道義交，晚得蘇公佐。',252,'全唐诗/poet.song.33000.json','["先公道義交，晚得蘇公佐。", "俾予往拜之，兄事安敢墮。", "漂忽十五年，日月如旋磨。", "近佩荆州符，吏牘方自課。", "蘇侯乃外臺，庶幾容謬懦。", "若獲巨木陰，似翳桑下餓。", "相約待秋深，事隙得高卧。", "風灑渚宮凉，碧溪絕塵涴。", "穿林或倦行，拂石還分坐。", "夙懷詎彷彿，幽事信坎坷。", "除書走馬來，換節長淮左。", "嗟予踽踽遊，有唱期誰和。", "楚老遮郭門，扳留知不可。", "別酒雖無歡，歸帆幸少垛。", "蘇侯賢大夫，歷數今誰過。", "議論抵廟堂，有力莫能破。", "挺如白玉圭，稜角不可挫。", "大匠斲明堂，宜居左右個。", "猶馳使者車，挾策均萬貨。", "淮人久焦枯，蘇息在欬唾。", "傾酒吐長言，遥爲淮人賀。"]'),
('eeeda618-00a4-4e3e-b10a-1c41146c7711','送呂稚卿郎中奉使江西','鄭獬','宋','宋诗','song-poetry','','[]','赤蛟卧淺水，頭角不可藏。',228,'全唐诗/poet.song.33000.json','["赤蛟卧淺水，頭角不可藏。", "天公果見之，叱起南山傍。", "吳侯蓄奇才，投刃誰能當。", "百吏如群鴉，簿領埋屋梁。", "據案即時决，眸子愈精光。", "不試巨鰲足，包裹百鍊鋼。", "如何若漫浪，華省亦爲郎。", "日署百十字，支頤對脩篁。", "酒醒晚意悶，睡美春味長。", "閒甚却索寞，相遇必壺觴。", "平子亦疏放，爾我兩相忘。", "昨日鳳凰下，詔書五色行。", "特賜黄金魚，付以十州强。", "江山亦畏威，指顧隨低昂。", "乃知飛龍廄，放出真乘黄。", "一秣一萬里，爭路看騰驤。", "此行况秋色，碧江襟袖凉。", "啄黍黄雀肥，鰣魚如截肪。", "願加數匕飯，以慰長相望。"]'),
('d3bc3419-00d7-486c-b599-f128195c08cf','送元待制知福州','鄭獬','宋','宋诗','song-poetry','','[]','常公廊廟姿，龍節殿南區。',144,'全唐诗/poet.song.33000.json','["常公廊廟姿，龍節殿南區。", "鑿開文章源，儒學比蜀都。", "儀儀天章老，秀色發東吳。", "相望三百載，還擁朱轓車。", "風帆入天境，雲際如飛鳬。", "到郡省風俗，少住使君旟。", "邦人愛文字，小吏亦詩書。", "歐生死北土，仙山失璠璵。", "魁怪遂橫行，聖人惡奪朱。", "願公正禮法，引之君子塗。", "騤騤萬馬群，必有真龍駒。", "它時楊得意，自可薦相如。"]'),
('b3b07f00-89a1-47f7-b697-03751034784e','送岷山楊道士遊廬山','鄭獬','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u897f\u6e56"]','獨鶴志萬里，不肯安故林。',240,'全唐诗/poet.song.33000.json','["獨鶴志萬里，不肯安故林。", "排翮下岷山，浩蕩窮幽尋。", "初來識京師，魏闕鬰蕭森。", "講書勤萬乘，賜服照華簪。", "群公作詩贈，却轉清淮潯。", "振策寄靈隠，採芝宿孤岑。", "明月落西湖，澒洞萬頃金。", "遂斷浙江潮，噴薄白日陰。", "芙蓉滿越國，耶溪秋水深。", "欲追二老迹，赤城窈嶔崟。", "海月入長嘯，山風吹醉襟。", "回橈姑孰溪，相逢慰予心。", "綠髮頎而長，蕭灑見球琳。", "共飛秋浦帆，飄若雲間禽。", "捨我入廬阜，煙蘿極登臨。", "瀑布瀉天來，飛雪寒涔涔。", "手攀青桂枝，側聽白猿吟。", "倚石讀周易，臨流揮素琴。", "於此可忘老，身世隨浮沉。", "若見荆州客，爲傳金玉音。"]'),
('37f96483-3df8-4c42-8f56-b85cebe61cbf','陪程太師宴柳湖歸','鄭獬','宋','宋诗','song-poetry','','[]','鳴珂曉日動，畫旗春風斜。',168,'全唐诗/poet.song.33000.json','["鳴珂曉日動，畫旗春風斜。", "馬蹄碧玉砧，踏破黄金沙。", "夾路盡高柳，屹如紺璧遮。", "草軟藉遊人，樹暖啼嬌鴉。", "長湖畜元氣，飛亭插蒼霞。", "開樽適逸調，笑言醉方嘩。", "人意重於春，酒香濃勝花。", "所嗟無壯士，挽住白日車。", "上馬橫馱歸，不省歸到家。", "淮陽有此境，足爲天下誇。", "要路諳機穽，㹞㹞爭齒牙。", "願公且留鎮，所得歡無涯。", "卷袖倒大白，秀髮欹烏紗。", "時與東風期，一來賞春花。"]'),
('6233b769-bef4-4998-a53f-aeb53241622f','春日陪楊江寧宴感古作','鄭獬','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5bb4\u4f1a", "\u611f\u6168"]','昔聞顔光祿，攀龍宴京湖。',168,'全唐诗/poet.song.33000.json','["昔聞顔光祿，攀龍宴京湖。", "樓船入天鏡，帳殿開雲衢。", "君王歌大風，如樂豐沛都。", "延年獻嘉作，邈與詩人俱。", "我來不及此，獨立鍾山孤。", "楊宰穆清飆，芳聲騰海隅。", "英寮滿四座，粲若瓊林敷。", "鷁首弄倒景，蛾眉掇明珠。", "新絃採梨園，古舞嬌吳歈。", "曲度繞雲漢，聽者皆歡娛。", "鷄棲何嘈嘈，沿月沸笙竽。", "古之帝宮苑，今乃人樵蘇。", "感此勸一觴，願君覆瓢壺。", "榮盛當作樂，無令後賢吁。"]'),
('7f5ff617-f4ee-4f21-b252-783f94cfe773','稚卿約郭外之遊','鄭獬','宋','宋诗','song-poetry','','[]','舉世尚刻飾，趨時獨放達。',252,'全唐诗/poet.song.33000.json','["舉世尚刻飾，趨時獨放達。", "醉眼挂飛雲，孤心貯明月。", "大匠坐高堂，群材就剞劂。", "楩楠即赤霄，容此蟠根屈。", "平明萬馬趨，玉鎖開雙闕。", "晴雲暖不收，飛繞龍旗闊。", "堯眼八采眉，下燭天光發。", "鸞鵠出閶門，穩路平沙滑。", "簾額見春輝，竹陰摇省闥。", "萬事攪乾坤，紛紛卷巾髮。", "安得黄金篦，靜把塵相刮。", "屈指待春遊，烟沸喉咽渴。", "擁樹雪花消，中庭潤於潑。", "臘酒寒未壓，玉醅猶可撥。", "東風自愛花，已入香梢活。", "醉友好相尋，烟郊綠如抹。", "無爲世網牽，直把名韁脫。", "白浪漂山來，意在秋毫末。", "險徑雖可通，驊騮中一跋。", "兩耳厭俗論，乍喜春泉聒。", "躍馬携金樽，風雨不可奪。"]'),
('524dbdd7-c11a-4854-9d01-8b46f6d4d7f6','懷顧子惇','鄭獬','宋','宋诗','song-poetry','','[]','託身事權門，譬如狎彫虎。',108,'全唐诗/poet.song.33000.json','["託身事權門，譬如狎彫虎。", "餧之得其欲，弭首乃無怒。", "苟或咈其心，騰爪必傷汝。", "權門愛曲從，破殻出毛羽。", "一語不相酬，隨手覆塵土。", "禍福非不明，焦爛猶奔赴。", "聳動會稽山，山前有直路。", "鑄金不作鈎，斷木寧爲矩。", "終歲守衡茅，藜藿甘辛苦。"]'),
('550d43f3-c895-4b04-989e-67a3a1f31ca3','贈朱省郎','鄭獬','宋','宋诗','song-poetry','','[]','蕭灑不羈性，本自出塵埃。',144,'全唐诗/poet.song.33000.json','["蕭灑不羈性，本自出塵埃。", "棄去萬物累，健翅天地回。", "白髮朱省郎，巀嶪稱高才。", "春風如故人，昨日天涯來。", "置酒畫堂晚，勸我白玉杯。", "調笑脫俗態，高談若風雷。", "歸來碧窗靜，殘照寒徘徊。", "豈知丈夫志，力劈青雲開。", "孤坐淚橫臆，慷慨無良媒。", "世事如轉蓬，竟日千萬回。", "捩翅凌赤霄，欲拉高山摧。", "誰可料前途，使我孤心哀。"]'),
('bf82e23f-7603-4fa0-b3df-af48e49a1585','送方元忠','鄭獬','宋','宋诗','song-poetry','','[]','京師惡塵土，兩足沒至踝。',288,'全唐诗/poet.song.33000.json','["京師惡塵土，兩足沒至踝。", "狂風暴然作，塞天赤如赭。", "事牽或出門，復又無馿跨。", "垢汗黏透衣，留遲固不遐。", "走歸掃一室，凉泉急傾灑。", "琢琢客扣門，置帽懶出迓。", "呼童揖客進，客語驚鄰舍。", "自夸已得計，歸舟即日駕。", "風塵久厭苦，喜此脫去乍。", "淮影貯蒼山，飛峰皆倒挂。", "霜月秋暉明，乾坤曝圖畫。", "往往窮谷間，賢豪伏其下。", "去而從之遊，精粗得陶冶。", "剖發露光鋩，爬羅無縫罅。", "豨膏滑兩軸，直縱飛黄靶。", "庶以卒吾業，孰能籌周捨。", "余云子語健，决去不可且。", "伊昔同壯遊，清樽固屢把。", "病酒常至午，醉歸每及夜。", "朋輩俱飲豪，斗酒快一寫。", "窮甚或見憐，怪極亦遭駡。", "爾來五六年，退縮但嗟訝。", "老意漸相期，歡心早已謝。", "買得東皋田，束衣即歸稼。"]'),
('6f2eae0e-6a82-4fef-8882-0ed69ef09a2c','夜坐寄正夫','鄭獬','宋','宋诗','song-poetry','','[]','月落如玉虹，飛過梧桐枝。',48,'全唐诗/poet.song.33000.json','["月落如玉虹，飛過梧桐枝。", "開懷待歸風，如與佳人期。", "白雲嬌娞嫷，綠樹凉參差。", "安得餌瓊華，慰此終夕饑。"]'),
('2ff40fe6-2649-4baf-87dd-6d63fb4727dc','扶溝白鶴觀有蘇子兄弟贈黄道士詩二闋縣令周原又以三篇紀之邀余同作','鄭獬','宋','宋诗','song-poetry','','[]','道士黄初平，愛酒老不衰。',48,'全唐诗/poet.song.33000.json','["道士黄初平，愛酒老不衰。", "二豪留醉墨，瀟灑白雲辭。", "流鶑境寂寞，無復落花枝。", "空餘鳳凰字，猶得周郎悲。"]'),
('3816aaa0-459a-46f1-837f-9173c3cb5f26','哭渭夫二兄','鄭獬','宋','宋诗','song-poetry','','[]','生平抱直氣，鬼神不敢干。',288,'全唐诗/poet.song.33000.json','["生平抱直氣，鬼神不敢干。", "乃從異物化，使我涕泗瀾。", "昔之初拜兄，申申從太原。", "府公頗好事，鑿地種琅玕。", "築學百餘室，吾徒得所盤。", "嘈嘈誦古書，鄰家嫌聒煩。", "間日課辭章，據義相譏彈。", "兄時處乎中，竦竦如長竿。", "負氣頗剛簡，未嘗媚語言。", "與衆不相合，節角難爲刓。", "而獨顧我喜，謂如椒在蘭。", "璞玉逢礪石，圭璧不爲難。", "離合雖屢更，於義則相完。", "應舉來京師，羈旅誰爲歡。", "投篋寄兄舍，乃同在家安。", "我常劇醉歸，吐嘔几席間。", "獨兄在我旁，撫眎夜不眠。", "雖非共飽乳，此意何疏親。", "向雖聞兄病，已云不能餐。", "日唯飲醇酒，無乃酒爲患。", "昨暮得報書，遂死不復還。", "擲書一痛哭，痛甚連心肝。", "恨我有此身，不生雙羽翰。", "摶風一飛去，瀝酒哭其棺。"]'),
('232e6e4f-d9bf-41a8-859c-b3845008a76d','送趙書記赴闕','鄭獬','宋','宋诗','song-poetry','','[]','草頭烟霏霏，草影摇斜暉。',48,'全唐诗/poet.song.33000.json','["草頭烟霏霏，草影摇斜暉。", "殘花猶綴枝，故人何日歸。", "不惜殘花飛，惟惜故人稀。", "酒到君莫辭，淋漓從滿衣。"]'),
('d6cd79f7-86be-4772-8690-933aa6f27a3f','勉陳石二生','鄭獬','宋','宋诗','song-poetry','','[]','精金埋深山，鑿土不難得。',288,'全唐诗/poet.song.33000.json','["精金埋深山，鑿土不難得。", "大貝貯滄海，破浪亦能識。", "山趨猛虎穴，海入長蛟室。", "必意往取之，投軀不少惜。", "仁義藏遺書，堯孔聖人迹。", "不觀不知道，觸塗暗於漆。", "上無猛虎畏，下無長蛟逼。", "污辱不及身，燦燦嵬山璧。", "金貝豈飽腹，盜窺恐易失。", "纍纍畜滿家，僅能一身佚。", "孰謂遺書貧，猗頓莫能易。", "其源固不貲，可爲天下澤。", "二子齒甚少，蚤莫宜加力。", "剖剝見光鋩，拄天一千尺。", "勿逐籬下雛，自跨鳳凰翼。", "雄聲落衆耳，白日飛霹靂。", "偏親况在堂，雪縷初垂白。", "淚眼望榮歸，一書千萬億。", "夜燈綻寒衣，秋風吹素壁。", "胡爲不奮飛，跳躍在泥磧。", "北闕挂賢科，將相嘗曾歷。", "五犗垂巨鉤，往往長鯨食。", "學飽遂騫翔，青雲無物隔。", "右顧玉堂人，左揖金鼎客。"]'),
('f4a1cabd-4942-4ae7-9750-d2e8b886bebd','別小女','鄭獬','宋','宋诗','song-poetry','','[]','一別寸腸破，再別玄髮衰。',48,'全唐诗/poet.song.33000.json','["一別寸腸破，再別玄髮衰。", "人生無百年，那堪長別離。", "萬事從委蛻，漆園真誕辭。", "去去復何言，東風雙淚垂。"]'),
('b7ff9b99-6f5a-4193-b8c8-0eb5b640fd54','咏竹寄元忠','鄭獬','宋','宋诗','song-poetry','','[]','寄卧丞相廬，東軒富脩竹。',48,'全唐诗/poet.song.33000.json','["寄卧丞相廬，東軒富脩竹。", "如對古賢人，高標鎮浮俗。", "露氣沃人清，烟色沾衣綠。", "丹鳳何時來，瘦損琅玕玉。"]'),
('61eb177a-0250-49c7-a689-93951ef739b2','對雪寄一二舊友呈張仲巽宗益運判','鄭獬','宋','宋诗','song-poetry','','[]','少年喜風雪，走上百尺樓。',204,'全唐诗/poet.song.33000.json','["少年喜風雪，走上百尺樓。", "買酒不論錢，貰却紫貂裘。", "相從盡豪客，樓下繫紫騮。", "雄心視宇宙，萬事葉沉浮。", "欲騎鳳凰去，肯顧萬戶侯。", "誤奏上林賦，白衣對冕旒。", "一釣滄海空，遂跨六鼇頭。", "去年辭紫微，龍節得荆州。", "渚宮美遊觀，絳帳壓清流。", "風雪不異昔，亂眼玉花稠。", "日月翻兩車，俄驚十五秋。", "故人如飛雲，零落不能收。", "老意雖未伏，酒量已難投。", "弔影對明燭，金樽誰獻酬。", "隔年得一書，何足解沉憂。", "安得縮地術，來此醉相留。", "故人不可見，敢忘貧賤遊。"]'),
('cef24aca-440e-45a7-9927-93e05a054f4c','答吳伯固','鄭獬','宋','宋诗','song-poetry','','[]','伯固讀我詩，掉頭吟不休。',204,'全唐诗/poet.song.33000.json','["伯固讀我詩，掉頭吟不休。", "明日踵我門，作詩還相投。", "初讀頗怪駭，如錄萬鬼囚。", "筆墨又勁絕，湧紙花光流。", "想其揮掃時，天匠無雕鎪。", "倒下百篋珠，滑走不可收。", "嗟余文字拙，瑕纇多瘡疣。", "乃如醜老婦，見此明鏡羞。", "美言反見誦，倫擬非其儔。", "扶樹腐木茂，使之凌崑丘。", "又欲唱其宮，使我商以謳。", "相搏如風雷，直與郊愈侔。", "子趨則甚易，於我寧得不。", "力敵氣遂作，聲應律乃酬。", "譬如楚漢翁，畫地爭鴻溝。", "我才非子對，何足當戈矛。", "幸子時見過，高吟消百憂。"]'),
('9731ad9e-ab1f-4bbb-a538-531265fda4a2','酬王生','鄭獬','宋','宋诗','song-poetry','','[]','兩日立我門，再拜求我詩。',48,'全唐诗/poet.song.33000.json','["兩日立我門，再拜求我詩。", "我詩非美粟，安得充君饑。", "十年誦周易，滿腹文王辭。", "文王不可見，使我空涕洟。"]'),
('28bb6c39-007b-42b5-8227-b58be24c913f','客舟','鄭獬','宋','宋诗','song-poetry','','[]','滄江落日動，宿鳥歸故山。',48,'全唐诗/poet.song.33000.json','["滄江落日動，宿鳥歸故山。", "託巢在高木，朝去夕必還。", "客舟逐南風，大雪留楚關。", "何日掃吾廬，種秫鄖溪間。"]'),
('05a8dd71-87cd-40fa-846f-89bfc4f0b8b9','陳蔡旱','鄭獬','宋','宋诗','song-poetry','','[]','萬頃無寸苗，旱氣白於水。',48,'全唐诗/poet.song.33000.json','["萬頃無寸苗，旱氣白於水。", "桑葉蟲蝕盡，蠶未三眠起。", "挽舟如挽山，何緣出泥滓。", "滯冤何足言，耕夫將餓死。"]'),
('67f4c02b-7b17-4e31-8942-263109af4188','村家','鄭獬','宋','宋诗','song-poetry','','[]','臨水夾疏篁，蕭然一環堵。',48,'全唐诗/poet.song.33000.json','["臨水夾疏篁，蕭然一環堵。", "稚子戲芳草，小婦舂黄黍。", "爲生雖甚微，猶足安吾土。", "應笑馬上人，衣濕朝來雨。"]'),
('2e5cc373-5d4c-4147-965b-ae1bf4891b8f','收麥','鄭獬','宋','宋诗','song-poetry','','[]','小麥深如人，澶漫不見地。',192,'全唐诗/poet.song.33000.json','["小麥深如人，澶漫不見地。", "一苞十餘莖，一莖五六穗。", "實粒大且堅，較歲增三倍。", "芟穫載滿車，纍纍犢銜尾。", "大挈置之場，巃嵷丘陵起。", "婦姑趁天色，撲抶喧鄰里。", "貧者攟其餘，翁嫗携稚子。", "農家茲有獲，卒歲可無餒。", "去夏水漂屋，汩竄幸不死。", "以得補所失，囷圌可儲峙。", "云問麥之收，豐飽何因爾。", "得非長官賢，政化順天理。", "無乃農夫勤，蚤莫事耘耔。", "茲蓋天公仁，雨澤以時至。", "消滅賊與蟊，隴畝皆稠穊。", "嗟嗟爾之民，無忘天公賜。"]'),
('99924023-379c-4595-9ac8-323694e7454c','羌奴','鄭獬','宋','宋诗','song-poetry','','[]','豢飽則蹄齧，羌奴敢肆行。',48,'全唐诗/poet.song.33000.json','["豢飽則蹄齧，羌奴敢肆行。", "蚊蝱失驅逐，螻蟻遂縱橫。", "古先謀士帥，今誰可將兵。", "廟堂攬群策，還許訪書生。"]'),
('2dbcffd4-fde4-4525-b382-bc3f7c7a09a3','古井','鄭獬','宋','宋诗','song-poetry','','[]','百尺青梧桐，下有寒泉井。',48,'全唐诗/poet.song.33000.json','["百尺青梧桐，下有寒泉井。", "分明古鏡中，照見梧桐影。", "朝汲水花清，暮汲水花冷。", "願持沆瀣杯，遠寄蓬山頂。"]'),
('bc499f8d-ddea-4eac-b4fb-c46042ff4305','老樹','鄭獬','宋','宋诗','song-poetry','','[]','老樹十百圍，赤日不滿影。',120,'全唐诗/poet.song.33000.json','["老樹十百圍，赤日不滿影。", "廟貌畫鬼神，焰閃見光景。", "閭里頗驚動，豚壺日叩請。", "小巫口吟呀，祝奠屢折磬。", "安敢議翦伐，惟恐罹災眚。", "烏雀不敢巢，繁陰實脩整。", "豈有物所憑，陰姦設機穽。", "吾聞夏后氏，液金鑄九鼎。", "窟穴盡發露，夔羊皆遠屏。", "自從九鼎亡，草木亦有幸。"]'),
('2a1d3c08-fd57-4e9c-8558-6b536be6bfe5','松竹','鄭獬','宋','宋诗','song-poetry','','[]','鉏蘭種松竹，意嫌蘭易衰。',48,'全唐诗/poet.song.33000.json','["鉏蘭種松竹，意嫌蘭易衰。", "土氣不變惡，物性先自欺。", "勁竹見破節，直松生曲枝。", "嗟嗟松與竹，空使幽蘭悲。"]'),
('61ea3214-9ed6-4763-81ff-409e666cb96c','菊','鄭獬','宋','宋诗','song-poetry','','[]','菊花初抱葉，始見春光來。',144,'全唐诗/poet.song.33000.json','["菊花初抱葉，始見春光來。", "綠蓓今著花，又見秋風回。", "高天不容土，白日安可栽。", "一世如大瘧，寒暑還相催。", "使我明鏡匣，羞爲蒼顔開。", "流年可奈何，獨有金螺杯。", "閒秋無丈尺，付與令翦裁。", "况茲佳節近，秋日宜樓臺。", "菊花又密鬧，爛若金縷堆。", "如何不自樂，行繞空徘徊。", "秋風不惜花，即見飛蒼苔。", "惟此一樽酒，萬事皆塵埃。"]'),
('7e6544a2-e115-4ad6-8b72-0458c6c42b93','瘦馬','鄭獬','宋','宋诗','song-poetry','','[]','瘦馬如束薪，寒沙粘綠髮。',108,'全唐诗/poet.song.33000.json','["瘦馬如束薪，寒沙粘綠髮。", "我非九方皋，謂有大宛骨。", "渴引寒泉飲，饑翦青芻秣。", "如何得甘豢，輒爾事蹄齧。", "朝來試錦韉，衝踏行步闊。", "起立高於人，一頓金羈脫。", "圉人雖有恩，亦懼來奔蹶。", "古稱去害群，吾寧痛鞭撻。", "咄哉爾何心，無乃忘本末。"]'),
('8bb32cbb-88fe-465e-8842-2919d6764afb','慈烏行','鄭獬','宋','宋诗','song-poetry','','[]','鴉鴉林中雛，日晚猶未棲。',216,'全唐诗/poet.song.33000.json','["鴉鴉林中雛，日晚猶未棲。", "口銜山櫻來，獨向林中啼。", "林中有鴉父，昔生六七兒。", "一朝棄之去，空此群雛悲。", "意謂父在林，還傍前山飛。", "山中得山櫻，欲來反哺之。", "繞林復穿樹，疑在葉東西。", "東西竟無有，還上高高枝。", "高枝僅空巢，見此涕沾衣。", "復念營巢初，手足生瘡痍。", "朝飛恐雛渴，暮飛恐雛饑。", "一日萬千回，日日銜黍歸。", "今我羽翼成，反哺方有期。", "如何天奪去，遂成長別離。", "山櫻正滿枝，結子紅琲肥。", "而我不得哺，安用自啄爲。", "嗟嗟我薄祜，哺之固已遲。", "尚有慈母恩，群雛且相隨。"]'),
('9dcc029f-3ea3-45c9-a3dd-74c5c69b7b0b','蝦蟆','鄭獬','宋','宋诗','song-poetry','','[]','積雨腐萬物，吾廬亦頹壓。',48,'全唐诗/poet.song.33000.json','["積雨腐萬物，吾廬亦頹壓。", "蝦蟆何無厭，短腹猶呼渴。", "吾欲携兩股，擲之滄海闊。", "懼其渴太甚，跳去食明月。"]'),
('b0ee92a1-7f46-4899-96b4-876e53a1ff53','題杭郡閣','鄭獬','宋','宋诗','song-poetry','','[]','雨影橫殘虹，秋容映陰日。',48,'全唐诗/poet.song.33000.json','["雨影橫殘虹，秋容映陰日。", "寒江带暮流，曉角穿雲出。", "峰藏翠如織，宿鳥去無迹。", "封書寄所懷，聊託金門翼。"]'),
('3f4d082e-dd75-4782-bdce-8848f7b341ed','採鳬茨','鄭獬','宋','宋诗','song-poetry','','[]','朝携一筐出，暮携一筐歸。',48,'全唐诗/poet.song.33000.json','["朝携一筐出，暮携一筐歸。", "十指欲流血，且急眼前饑。", "官倉豈無粟，粒粒藏珠璣。", "一粒不出倉，倉中群鼠肥。"]'),
('89e47768-45a8-4967-aa17-bb125caac288','故人梁天機家岢嵐即五臺山之南也余馳使雲中道出山後跂望不及因成拙句以寄之','鄭獬','宋','宋诗','song-poetry','','[]','君家在山南，我行在山北。',120,'全唐诗/poet.song.33000.json','["君家在山南，我行在山北。", "山如碧連城，千里萬重隔。", "我行君不知，乘冰赴異域。", "異域無春風，未晚日先黑。", "思君應在家，游衍甘眠食。", "復恐爲薦書，去謁天子國。", "寒雲在山頭，應見真消息。", "我欲訊寒雲，雲飛攀不得。", "我馬不行空，如何度山側。", "相望兩不知，立馬情何極。"]'),
('8d882c7c-669e-49a0-a5fc-26fa95b5b70c','春日','鄭獬','宋','宋诗','song-poetry','','[]','樹頭啼鳥喚眠覺，無數柳綿飛入袍。',64,'全唐诗/poet.song.33000.json','["樹頭啼鳥喚眠覺，無數柳綿飛入袍。", "亂花繞屋水光動，碧虹漏窗春日高。", "乳雀趁飛玉蛺蝶，嬌鴉啄落金櫻桃。", "倚欄正欲破閒悶，聽得酒聲鳴小槽。"]'),
('618b0d3f-8e9b-47b9-a517-1cf361a407a7','二月雪','鄭獬','宋','宋诗','song-poetry','','[]','戊戌二月二十六，忽見大雪漫空來。',352,'全唐诗/poet.song.33000.json','["戊戌二月二十六，忽見大雪漫空來。", "長老驚嘆共相語，非時有雪誠怪哉。", "陽爻四畫已出地，至今百蟄不聞雷。", "怪得氣候斗暄暖，便疑赤帝來相排。", "黑風倏起捲滄海，白日黯黯如煙煤。", "須臾大雹雜猛雨，滿地走迸瓊與瑰。", "陰氣蓄怒固未已，即時飛雪相傾頹。", "青靈何處避威侮，蒼鳳停車寒毰毸。", "天地萬物失光彩，草樹僵凍成枯荄。", "凌暴春工大酷烈，似恨百花先時開。", "隠公三月亦雨雪，仲尼春秋書爲災。", "是時魯國行謬政，天心可用人理推。", "我疑此雪不虛應，必有沴氣戕栽培。", "去年六月已大水，居人萬類生魚顋。", "當時夏稅不得免，至今里正排門催。", "農夫出田掘野薺，餓倒只向田中埋。", "方春鳥獸尚有禁，不許彈獵傷胚胎。", "而况吾民戴君后，上官不肯一挂懷。", "豈無愁苦動天地，所以當春陰氣乖。", "只消黄紙一幅詔，敕責長吏須矜哀。", "蠲除餘租不盡取，收提赤子蘇饑骸。", "沛然德澤滿天下，坐中可使春風回。"]'),
('b4fd5ce0-6a4d-495f-b0d5-bbd36b4210c5','通州雨夜寄孫中叔','鄭獬','宋','宋诗','song-poetry','','[]','黑雨噴薄陰雲驅，昏林號風秋聲粗。',384,'全唐诗/poet.song.33000.json','["黑雨噴薄陰雲驅，昏林號風秋聲粗。", "海氣熏煮怒不泄，彭彭十月推雷車。", "濕衣憫默瞠無睡，起對樽酒誰爲娛。", "此心豈復有雙羽，一夜飛去不可拘。", "昔與子同入京師，借屋共寄西城廬。", "愛我議論有可採，携草就我誇染濡。", "鍊出五色補天漏，拈筆蘸墨縱橫塗。", "子云朋友當如是，脫然意快如獰駒。", "京師天子之所宅，樓殿堆疊騎天衢。", "瓦光流碧滑欲走，繢畫顛倒橫相舁。", "東風薰濃一千里，黄蜂蝴蝶飛蘧蘧。", "高樓張旗鬥煮酒，沉香滿榼金真珠。", "玉盆一飲醉不醒，落花滿衫行相扶。", "未幾子去遊西洛，嗟我出門獨騎馿。", "晚落塵埃兩袖淚，望子不見風吹裾。", "三月殿前試不中，青冥失計遊五湖。", "撫劍東南看滄海，大江正值秋風初。", "我疑海神怒天熱，直欲上薄東日烏。", "乾坤頓撼壯人意，揭竿便欲尋狂奴。", "九月歸來已霜蚤，肥膏紫蟹溶金酥。", "南窗燈火夜可喜，篋中卷冊聊鋪舒。", "讀倦抱膝一吐氣，契闊各在天一隅。", "相別於今二百日，飛雁南來無北書。", "遊從歡喜似舊否，洛下爲學安穩無。"]'),
('4c4c51c2-3000-4e11-bc19-414250c67cf5','荆江大雪','鄭獬','宋','宋诗','song-poetry','','[]','長鯨戲浪噴滄海，北風吹乾成雪花。',176,'全唐诗/poet.song.33000.json','["長鯨戲浪噴滄海，北風吹乾成雪花。", "漫空傾下不暫住，三日不見金老鴉。", "天工鬥巧變物境，玉作荆州十萬家。", "須臾堆地厚一尺，直疑天漏亡由遮。", "白頭老柏最崛强，壓折鐵幹紛鬖髿。", "竹屋夜倒不知數，但聞走下雷霆車。", "南方瘴土本炎熱，經臘猶生碧草芽。", "忽遭大雪固可怪，凍兒赤立徒悲嗟。", "青錢滿把不酬價，斗粟重於黄金沙。", "此時刺史頗自愧，起望霽景殊無涯。", "有民不能爲撫養，安用黄堂坐兩衙。"]'),
('995e673b-d851-4d67-98de-7883e4ba85db','和仲巽荆州大雪','鄭獬','宋','宋诗','song-poetry','','[]','黑雲撲下一天雪，開簾正見花飄颻。',326,'全唐诗/poet.song.33000.json','["黑雲撲下一天雪，開簾正見花飄颻。", "淥樽覆案不能飲，緬懷白髮同心交。", "拈毫竄紙聊自戲，不覺大語驚連鼇。", "呼兒謄本寄之去，豈敢有意夸雄豪。", "諺稱拋磚引鳴玉，遂蒙老手來相嘲。", "且言本出將家子，慣看飛雲連沙起。", "常騎快馬臂蒼鷹，走屠赤豹裂青兕。", "燕山崛岉鬰天起，玉關石壁俱天壘。", "昔纓漢冠爲漢民，今埋胡沙作胡鬼。", "欲携熊虎十萬師，獨以一箒掃群螘。", "左鈐休屠批谷蠡，直出龍沙五千里。", "嗚呼君言豈不偉，單于聞之須怖死。", "莫羞茜袖雙鬢華，盤屈肺肝生嘆嗟。", "君不見東海老翁含兩齒，投竿起載文壬車。", "又不見荆州長史年七十，手提九鼎還唐家。", "窮通變化不可測，蟠蛟寧久藏泥沙。", "况君著意經營久，奇策崢嶸爛星斗。", "殿前即日拜將軍，縛取單于不引手。", "我實讀書枉用心，伊皋功名竟何有。", "待君金甲破敵歸，且作長歌傾賀酒。"]'),
('b912ef13-535d-4901-8a31-86b17318a091','杭州喜雪','鄭獬','宋','宋诗','song-poetry','','[]','吳兒經年不識雪，忽驚大片遮空來。',64,'全唐诗/poet.song.33000.json','["吳兒經年不識雪，忽驚大片遮空來。", "黑帝不分苦荒拙，六花一夜隨風開。", "平明掃徑招佳客，座上豈無鄒與枚。", "荆州新釀潑醅熟，清光透徹黄金杯。"]'),
('c816da9d-df80-499d-b2ad-b56860d13ec5','冬日示楊季若梁天機','鄭獬','宋','宋诗','song-poetry','','[]','天河忽側飛雹傾，丁丁屋瓦相敲鳴。',176,'全唐诗/poet.song.33000.json','["天河忽側飛雹傾，丁丁屋瓦相敲鳴。", "撲衣寫下白玉粒，脚底踏碎真珠聲。", "官舍高屋苦濩落，此時不易孤客情。", "潁侯恰寄玉泉釀，乳花甘滑琉璃清。", "紅糟淮白復脆美，佐之綠菘作吳羹。", "縱談往舊雜嘲戲，大笑觴倒金酒觥。", "閒以罰令却寂默，四座睥睨如伏兵。", "人生會合即爲樂，况子歸意凌青冥。", "赤尾鯉魚在泥滓，行見兩翅穿鱗生。", "跳身聳鬣望東海，蒼崖枯涸埋層冰。", "明年春風掃地起，一起萬物皆光明。"]'),
('f9fa1906-f68b-43b7-9088-16d65e47d6d3','出城寄梁天機','鄭獬','宋','宋诗','song-poetry','','[]','春風徘徊來何時，花光還破小桃枝。',96,'全唐诗/poet.song.33000.json','["春風徘徊來何時，花光還破小桃枝。", "不因出城見花樹，春到人間殊不知。", "昔年逢花便買酒，看花走馬猶嫌遲。", "花傍不醉不肯去，醉到春歸花已飛。", "誰憐官紱少風味，入春未拈金酒卮。", "豈惟花少醉亦少，當時故人今更稀。"]'),
('a66dbb2a-2f7e-4a9a-bc63-5c339a376496','淮揚大水','鄭獬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','淮揚水暴不可言，繞城四面長波皴。',384,'全唐诗/poet.song.33000.json','["淮揚水暴不可言，繞城四面長波皴。", "如一大瓢寄滄海，十萬生聚瓢中存。", "水之初作自何爾，舊堤有病亡其唇。", "劃然大浪劈地出，正如百萬狂牛犇。", "頃之漂泊成大澤，壯士挾山不可堙。", "居民竄避爭入郭，郭內衆人還塞門。", "老翁走哭覓幼子，哀赴卒爲蛟龍吞。", "豈獨異物乃爲害，惡人行劫不待昏。", "此時蝦蟆亦得志，撩鬚睥睨河伯尊。", "附城廬舍盡水府，惟見屋脊波間橫。", "間或大雨又暴作，直疑瓶盎相奔傾。", "溝渠漲滿無處泄，往往床下飛泉鳴。", "只恐此城澒洞徹，城中坐見魚頰生。", "豪子室中具大筏，此筏豈便長全身。", "朝夕築塞漸排去，兩月未見車間塵。", "且喜餘生尚存世，資儲誰復傷漂淪。", "京師乃處天下腹，亦聞大水來扣閽。", "至於河朔南兩蜀，長江大河俱騰掀。", "豈惟淮陽一彈地，洪濤乃撼半乾坤。", "臣聞九疇天公書，三十六字先五行。", "茲謂水德不潤下，蓋與土氣交相爭。", "願召近臣講大義，使之搜鑿災害根。", "下書遣使巡郡國，曠然一發天子恩。", "家貧溺死無以葬，賜以棺轊收冤魂。"]'),
('b216e046-ab64-4cae-87cb-75b91f6a5f95','行次漢水寄荆南漕唐司勳','鄭獬','宋','宋诗','song-poetry','','[]','漢水渺渺東南流，蕭蕭雨打杏花洲。',64,'全唐诗/poet.song.33000.json','["漢水渺渺東南流，蕭蕭雨打杏花洲。", "欲託雙魚寄書札，不知幾日到荆州。", "荆州故人日漸遠，到時綠草滿沙頭。", "爭得報章來闕下，鳳林北去不通流。"]'),
('6f77ebc9-55f1-4718-a36b-6090581c5bb0','憶陪諸公會張侯之第','鄭獬','宋','宋诗','song-poetry','','[]','姚黄左紫雖絕品，不言不笑空夭斜。',64,'全唐诗/poet.song.33000.json','["姚黄左紫雖絕品，不言不笑空夭斜。", "不如共訪張公子，自有三枝解語花。", "主人耳熱更促席，坐客眼亂忘歸家。", "扁舟一夕若風雨，悵望落日沉寒沙。"]'),
('ef523164-38e6-42c7-bb84-9578793b1bb3','山陽太守見招值病以長句謝之','鄭獬','宋','宋诗','song-poetry','','[]','山陽大都天下誇，長淮蟠山無垠涯。',176,'全唐诗/poet.song.33000.json','["山陽大都天下誇，長淮蟠山無垠涯。", "春風萬里漢東來，流輝泱漭不可遮。", "繞城樓臺滿空紫，瓦光碧滑流成波。", "東園花草趁姿媚，真珠蓓蕾黄金芽。", "太守政閒日無事，隼旟聊駐朱輪車。", "寶明簪裾盡賢彥，金盆瀉酒成飛花。", "山河喧咽歌管外，舞裾綉畫金縷霞。", "都人來從無居人，飛塵雜沓何繁華。", "固知太守爲民意，與民歡然無怨嗟。", "明日邀我復同遊，我已病酒醉在家。", "伏枕不得從車塵，坐見落日啼棲鴉。"]'),
('d2587a4d-8227-4414-8305-475ad3659cd7','還汪正夫山陽小集','鄭獬','宋','宋诗','song-poetry','','[]','汪子文章何偉奇，如觀天子乘輿儀。',387,'全唐诗/poet.song.33000.json','["汪子文章何偉奇，如觀天子乘輿儀。", "怛然暴見殊驚疑，舌拄上齶兩目癡。", "定神屏氣試引窺，漸識羽衛行相隨。", "金吾佽飛開中逵，橫刀執矟鐵馬馳。", "畫旆赤白盤龍螭，大角一百二十支。", "鐃鼓嘲轟雜橫吹，繡幡絳幢何紛披。", "䍐罼鈹戟開黄麾，屬車{車急}轔霹靂移。", "侍郎御史冠峨危，圓扇孔雀雙翅垂。", "辟邪白澤飛麟麒，金輅赤馬火鬣鬐。", "飄飄鳳蓋翳華芝，水光鐵甲羽林兒。", "二十四仗驅熊貔，長殳闊劍梢魍夔。", "團花絳袖武士衣，大小不同雖異宜。", "要之盡是聖賢爲，奇服怪玩一不施。", "斥之所以尊皇威，汪子之文正類斯。", "一十五軸紛葳蕤，爛光直欲紙上飛。", "長篇短篇傾珠璣，題說論序及賦詩。", "篇雖不同皆有歸，要之孔子韓退之。", "留讀旬日不知疲，大渴適得甘露飴。", "我欲誦記留肝脾，惟我老鈍無記持。", "又無小吏操筆揮，或可寫留慰朝饑。", "二者不遂其齎咨，今復奪去心黭黟。", "室中斗覺無光輝，靈寶不可留洿池。", "風雨送還滄海湄，嗟我居陳逾歲時。", "兩耳無聞如塞泥，遂恐聾瞶不可醫。"]'),
('2f54a307-a650-4a65-920e-d879741c6794','梁卦孫過飲','鄭獬','宋','宋诗','song-poetry','','[]','手搓兩眼睡已足，落花滿床紅飄颻。',144,'全唐诗/poet.song.33000.json','["手搓兩眼睡已足，落花滿床紅飄颻。", "山鳥不須報春曙，清明自放端門朝。", "夜來賓客偶過我，呼奴留客解金鑣。", "花枝顛倒插翠帽，酒杯傾潑淋春袍。", "更深客去我亦醉，畫簾殘燭香初銷。", "俛仰之間乃陳迹，酒醒夢斷還無聊。", "白雲已抱日光落，春水自共東風摇。", "聖賢勞心當萬事，吾徒掃榻頻相招。", "好花欲盡速來飲，爲君倒甕傾春醪。"]'),
('fb8fe5a7-77e4-4a27-b8fd-627da359a5a4','和人柳溪','鄭獬','宋','宋诗','song-poetry','','[]','三月二十七，春叢已半空。',44,'全唐诗/poet.song.33000.json','["三月二十七，春叢已半空。", "細草著露作團綠，落花擁溪相壓紅。", "南北遊人歸未歸，日斜飛絮撩東風。"]'),
('c083d04f-8794-4027-bd45-df7d55577675','汪正夫云已厭遊湖上顧予猶未數往遂成長篇寄之','鄭獬','宋','宋诗','song-poetry','','[]','君已厭折湖上花，我猶驅迫坐兩衙。',176,'全唐诗/poet.song.33000.json','["君已厭折湖上花，我猶驅迫坐兩衙。", "須知樂事屬閒客，日日携觴不在家。", "况君才力自少對，取次落筆成天葩。", "春風湖上與之敵，豪放麗絕無以加。", "幽岩絕壁無不到，欲緣雲漢尋天槎。", "頃屬勝遊不得往，猶如野馬絆在車。", "眼看紅英零落盡，長條已被綠葉遮。", "春芳雖晚猶得在，山丹正好紅相誇。", "終當擺去百事役，與君共躡南山霞。", "雖老猶能沃金葉，卞娘送以雙琵琶。", "已教樓下排花舫，醉到碧山春日斜。"]'),
('f71a0421-e73d-4403-8144-79eafeffb67b','寄題明州太守錢君倚衆樂亭','鄭獬','宋','宋诗','song-poetry','','[]','使君何所樂，樂在南湖濱。',220,'全唐诗/poet.song.33000.json','["使君何所樂，樂在南湖濱。", "有亭若孤鯨，覆以青玉鱗。", "四面擁荷花，花氣摇紅雲。", "使君來遊携芳樽，兩邊佳客坐翠裀。", "鄞江鮮魚甲如銀，玉盤千里紫絲蓴。", "金壺行酒雙美人，小履輕裙不動塵。", "壯年行樂須及辰，高談大笑留青春。", "遊人來看使君遊，芙蓉爲檝木蘭舟。", "橫簫短笛悲晚景，畫簾繡幕翻中流。", "貪歡尋勝意不盡，相招却渡白蘋洲。", "日落使君扶醉歸，遊人散後水煙霏。", "紫鱗跳復戲，白鳥落還飛。", "豈獨樂斯民，魚鳥亦忘機。", "使君今作螭頭臣，遊人依舊歲時新。", "空餘華榜照湖水，更作佳篇誇北人。"]'),
('e2de1117-3e9e-4ef6-899d-71d1777a11da','爲題小靈隠修廣師法喜堂','鄭獬','宋','宋诗','song-poetry','','[]','浮屠藏家多在山，飛舟跨海煩往還。',64,'全唐诗/poet.song.33000.json','["浮屠藏家多在山，飛舟跨海煩往還。", "不如廣師開此堂，清曠不減山中間。", "前有怪石天所鑱，莓苔模糊蒼鬼顔。", "我時跨馬來扣關，訪師對石終日閒。"]'),
('c7620fda-91ef-47da-91f7-b80f159a20e8','代人上明龍圖','鄭獬','宋','宋诗','song-poetry','','[]','凶徒盜覆甘陵城，白日堂堂梟呼鳴。',192,'全唐诗/poet.song.33000.json','["凶徒盜覆甘陵城，白日堂堂梟呼鳴。", "生靈十萬陷死地，長刀大戟交縱橫。", "留都丞相統河北，雷霆四馳諸侯兵。", "鐵林合圍三十里，甲光如水魚鱗明。", "風霜曠野苦暴露，未得鼠子腥吾烹。", "天子憫惻覽群議，冠蓋滿朝賢公卿。", "安得破賊如裴度，開封大尹宜其行。", "公拜稽首出就駕，畫旆獵獵蟠虬獰。", "沛然德澤隨車來，一煦萬物皆發生。", "士卒奮怒爭以死，遂窮巢穴誅根萌。", "平賊之功無與讓，當見大軸歸老成。", "夔皋拱列帝舜坐，願補日月歌太平。"]'),
('14ece5a7-5441-4588-bbd4-03714ce5a7e8','題關彥長孤山四照閣','鄭獬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖山天下之絕境，群山繞湖千百重。',320,'全唐诗/poet.song.33000.json','["湖山天下之絕境，群山繞湖千百重。", "碧笋四插明鏡外，此閣正落明鏡中。", "綠波一穗掃沙尾，擁門盡是紅芙蓉。", "清香斷處接蒼靄，綠蘿攀樹登高峰。", "當軒不置窗與檻，湖光山翠還相通。", "側耳似聞天上語，接手便欲翻長空。", "忽疑躍入畫屏上，但覺毛髮生清風。", "光景動蕩失天地，直與顥氣爭雌雄。", "君何容易得此處，著意鑱鑿由天公。", "西湖雖然多佳境，遊人到此景遂窮。", "昔日郎官退居此，足踏藤履手携筇。", "時陪金壺宴親舊，船飛兩楫如歸鴻。", "溪魚鮮白玉膏脆，林果紅熟燕脂濃。", "揮弄清泉倚蒼石，當時即是神仙翁。", "又况諸子盡奮發，綠袍照爛時相從。", "我來登覽但嘆息，有家不得居江東。", "至今此景常入夢，尚有清氣留心胸。", "屢蒙書尾追拙唱，强臨紙札誠難工。", "湖山有靈必見笑，便與棄擲無留蹤。", "直須收拾買鄰舍，兄乎異日能相容。"]'),
('ae5dd2aa-30a3-4e4c-a6aa-f0d549c4f707','上李太傅','鄭獬','宋','宋诗','song-poetry','','[]','陳人嘗傳李太傅，云作太守來此州。',128,'全唐诗/poet.song.33000.json','["陳人嘗傳李太傅，云作太守來此州。", "頃遭暴水拉堤出，設施畫略排橫流。", "大偷嘗欲穴堤腹，掩之即日斷其頭。", "至於小猾幸民禍，鈎羅姓名皆不留。", "陳人恬恬但眠食，恃公牢固如山丘。", "今茲水暴潴外郭，眼見盜賊何由仇。", "况我方在艱阨中，竄奔日懼蛟龍求。", "烏乎不見李太傅，使我涕淚成沈憂。"]'),
('72566b63-0920-4057-bc0e-704a97c43e56','次韵程丞相重九日示席客','鄭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湖光飛出洞庭秋，拍手齊看山公遊。',240,'全唐诗/poet.song.33000.json','["湖光飛出洞庭秋，拍手齊看山公遊。", "黑雲抱日離東海，蒼霞穿漏紅光浮。", "我公重惜此佳節，携賓留燕停鳴騶。", "城角直穿一氣外，碧鱗縹緲飛高樓。", "晚花纖麗金靨鬧，平莎蒙密綠髮稠。", "手把玻璃笑當坐，飄然逸氣凌雲遒。", "須臾大卷出新作，鐵網包住鯨與虬。", "四座傳觀賞佳句，絲管不發清歌留。", "茱萸著酒紫香透，芙蓉插髻雙眉修。", "後堂新壓菊花釀，傾在玉盆凝不流。", "美人再拜勸公飲，一飲可忘今古愁。", "誰謂長戈可駐景，誰謂萱草能忘憂。", "斯言寥闊不可考，樂事須向尊前求。", "霓裳法曲古來絕，小槽琵琶天下尤。", "只此醉鄉有佳境，此境不與人間侔。"]'),
('2495303e-cfb6-4ea3-aee5-47239722d0b2','酬余補之見寄','鄭獬','宋','宋诗','song-poetry','','[]','吾友補之會稽家，高眉大眼稱才華。',272,'全唐诗/poet.song.33000.json','["吾友補之會稽家，高眉大眼稱才華。", "入京共收太學第，姓名頭角相撐磨。", "高樓管弦相與雜，黄金酒面溶成波。", "樽前軒昂如孤鷹，四顧不見雀與蛙。", "試招紙筆恣揮掃，縱橫噴薄不可遮。", "我疑君心如春風，呵吐草樹皆成花。", "忽然驚爆險絕句，旱天霹靂雷霆車。", "我輩觀之瞪兩眼，汗流滿面空長嗟。", "明年南北別君去，落照滿帆秋風斜。", "天涯朋歡少披豁，還如穴鰋跳泥沙。", "兩耳喧聒久厭苦，思君便欲飛仙槎。", "前時得君山陽書，副之長句封天葩。", "筆墨勁健愈精絕，鐵繩鈕縛虬爪牙。", "有時風雨恐飛去，嘗自密鎖金鴉叉。", "嗟我文字苦慳短，才力不敵兩角蝸。", "下筆欲答輒自止，如君一句已可誇。", "持此聊且謝勤叩，念君不見愁無涯。"]'),
('be750808-be9a-4118-a137-efae3bd87316','酬隨子直十五兄','鄭獬','宋','宋诗','song-poetry','','[]','通州窮並大海涯，厥壤不毛坤德虧。',352,'全唐诗/poet.song.33000.json','["通州窮並大海涯，厥壤不毛坤德虧。", "床下矍索穴蟛蜞，我初來居常吟悲。", "見君顔采方伸眉，眸子清徹鬢垂頤。", "中懷洞然無由歧，鎸鑱文字干有司。", "古書細鈔指生胝，弟姪鳬雁行纍纍。", "脫衣易粟飴其饑，慈祥孝友鄉里推。", "前者天子親饗祠，黄紙赦書疾風馳。", "挂羅山林網逸遺，守臣奉詔敢言遲。", "外臺使者爭薦之，野廬供餼禮所宜。", "白袍大袖何紛披，來居太學森蘭芝。", "世俗譏議喜瑕疵，蒼蠅往來工讒詞。", "椎鑿璞玉生瘡痍，猛虎不如牆下貍。", "聽者雖明豈無疑，紫薇群公文章師。", "發以鉅策健筆隨，鋪紙吐論語亦奇。", "綴名紙末何其卑，藻火爲裳誠倒施。", "赤驥不得黄金羈，編之下櫪耳羸垂。", "令我包羞心鬰伊，一舸東入長淮湄。", "勿言顯發遂無期，青衫猶足慰妻兒。", "海陵得君七字詩，重謝解謗稱相知。", "我雖有言如鈍錐，說之不入何能爲。", "願子加餐善自持，高山峨峨寸土基。", "前塗如壁不可窺，榮落窮通各有時。"]'),
('26b3b86a-9f56-4039-9b38-75a4e8f0e3c5','戲酬正夫','鄭獬','宋','宋诗','song-poetry','','[]','汪子怪我不作詩，意欲窘我荒唐辭。',272,'全唐诗/poet.song.33000.json','["汪子怪我不作詩，意欲窘我荒唐辭。", "自顧拙兵苦頓弱，安敢犯子之鼓鼙。", "子之文章既勁敏，屢從大敵相摩治。", "左立風后右立牧，黄帝秉鉞來指麾。", "蚩尤跳梁從風雨，電師雷鬼相奔馳。", "頃之截首挂大旆，兩肩塚葬高峨危。", "如何韜伏不自發，欲用古術先致師。", "遺之巾幗武侯策，司馬豈是尋常兒。", "應須敵氣已衰竭，然後鐵騎來相追。", "回戈坐致窮龐伏，得非欲學韓退之。", "嗟我豈敢與子校，唯圖自守堅城陴。", "况茲憂窘久廢絕，空餘衰老扶瘡痍。", "開卷舊字或不識，豈能有意爭雄雌。", "朝來據鞍試矍鑠，是翁獨足相撐支。", "檢勒稍稍就部伍，亦欲一望將軍旗。", "曹公東壁不羞走，周郎未得相凌欺。", "便須持此邀一戰，非我無以發子奇。"]'),
('c24a527e-cd58-47bc-8393-80118684abbd','送蔡同年守四明','鄭獬','宋','宋诗','song-poetry','','[]','尚書蔡公在廊廟，器業文章第一人。',176,'全唐诗/poet.song.33000.json','["尚書蔡公在廊廟，器業文章第一人。", "繡墩賜坐議大政，天子稱之社稷臣。", "渥洼遺種出驥子，纔生七日超其群。", "蔚如長松倚絕壁，灑落不雜人間塵。", "東風共醉杏花下，滄波浩蕩天地春。", "近者諸公薦御史，宰相未識真麒麟。", "却借朱袍下南國，畫船醉眠官不嗔。", "吾徒對酒共嘆息，破車快犢誠難馴。", "陳蕃高才雖少對，辟書聊慰汝南民。", "溪山見君亦須喜，飛雲遮路迎車輪。", "朱雲風采久寂寞，豈宜遠處滄海濱。"]'),
('67d6d29d-1ed0-415b-a1fc-d461d2b48e38','送仲巽歸闕下','鄭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','老驥不妄行，蒼鷹不虛擊。',221,'全唐诗/poet.song.33000.json','["老驥不妄行，蒼鷹不虛擊。", "高車折軸棄路旁，繭栗犢兒負其力。", "指麾萬事自有理，不須破海驚霹靂。", "君不見張侯白頭郎，仗節雍容在南國。", "事如倒山落面來，談笑當之不遺策。", "往時夸者欲驚俗，揭浪翻風一千尺。", "屢成大獄沸如糜，六月飛霜觸白日。", "張侯不矜亦不倚，老驥蒼鷹稱其德。", "洞庭之北十二州，吏民帖帖甘眠食。", "有詔奪歸不得留，正值風雨花狼籍。", "離思浩蕩入青春，楚澤荆山淡無色。", "此行况是赤縣官，賢者宜令天子識。", "公雖已老心尚存，今不急用真可惜。", "但用河南張漢陽，何必東山謝安石。"]'),
('04972ca9-980b-440a-9901-3b2535050d3f','送人東上','鄭獬','宋','宋诗','song-poetry','','[]','騏驥太俊不得馭，塵埃尚走高陽翁。',48,'全唐诗/poet.song.33000.json','["騏驥太俊不得馭，塵埃尚走高陽翁。", "奇文泣下鬼神血，高議鑿開天地聾。", "平明仗劍背我去，老蛟奮鬣歸江東。"]'),
('618352da-6436-45ee-8c62-5998adc03d96','送李處士南歸','鄭獬','宋','宋诗','song-poetry','','[]','駕車跨馬聲嘈嘈，長劍闊佩橫滿朝。',80,'全唐诗/poet.song.33000.json','["駕車跨馬聲嘈嘈，長劍闊佩橫滿朝。", "塵埃走趨顔髮老，先生久客得無勞。", "夜來氣味有秋色，歸心鬥與秋風高。", "揭竿跨浪好歸去，扁舟爛醉眠雲濤。", "大小不能薦天子，遺詩有意徒嘵嘵。"]'),
('eacfcf1e-e053-48b4-8f60-91b1633a30db','題名碑石琢之已成求章伯益先生篆額','鄭獬','宋','宋诗','song-poetry','','[]','老匠隳山斬蒼石，偃然巨璞長於席。',120,'全唐诗/poet.song.33000.json','["老匠隳山斬蒼石，偃然巨璞長於席。", "銳鑿飛椎日鑱擊，金錞嘲轟滿虛室。", "白沙礲就大禹圭，紺滑自同青玉色。", "兩螭攫拏相鬥立，欲求大篆冠其額。", "先生絕妙不須言，引墨爲我一落筆，蟠屈玉筯入石壁。", "吾曹名氏遂輝赫，異物不復容侵蝕。", "赤尾鯉魚問消息，丐我數字得不得。"]'),
('5d96215a-b65a-4c80-a680-855228605bd6','讀朝報','鄭獬','宋','宋诗','song-poetry','','[]','天子曉坐朝明光，丞相叩頭三拜章。',64,'全唐诗/poet.song.33000.json','["天子曉坐朝明光，丞相叩頭三拜章。", "乞還相印避賢路，願爲天子專城隍。", "上恩深厚未聞可，丞相退讓聞四方。", "濃書大紙批聖語，鳴騶却入中書堂。"]'),
('c0155a99-e922-412e-b464-af9311f7443d','滯客','鄭獬','宋','宋诗','song-poetry','','[]','五月不雨至六月，河流一尺清泥渾。',112,'全唐诗/poet.song.33000.json','["五月不雨至六月，河流一尺清泥渾。", "舟人繫鼓挽舟去，牛頭刺地挽不行。", "我舟繫岸已七日，疑與綠樹同生根。", "忽驚黑雲湧西北，風號萬竅秋濤奔。", "截斷兩脚不到地，半夜霹靂空殺人。", "須臾雲破見星斗，老農嘆息如銜冤。", "高田已槁下田瘦，我爲滯客何足言。"]'),
('c4e8f696-e89a-47a3-81be-adc1d2c12f06','感懷','鄭獬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','北風哭夜星辰寒，竹籬敲戛鳴琅玕。',128,'全唐诗/poet.song.33000.json','["北風哭夜星辰寒，竹籬敲戛鳴琅玕。", "老蟾瘦噤失光采，天地凍合魚龍乾。", "嘅然憶歸幾千里，長江大山交屈蟠。", "湘水東去注不極，我心夜夜如鳴湍。", "弟兄起居諒歡適，高堂綵衣翩翻翻。", "嗟我摧頹落蒼海，兩腋恨無雙飛翰。", "遠方就學何所得，數年短髮才勝冠。", "何時拂袖得歸去，春風笑滿南陔蘭。"]'),
('4973b929-32e4-4016-9f0d-970948373d1d','木渠','鄭獬','宋','宋诗','song-poetry','','[]','木渠遠自西山來，下溉萬頃民間田。',96,'全唐诗/poet.song.33000.json','["木渠遠自西山來，下溉萬頃民間田。", "誰謂一石泥數斗，直是萬頃黄金錢。", "去年出穀借牛耕，今年買牛車連連。", "須知人力奪造化，膏雨不如山下泉。", "雷公不用苦震怒，且放乖龍閒處眠。", "安得木渠通萬里，坐令四海成豐年。"]'),
('aafd8240-0e5c-46ec-9f6e-5520dd92f843','道旁稚子','鄭獬','宋','宋诗','song-poetry','','[]','稚兒怕寒床下啼，兩骭赤立仍苦饑。',64,'全唐诗/poet.song.33000.json','["稚兒怕寒床下啼，兩骭赤立仍苦饑。", "天之生汝豈爲累，使汝不如鳬鶩肌。", "官家桑柘連四海，豈無寸縷爲汝衣。", "羨爾百鳥有毛羽，冰雪滿山猶解飛。"]'),
('d05ec2d8-f985-4aaa-aedb-e90871cc0256','買桑','鄭獬','宋','宋诗','song-poetry','','[]','出持舊粟買桑葉，滿斗纔換幾十錢。',64,'全唐诗/poet.song.33000.json','["出持舊粟買桑葉，滿斗纔換幾十錢。", "桑貴粟賤不相直，老蠶仰首將三眠。", "前日風雨乖氣候，凍死箔卷埋中田。", "蠶不見絲粟空鬴，安得衣食窮歲年。"]'),
('68f818ae-bcc9-4a88-af7b-febfc38a516a','題正夫小齋栽新竹','鄭獬','宋','宋诗','song-poetry','','[]','斲開俗境栽新竹，滿地冰圓映玉膚。',64,'全唐诗/poet.song.33000.json','["斲開俗境栽新竹，滿地冰圓映玉膚。", "高梢爭出翠鳳尾，孤根對植蒼龍鬚。", "雨聲曾洗越溪石，風影寫成湘水圖。", "獨有素娥留夜月，與君相對倒金壺。"]'),
('91c273cd-8c7b-4c82-b646-0aab0990f776','捕蝗','鄭獬','宋','宋诗','song-poetry','','[]','翁嫗婦子相催行，官遣捕蝗赤日裏。',96,'全唐诗/poet.song.33000.json','["翁嫗婦子相催行，官遣捕蝗赤日裏。", "蝗滿田中不見田，穗頭櫛櫛如排指。", "鑿坑篝火齊聲驅，腹飽翅短飛不起。", "囊提籝負輸入官，換官倉粟能得幾。", "雖然捕得一斗蝗，又生百斗新蝗子。", "只應食盡田中禾，餓殺農夫方始死。"]'),
('80b72f58-9238-4076-81fe-b3a062ef727a','獐猿','鄭獬','宋','宋诗','song-poetry','','[]','翠樹不從青嶂出，蟠根却向屏中生。',112,'全唐诗/poet.song.33000.json','["翠樹不從青嶂出，蟠根却向屏中生。", "黄獐引脰探綠葉，老猿護雛枝上驚。", "獝然相顧見異態，誰言野物能忘情。", "我來賞激繞屏下，亦疑此身林中行。", "自古畫工無畫者，今得絕筆方傳名。", "吾廬昔在鄖溪上，滿溪桃花春水明。", "曾隨麋鹿藉芳草，更倚白雲聽嘯聲。"]'),
('ee0d7016-91a6-4a66-be81-17501c39d703','省中畫屏蘆雁','鄭獬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','高堂傾動長江流，黄蘆群雁滿滄洲。',112,'全唐诗/poet.song.33000.json','["高堂傾動長江流，黄蘆群雁滿滄洲。", "掃開長安塵土窟，寫出江南煙水秋。", "兩雁斜飛入空闊，四雁顧慕橫沙頭。", "高風拉折蒼玉幹，蘆花雪盡無人收。", "赤日飛光不敢近，但覺爽氣屏間浮。", "嘗聞畫龍入神變，坐馳雲雨天地遊。", "只恐此雁亦飛去，瀟瀟萬里誰能留。"]'),
('ba3f88cb-406d-415b-9e32-a97415c06f0b','黄雀','鄭獬','宋','宋诗','song-poetry','','[]','啾啾黄雀竹間飛，日晚復歸枝上棲。',80,'全唐诗/poet.song.33000.json','["啾啾黄雀竹間飛，日晚復歸枝上棲。", "雪粒蓋地三寸玉，地膚凍裂不作泥。", "錦韝公子臂蒼鶻，快馬踏下黄雲低。", "馬前紫兔躍白草，老拳下批饑兒啼。", "啄鮮裂血飽腹去，可憐黄雀空死饑。"]'),
('cd468c52-4954-4b68-8539-a365a5099644','和御製賞花釣魚','鄭獬','宋','宋诗','song-poetry','','[]','曉日開閶闔，春風滿未央。',72,'全唐诗/poet.song.33000.json','["曉日開閶闔，春風滿未央。", "水摇天仗影，花雜御衣香。", "覆檻紅梢接，連鈎紫鬣長。", "千鍾浮帝酒，五色染天章。", "鄒馬摛嘉頌，夔龍拜壽觴。", "金輿歸晚處，正在五雲旁。"]'),
('d164aa90-5efd-4685-8e95-24e1c7a8c294','程丞相生日','鄭獬','宋','宋诗','song-poetry','','[]','大昴光芒正，荆河氣象渾。',240,'全唐诗/poet.song.33000.json','["大昴光芒正，荆河氣象渾。", "始知真相出，遂見本朝尊。", "漢地汝陽國，程侯司馬孫。", "精剛得金氣，深厚體乾元。", "申甫生周嶽，皋夔拱舜軒。", "山河歸妙算，社稷繫昌言。", "九鼎群生重，洪鑪一氣奔。", "群雛忌鵰鶚，衆草失蘭蓀。", "慷慨提千騎，扶摇下九閽。", "秦關春草短，洼水暮雲屯。", "詩必曹劉敵，兵須衛霍論。", "談餘珠委積，筆落鳳騰騫。", "秀髮煙霞外，丹心金石存。", "未歸真宰柄，猶倚大師藩。", "日月回龍角，星辰會紫垣。", "氣凌金節潤，風入繡旗翻。", "歌管傾南國，簪裾拜慶門。", "飛黄下天廄，縹酒賜堯樽。", "固有神靈護，應知福祿蕃。", "蟠桃三結實，未見老雲根。"]'),
('94bb0528-fbea-4b08-b4f1-9514399d13ff','後閣四松','鄭獬','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','丞相當時植，幽襟對此開。',120,'全唐诗/poet.song.33000.json','["丞相當時植，幽襟對此開。", "人知舟檝器，天假棟梁材。", "錯落龍鱗出，襹褷鶴翅回。", "重陰羅武庫，細響靜山臺。", "得地公堂裏，移根澗水隈。", "吳城夢寐遠，泰嶽歲年催。", "轉覺飛纓謬，何因繼組來。", "幾尋珠履蹟，願比角弓培。", "柏悅猶依社，星高久照台。", "後凋應共操，無復問良媒。"]'),
('a1d1ec0b-9180-49cb-923d-4644c3f8b4b0','夜意','鄭獬','宋','宋诗','song-poetry','','[]','卧北斗柄直，插西月角橫。',96,'全唐诗/poet.song.33000.json','["卧北斗柄直，插西月角橫。", "風吹病骨醒，秋入壯心驚。", "騏驥老方健，太阿靈有聲。", "山河寄功業，樽酒識平生。", "豺虎須探穴，朝廷可息兵。", "山西少勁氣，天外縱長庚。", "自古輸成算，誰人解請纓。", "干戈五十萬，何日到燕城。"]'),
('be77f35c-61bd-4167-b622-85fcbad4bf7f','出城','鄭獬','宋','宋诗','song-poetry','','[]','塵土滿城黑，出城雙眼寬。',72,'全唐诗/poet.song.33000.json','["塵土滿城黑，出城雙眼寬。", "山川秋意惡，風雨晚潮寒。", "物象颯以變，泥污不可蟠。", "英豪重節概，兒女感衰殘。", "霜老琱弓勁，風焦畫鼓乾。", "蛟螭正無頼，好擲六鼇竿。"]'),
('de3ed282-c52e-4f0f-9407-d0c851a367ad','晚晴','鄭獬','宋','宋诗','song-poetry','','[]','人間久厭雨，最快是初晴。',48,'全唐诗/poet.song.33000.json','["人間久厭雨，最快是初晴。", "驟見碧林影，喜聞歸雁聲。", "乾坤一蘇醒，耳目兩聰明。", "寄語浮雲意，休來污太清。"]'),
('0e8c7f7e-3eab-47bd-9d7f-256f63c6aef5','乍凉','鄭獬','宋','宋诗','song-poetry','','[]','雲湧海潮黑，軒窗凉氣侵。',48,'全唐诗/poet.song.33000.json','["雲湧海潮黑，軒窗凉氣侵。", "清風醒病骨，快雨破煩心。", "噴薄紫荷蓋，飄颻青桂林。", "作詩招醉友，方外一相尋。"]'),
('e213fda9-b327-41bb-8d6e-5e6732237f3b','淮西道中','鄭獬','宋','宋诗','song-poetry','','[]','夾道柳梢長，竹橋風影凉。',48,'全唐诗/poet.song.33000.json','["夾道柳梢長，竹橋風影凉。", "行人殘照裏，歸路白雲旁。", "泉淺带土味，巖深聞草香。", "到家花已盡，杏頰擁枝黄。"]'),
('7128c71c-dbe7-4826-aaae-bf0215548680','舟泊','鄭獬','宋','宋诗','song-poetry','','[]','鳴櫓解雙纜，寒蒸江氣昏。',48,'全唐诗/poet.song.33000.json','["鳴櫓解雙纜，寒蒸江氣昏。", "春雲兼雨重，晚水带潮渾。", "小市魚蝦集，空亭燕雀喧。", "一尊得濃睡，行計不須論。"]'),
('eaec6699-4d19-4679-aa54-c0837c283422','江行','鄭獬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','碧草已堪翦，長江二月頭。',48,'全唐诗/poet.song.33000.json','["碧草已堪翦，長江二月頭。", "林深藏宿雨，岸豁聚春流。", "潮背燕支浦，山橫桑落州。", "松醪欺客病，易醉苦難投。"]'),
('8bb232fc-cdf1-4dad-81f8-e8defb593222','雨後江上','鄭獬','宋','宋诗','song-poetry','','[]','船泊碧鑑裏，清風晚思長。',48,'全唐诗/poet.song.33000.json','["船泊碧鑑裏，清風晚思長。", "江皋過微雨，秋色滿斜陽。", "浮野山光動，侵衣水氣凉。", "好尋紫溪叟，共醉碧荷香。"]'),
('4870e283-e5fc-41fb-af10-b2334b1acdc2','雲中憶歸','鄭獬','宋','宋诗','song-poetry','','[]','何日燕南去，平生此別稀。',48,'全唐诗/poet.song.33000.json','["何日燕南去，平生此別稀。", "定知花已發，不及雁先歸。", "寒日連雲慘，驚沙带雪飛。", "雲中風土惡，換盡別家衣。"]'),
('3ca1b03c-46d2-4774-ae58-25a3cf7d5f2e','臨淮大水','鄭獬','宋','宋诗','song-poetry','','[]','大水沒樹杪，涉冬原隰平。',48,'全唐诗/poet.song.33000.json','["大水沒樹杪，涉冬原隰平。", "蛟龍移窟宅，蒲稗出縱橫。", "壞屋久不補，汙田晚更耕。", "接春恐流散，何策活蒼生。"]'),
('67e97713-1fdb-4baa-ab10-4942b3f43c78','邇英閣早直','鄭獬','宋','宋诗','song-poetry','','[]','綠樹蔭脩廊，雲深別殿凉。',48,'全唐诗/poet.song.33000.json','["綠樹蔭脩廊，雲深別殿凉。", "星文開帝座，玉色泛天光。", "大典尊周孔，名家盛漢唐。", "自憐携釣手，持筆翠旒旁。"]'),
('6d74c79a-dc5c-402e-823e-4eed2dfa64e3','朝退','鄭獬','宋','宋诗','song-poetry','','[]','朝退洗雙耳，厭聞人是非。',48,'全唐诗/poet.song.33000.json','["朝退洗雙耳，厭聞人是非。", "不知春意晚，時有燕聲歸。", "散木還容老，孤雲亦倦飛。", "趨時自疏闊，不是學忘機。"]'),
('c27cb407-a555-4c8e-b083-549f2522cee4','閒居二首  其一','鄭獬','宋','宋诗','song-poetry','','[]','空庭羅雀網，應似翟侯居。',48,'全唐诗/poet.song.33000.json','["空庭羅雀網，應似翟侯居。", "多病惟尋藥，忘機不著書。", "僧來留石鼎，人在典金魚。", "惟有南窗睡，春來分不疏。"]'),
('86e4dd0c-eb9e-4de7-8117-c65d36c4d410','閒居二首  其二','鄭獬','宋','宋诗','song-poetry','','[]','不從山下住，若箇似山家。',48,'全唐诗/poet.song.33000.json','["不從山下住，若箇似山家。", "留地教移竹，開門自掃花。", "林疏容鶴卧，溪浄怕雲遮。", "落日杖藜去，塍頭看稻牙。"]'),
('2d9d8f45-78f6-4fb1-aad5-78d1104dc53a','閒悶','鄭獬','宋','宋诗','song-poetry','','[]','閒悶萬千縷，金刀不可裁。',48,'全唐诗/poet.song.33000.json','["閒悶萬千縷，金刀不可裁。", "逢人心不記，見酒眼方開。", "亂夢無時斷，殘春數日回。", "東風固相惱，時送落花來。"]'),
('8eb04540-b558-46f7-9593-e7199a996518','晚悶','鄭獬','宋','宋诗','song-poetry','','[]','晚悶牢難破，秋懷勇未降。',48,'全唐诗/poet.song.33000.json','["晚悶牢難破，秋懷勇未降。", "何人歸楚國，竟日憶溳江。", "鼠迹排書簏，蟲絲網酒缸。", "江都章未報，枕手卧南窗。"]'),
('a6a1166c-b238-4ff3-ab41-ae8213e22688','小軒','鄭獬','宋','宋诗','song-poetry','','[]','鑿見碧天影，秋光注小軒。',48,'全唐诗/poet.song.33000.json','["鑿見碧天影，秋光注小軒。", "消閒惟蠹簡，破悶有金尊。", "怪石中邊透，老松鬚鬣繁。", "人生有佳尚，塵土暗朱門。"]'),
('996ecf45-5231-4273-bd9a-b0604c2ea4f8','不出','鄭獬','宋','宋诗','song-poetry','','[]','高卧即經旬，林間掛葛巾。',48,'全唐诗/poet.song.33000.json','["高卧即經旬，林間掛葛巾。", "野雲閒照水，山鳥自啼春。", "釀酒期佳客，開書見古人。", "莓苔漬雙履，不識洛陽塵。"]'),
('76dd9a71-f479-4765-8919-833d3a7eefec','憶在晉陽','鄭獬','宋','宋诗','song-poetry','','[]','憶在晉陽日，曾爲痛飲家。',48,'全唐诗/poet.song.33000.json','["憶在晉陽日，曾爲痛飲家。", "披衣投宿酒，把燭覓殘花。", "莫解玉驄馬，且留金鈿車。", "壯遊今不復，愁卧鬢將華。"]'),
('366fbf27-79d2-4f00-b0be-a259bd20b7ad','送周密學知真定府','鄭獬','宋','宋诗','song-poetry','','[]','白髮漢中郎，旌旗下建章。',48,'全唐诗/poet.song.33000.json','["白髮漢中郎，旌旗下建章。", "雪通沙路潤，春入塞雲黄。", "地勢井陘口，天文大昴旁。", "平時卷金甲，壯略寄壺觴。"]'),
('5776f219-6641-4c79-b5fc-92ab15d99d45','送惠思歸杭州','鄭獬','宋','宋诗','song-poetry','','[]','湖上秋風滿，歸懷豈易寬。',48,'全唐诗/poet.song.33000.json','["湖上秋風滿，歸懷豈易寬。", "身隨秦樹老，夢入浙江寒。", "爲客久應厭，到家貧亦安。", "石房舊書在，重拂綠塵看。"]'),
('980248e8-f761-474b-97dc-85e0e2811d29','送盛寺丞','鄭獬','宋','宋诗','song-poetry','','[]','蕭相關中守，元瑜鄴下豪。',48,'全唐诗/poet.song.33000.json','["蕭相關中守，元瑜鄴下豪。", "秋風嘶白馬，路草照青袍。", "地入參旗近，河連積石高。", "當年兵戰處，尊酒屬吾曹。"]'),
('9f5d2605-4238-4881-a9d0-e8329925f9de','送張景山知康州','鄭獬','宋','宋诗','song-poetry','','[]','遂溪張太守，懇意乞南州。',48,'全唐诗/poet.song.33000.json','["遂溪張太守，懇意乞南州。", "家在白雲下，郡當滄海頭。", "旌旗瀧水晚，風雨瘴山秋。", "解却淮西印，輕爲萬里遊。"]'),
('89be364b-1f6d-4747-a2b6-ba91166a6209','贈任某','鄭獬','宋','宋诗','song-poetry','','[]','寂寞任夫子，窮山秋氣寒。',48,'全唐诗/poet.song.33000.json','["寂寞任夫子，窮山秋氣寒。", "塵埃雙鬢白，金石寸心丹。", "不悔窮經老，所嗟行道難。", "太阿終亦斷，寧久匣中蟠。"]'),
('e9a2a561-1641-4a40-af65-9a5046266a38','寄汪正夫','鄭獬','宋','宋诗','song-poetry','','[]','汪子清徹骨，竦如秋竹竿。',48,'全唐诗/poet.song.33000.json','["汪子清徹骨，竦如秋竹竿。", "高名九鼎重，俊氣一峰寒。", "議論今誰對，文章古所難。", "青蠅變白黑，無污碧琅玕。"]'),
('e637c0a5-dc12-4e35-abf7-fd05f7c2fb7e','寄陸憲元','鄭獬','宋','宋诗','song-poetry','','[]','陸子處乎順，雖窮志愈剛。',48,'全唐诗/poet.song.33000.json','["陸子處乎順，雖窮志愈剛。", "劍埋金不蝕，圭折玉猶方。", "古意閒中見，浮名靜外忘。", "行藏吾自得，可笑接輿狂。"]'),
('2bb711b7-7bee-4a7e-b9ee-e9df069f5ebd','李道士','鄭獬','宋','宋诗','song-poetry','','[]','金鼓破南粵，山中冷不聞。',48,'全唐诗/poet.song.33000.json','["金鼓破南粵，山中冷不聞。", "是非同一馬，富貴自浮雲。", "吐納龍虎氣，遨遊麋鹿群。", "朝來問丹訣，已酌凍醪醺。"]'),
('b78ee3e9-b619-4bc9-a7fa-4c993ba41886','次韵酬張擇甫','鄭獬','宋','宋诗','song-poetry','','[]','別後正春孟，溪頭黄柳芽。',48,'全唐诗/poet.song.33000.json','["別後正春孟，溪頭黄柳芽。", "相思滿芳草，獨自照殘花。", "晚樹秦川闊，黄雲瘴海賒。", "上樓無別望，歸路向西斜。"]'),
('dd5f108a-4efd-40ec-8cbf-4748dad62ce8','留別汪正夫','鄭獬','宋','宋诗','song-poetry','','[]','夫子青雲士，聲名孰與齊。',48,'全唐诗/poet.song.33000.json','["夫子青雲士，聲名孰與齊。", "心經時事老，顔向俗人低。", "氣象必衝斗，風雷猶蟄泥。", "行看萬里志，聊爾謝群雞。"]'),
('5748bd5f-8a1d-404b-8c2d-0fb3667adb45','贈儀真密禪師','鄭獬','宋','宋诗','song-poetry','','[]','渾淪老學佛，到處說支郎。',48,'全唐诗/poet.song.33000.json','["渾淪老學佛，到處說支郎。", "斷臂求諸法，浮杯遍十方。", "自栽雙柏樹，獨坐一繩床。", "惟有林間客，時來扣竹房。"]'),
('f60c8631-5291-406f-b7f0-de449e9f97c5','即事簡友人','鄭獬','宋','宋诗','song-poetry','','[]','門巷遍芳草，相期春醉稀。',48,'全唐诗/poet.song.33000.json','["門巷遍芳草，相期春醉稀。", "可憐雙燕到，還似故人歸。", "幽鳥隔溪語，落花穿竹飛。", "誰知靜者樂，石上脫朝衣。"]'),
('746b75fb-dda0-4ab1-b7c6-e7e97d286005','久不得孫中叔信','鄭獬','宋','宋诗','song-poetry','','[]','秋風起天末，之子在窮途。',48,'全唐诗/poet.song.33000.json','["秋風起天末，之子在窮途。", "久客住應悶，故鄉歸得無。", "清淮不到渭，晚樹自沈吳。", "願寄一樽酒，與君消壯圖。"]'),
('042f0054-31f9-46ad-97d8-529970db1fa8','明皇','鄭獬','宋','宋诗','song-poetry','','[]','四海不摇草，九重藏禍根。',48,'全唐诗/poet.song.33000.json','["四海不摇草，九重藏禍根。", "十年傲堯舜，一笑破乾坤。", "羌貊皆冠冕，豺狼盡子孫。", "潼關兵已破，會憶老臣言。"]'),
('71bbf5d0-e378-4365-bc7b-3b7f24fe0365','晉陽宮基','鄭獬','宋','宋诗','song-poetry','','[]','金屋無寸瓦，蒼然老樹青。',48,'全唐诗/poet.song.33000.json','["金屋無寸瓦，蒼然老樹青。", "海枯露龍穴，火盡見坤靈。", "自昔流血處，於今土氣腥。", "廢興千載事，過耳一飛霆。"]'),
('4d14eb71-d567-40b1-b5a9-f5df1471b297','題招提院靜照堂','鄭獬','宋','宋诗','song-poetry','','[]','招提去山遠，還似在山家。',48,'全唐诗/poet.song.33000.json','["招提去山遠，還似在山家。", "晚日惟歸鳥，春風自落花。", "空談銷劍火，醉墨灑天葩。", "更欲拏舟去，清溪月正華。"]'),
('dce5e496-936d-4e59-b932-6bb7bdd7e931','題處士居','鄭獬','宋','宋诗','song-poetry','','["\u592a\u6e56"]','高卧太湖石，自嫌名利腥。',48,'全唐诗/poet.song.33000.json','["高卧太湖石，自嫌名利腥。", "網羅當道路，鴻鵠出青冥。", "氣貯秋琴淡，心蟠古劍靈。", "我來閒劇論，山鬼不須聽。"]'),
('6d89a051-87e5-45cc-97b5-bfa225e60d7c','王氏園','鄭獬','宋','宋诗','song-poetry','','[]','車馬少行迹，鄰僧爲掩門。',48,'全唐诗/poet.song.33000.json','["車馬少行迹，鄰僧爲掩門。", "飛泉鳴似雨，老竹瘦於孫。", "幽鳥靜相語，晚花寒亦繁。", "主人雙綬重，遊客倒金樽。"]'),
('a2f00ffa-df46-4d75-a1d0-77859c7f8393','簡夫別墅','鄭獬','宋','宋诗','song-poetry','','[]','靜境清無敵，門前繫鹿車。',48,'全唐诗/poet.song.33000.json','["靜境清無敵，門前繫鹿車。", "買山憑野客，覓竹到鄰家。", "棋爲尋圖勝，書因借本差。", "平時非厭仕，所樂在桑麻。"]'),
('ed69ca64-cbc0-4875-858a-f151e83f11b9','簡夫北墅','鄭獬','宋','宋诗','song-poetry','','[]','先生已到舍，稚子未歸樵。',48,'全唐诗/poet.song.33000.json','["先生已到舍，稚子未歸樵。", "草晚牛羊病，場登雀鼠驕。", "孔顔雖困魯，夔契未忘堯。", "自笑非逋客，煩君重見招。"]'),
('891b4b0d-7d85-45ea-bd4d-d207daf0d253','挽程中書令三首  其一','鄭獬','宋','宋诗','song-poetry','','[]','社稷方爲繫，乾坤豈不容。',48,'全唐诗/poet.song.33000.json','["社稷方爲繫，乾坤豈不容。", "廟堂遺劍履，風雨失蛟龍。", "漢將蓮花幕，周人馬鬣封。", "小羌猶慢禮，先折太阿鋒。"]'),
('e9327a2c-3c7e-41c2-9209-b69aa3374edc','挽程中書令三首  其二','鄭獬','宋','宋诗','song-poetry','','[]','舊愛霓裳曲，翻聞薤露歌。',48,'全唐诗/poet.song.33000.json','["舊愛霓裳曲，翻聞薤露歌。", "賢人今已矣，天道竟如何。", "泉下一抔盡，人間萬事多。", "空餘幕中客，寫淚劇懸河。"]'),
('908b9508-d891-46b5-823d-b59389d2ab21','挽程中書令三首  其三','鄭獬','宋','宋诗','song-poetry','','[]','湖上千條柳，山翁舊日栽。',48,'全唐诗/poet.song.33000.json','["湖上千條柳，山翁舊日栽。", "自從春水綠，不見相車來。", "明月何須好，餘花忽更開。", "平生歌舞地，零落濕蒼苔。"]'),
('cbb114d9-136d-4af8-992f-60d546afc28b','挽仁宗皇帝辭五首  其一','鄭獬','宋','宋诗','song-poetry','','[]','恭儉同堯舜，憂勤固損年。',48,'全唐诗/poet.song.33000.json','["恭儉同堯舜，憂勤固損年。", "悲風來萬國，白日下中天。", "薄葬遵周室，初陵兆洛川。", "至仁推廟號，百世不能遷。"]'),
('f226a3bd-023f-489c-a55c-ec03a2d46e92','挽仁宗皇帝辭五首  其二','鄭獬','宋','宋诗','song-poetry','','[]','四海一明鑑，舟車萬里通。',48,'全唐诗/poet.song.33000.json','["四海一明鑑，舟車萬里通。", "名王花賜綬，戰士錦韜弓。", "孝武曾疲戰，明皇亦召戎。", "爭如四十載，終始太平中。"]'),
('46dcc182-06e1-47e2-aef0-9caaa5380584','挽仁宗皇帝辭五首  其三','鄭獬','宋','宋诗','song-poetry','','[]','付託神靈器，子孫千萬年。',48,'全唐诗/poet.song.33000.json','["付託神靈器，子孫千萬年。", "果爲天下福，遂得聖人傳。", "已定無疆業，方成顧命篇。", "明朝無一事，脫屣或登仙。"]'),
('90ca1575-1b76-43cb-8ccb-6839ef3bd966','挽仁宗皇帝辭五首  其四','鄭獬','宋','宋诗','song-poetry','','[]','歌舞西陵望，衣冠渭北遊。',48,'全唐诗/poet.song.33000.json','["歌舞西陵望，衣冠渭北遊。", "應從天上樂，不爲世間留。", "龍去鼎湖晚，雁飛汾水秋。", "群臣淚橫臆，空拜翠雲裘。"]'),
('3157afb4-2911-41e7-8cac-c9cf04ead00f','挽仁宗皇帝辭五首  其五','鄭獬','宋','宋诗','song-poetry','','[]','曾從西池幸，宮花落未稀。',48,'全唐诗/poet.song.33000.json','["曾從西池幸，宮花落未稀。", "日隨黄繖轉，雲繞赭袍飛。", "臨水樓臺在，傷心歌管非。", "都門舊行處，却望壽山歸。"]'),
('4559d8d8-7413-40b9-bd2d-6f1951b9b039','挽吳宣徽  其一','鄭獬','宋','宋诗','song-poetry','','[]','平生負高節，至死寸心丹。',48,'全唐诗/poet.song.33000.json','["平生負高節，至死寸心丹。", "明主雖容進，孤臣豈易安。", "神歸嵩嶽黑，人哭洛川寒。", "不識平津面，臨風亦涕汍。"]'),
('4a69b5cf-c0aa-458f-8c54-abbaf2da49f2','挽吳宣徽  其二','鄭獬','宋','宋诗','song-poetry','','[]','大策三千字，朝廷耳目醒。',48,'全唐诗/poet.song.33000.json','["大策三千字，朝廷耳目醒。", "高名動牛斗，直氣破雷霆。", "美行皆成法，閒談盡可銘。", "悲哉真玉樹，風雨一飄零。"]'),
('39905569-3d8f-4bcb-8062-a7e0b7773121','傷田肅秀才','鄭獬','宋','宋诗','song-poetry','','[]','働哭遂滅性，誰言天道長。',48,'全唐诗/poet.song.33000.json','["働哭遂滅性，誰言天道長。", "未收雙寶劍，已失一飛黄。", "稚子遥虛祭，孤棺寄異鄉。", "可憐江夏守，不得薦黄香。"]'),
('bb70c6a6-7a5c-41b4-8ca0-a3a8eb8abaea','石榴','鄭獬','宋','宋诗','song-poetry','','[]','高枝重欲折，霜老裂丹膚。',48,'全唐诗/poet.song.33000.json','["高枝重欲折，霜老裂丹膚。", "試剖紫金椀，滿堆紅玉珠。", "根雖傳大夏，種必近仙都。", "題作江南信，人應賤橘奴。"]'),
('68927fa8-6509-4509-ba02-5cb8b7c3b85c','貢麟','鄭獬','宋','宋诗','song-poetry','','[]','麟本出中國，無聞貢海濱。',48,'全唐诗/poet.song.33000.json','["麟本出中國，無聞貢海濱。", "豈將遠方獸，煩我太平民。", "烹割羅牲餼，奔趨掃路塵。", "漢高嘗聘士，此禮屬蠻人。"]'),
('a0cc1906-7387-453b-a3e0-ce34d404ba42','昔遊','鄭獬','宋','宋诗','song-poetry','','[]','小旗短棹西池上，青杏煮酒寒食頭。',64,'全唐诗/poet.song.33000.json','["小旗短棹西池上，青杏煮酒寒食頭。", "綠楊陰裏穿小巷，鬧花深處藏高樓。", "紫絲絡馬客欲起，錦袖挽衣人相留。", "逢春倚醉不自醒，明朝始對春風羞。"]'),
('a5b71f79-4868-46eb-b248-6ff42badf0dc','夜懷','鄭獬','宋','宋诗','song-poetry','','[]','獨倚青桐聽鼓聲，參旗歷落上三更。',64,'全唐诗/poet.song.33000.json','["獨倚青桐聽鼓聲，參旗歷落上三更。", "凉風卷雨忽中斷，明月背雲還倒行。", "頼有清吟消意馬，豈無美酒破愁城。", "是非人世何須校，方外曾師阮步兵。"]'),
('e7c67f9b-7827-41cc-9eb7-0114e7de947f','獨遊','鄭獬','宋','宋诗','song-poetry','','[]','馬後獨携一壺酒，林間更解紫綸巾。',64,'全唐诗/poet.song.33000.json','["馬後獨携一壺酒，林間更解紫綸巾。", "飛來白鷺即佳客，相對好花爲美人。", "萬事易忘唯劇醉，四時難判是殘春。", "吳兒曾識陶彭澤，又見羲皇一散民。"]'),
('860f11c7-c6e0-4eea-88c0-617ae1e585ce','野步','鄭獬','宋','宋诗','song-poetry','','[]','留著雲扉儘晚關，穿林踏破紫苔斑。',64,'全唐诗/poet.song.33000.json','["留著雲扉儘晚關，穿林踏破紫苔斑。", "虹蜺渴雨欲下澗，魍魎避人還入山。", "石觜露烟孤歷刺，溪腰纏草綠灣環。", "野僧有意待明月，獨倚一筇松竹間。"]'),
('683cd69d-757c-4222-add9-f696c8be479e','清明郊外','鄭獬','宋','宋诗','song-poetry','','[]','桃葉青青杏子肥，清明雨後舊花稀。',64,'全唐诗/poet.song.33000.json','["桃葉青青杏子肥，清明雨後舊花稀。", "草翻蝴蝶日將晚，門掩鞦韆人未歸。", "春艷濃堪燒美酒，湖光綠好染羅衣。", "柳條滿插金車上，一路香塵去似飛。"]'),
('36c72a79-1c10-45f1-9ca2-5f378aae6c64','驟寒','鄭獬','宋','宋诗','song-poetry','','[]','四擁蒼雲拂浪驚，北風飛下海濤聲。',64,'全唐诗/poet.song.33000.json','["四擁蒼雲拂浪驚，北風飛下海濤聲。", "水摇冰骨凍未得，雨作雪花開不成。", "玉匣寶刀鋒欲折，鐵衣戰騎力還生。", "杏梢柳葉無聊頼，爲祝鳴鳩探晚晴。"]'),
('924070db-41c4-4130-ad3d-3d2471f2bab1','晚發關山','鄭獬','宋','宋诗','song-poetry','','[]','燭前行客捲征衣，路轉平林入翠微。',64,'全唐诗/poet.song.33000.json','["燭前行客捲征衣，路轉平林入翠微。", "家在白雲鄉裏住，人從明月嶺邊歸。", "來時未見梨花破，別後方驚燕子飛。", "綠樹連陰十三驛，從今歸夢到家稀。"]'),
('8484eae5-424d-4243-b04c-2f33801cd05b','宿白雪驛','鄭獬','宋','宋诗','song-poetry','','[]','春酒味濃殊不解，繞廊倚柱獨徘徊。',64,'全唐诗/poet.song.33000.json','["春酒味濃殊不解，繞廊倚柱獨徘徊。", "蒼山碧樹共沈寂，明月斷雲相往來。", "細雨忽飄溪外去，好風却傍竹間回。", "朝來已有西歸燕，爲問庭花幾日開。"]'),
('d7ee13e1-4c39-4a06-9cd1-db0c054091af','再至會稽','鄭獬','宋','宋诗','song-poetry','','[]','自憐多病趁朝稀，合引朱轓東路歸。',64,'全唐诗/poet.song.33000.json','["自憐多病趁朝稀，合引朱轓東路歸。", "名姓未通丹陛下，夢魂已過浙江飛。", "人生如意即爲樂，世事驚心漸覺非。", "正是春風催酒熟，蝤蛑霜飽蛤蜊肥。"]'),
('7ec20897-9eb6-4f1b-bfa2-3e92c115f7cc','金陵道中','鄭獬','宋','宋诗','song-poetry','','[]','六國相排一局棋，岸頭百草野烟微。',64,'全唐诗/poet.song.33000.json','["六國相排一局棋，岸頭百草野烟微。", "樹深啼鳥自相失，山靜晚雲猶未歸。", "濡口潮回殘照滿，石城春盡亂花飛。", "周郎屈指圖天下，誰道江南玉鱠肥。"]'),
('02eb3cfb-6a09-4824-a5bb-0a98c1b800c4','汴河夜行','鄭獬','宋','宋诗','song-poetry','','[]','汴流長恐日夜落，夜行愁殺刺船郎。',64,'全唐诗/poet.song.33000.json','["汴流長恐日夜落，夜行愁殺刺船郎。", "櫓聲驚破老龍睡，船底觸翻明月光。", "大兒燈下尋難字，小女窗間學翦裳。", "自笑病夫無所事，一尊身世兩相忘。"]'),
('67c26377-0441-40fb-9961-9bdb37722a5f','下第後與孫仲叔飲','鄭獬','宋','宋诗','song-poetry','','[]','萬里青雲失意深，畫樓酒美共登臨。',64,'全唐诗/poet.song.33000.json','["萬里青雲失意深，畫樓酒美共登臨。", "不羞獨落衆人後，却是重辜親老心。", "一缺不完非折劍，至剛無屈是精金。", "男兒三十年方壯，何必尊前淚滿襟。"]'),
('0ec4e316-dc43-4fa4-87f2-18ce5b7148ba','江上','鄭獬','宋','宋诗','song-poetry','','[]','蘆葉蕭蕭江上秋，鰣魚清酒解消憂。',64,'全唐诗/poet.song.33000.json','["蘆葉蕭蕭江上秋，鰣魚清酒解消憂。", "雲纔散後月當浦，潮欲來時風滿樓。", "好景未應輸白鷺，飛塵終不到扁舟。", "晚來天卷蒼霞盡，萬頃玻璃爛不收。"]'),
('c3bc83a0-efec-4774-bd1c-c2cd3f0b76a5','次韵汪正夫對雨','鄭獬','宋','宋诗','song-poetry','','[]','雨氣飄蕭動竹齋，驚秋高思若爲裁。',64,'全唐诗/poet.song.33000.json','["雨氣飄蕭動竹齋，驚秋高思若爲裁。", "壯心雖被愁催去，歡意須憑酒借來。", "雲脚一從邊地合，風頭半是海潮回。", "長汀從此傷摇落，獨有騷人最費才。"]'),
('b5386c5b-c63f-4ca6-9b3d-f2a396a109ff','雨餘','鄭獬','宋','宋诗','song-poetry','','[]','飛雨淙淙萬弩奔，雨餘氣象變朝曛。',64,'全唐诗/poet.song.33000.json','["飛雨淙淙萬弩奔，雨餘氣象變朝曛。", "長虹挂雨出青嶂，落日翻光燒赤雲。", "得水跳蛙惟召鬧，投林栖雀自求群。", "欲尋方外無窮樂，更滿梨花四五分。"]'),
('5a5ddd10-e8b8-43dc-a842-17f4239cc2fc','水館','鄭獬','宋','宋诗','song-poetry','','[]','繞舍清流淙碧玉，塵懷開闊灑然醒。',64,'全唐诗/poet.song.33000.json','["繞舍清流淙碧玉，塵懷開闊灑然醒。", "窗欞風入秋氣活，橋脚倒撐天面青。", "露濕風標紅芰老，雨生鱗甲伏龍腥。", "將書借取琴高鯉，從此橫騎入杳冥。"]'),
('16ef6bff-34ed-44e8-9345-417c9e3185c2','春盡二首  其一','鄭獬','宋','宋诗','song-poetry','','[]','春盡行人未到家，春風應怪在天涯。',64,'全唐诗/poet.song.33000.json','["春盡行人未到家，春風應怪在天涯。", "夜來過嶺忽聞雨，今日滿溪俱是花。", "前樹未回疑路斷，後山纔轉便雲遮。", "夜間絕少塵埃污，惟有清泉漾白沙。"]'),
('3d88f77c-0426-48b3-9727-617a2350fb12','春盡二首  其二','鄭獬','宋','宋诗','song-poetry','','[]','禁籞平明帳殿開，華芝初下未央來。',64,'全唐诗/poet.song.33000.json','["禁籞平明帳殿開，華芝初下未央來。", "人間彩鳳儀韶曲，天上流霞滿御杯。", "花近赭袍偏燦爛，魚窺仙仗亦徘徊。", "蓬萊絕景何曾到，自愧塵蹤此一陪。"]'),
('270fc1ab-38a3-4aa1-beb8-ba769c5153c4','松陵道中','鄭獬','宋','宋诗','song-poetry','','[]','蕭蕭落日荻花林，秋浪陂陀快醉襟。',64,'全唐诗/poet.song.33000.json','["蕭蕭落日荻花林，秋浪陂陀快醉襟。", "江上碧峰偏入眼，沙邊白鳥最知心。", "百分美酒酬雙鬢，一覺高眠敵萬金。", "聞道鱸魚屬張翰，飛帆欲過五湖尋。"]'),
('b5b23f55-8138-49fb-9599-40619fbe0e0b','次韵丞相柳湖席上','鄭獬','宋','宋诗','song-poetry','','[]','湖上春深不見沙，畫橋飛影入晴霞。',64,'全唐诗/poet.song.33000.json','["湖上春深不見沙，畫橋飛影入晴霞。", "園林到處消得酒，風雨等閒飛盡花。", "令罰艷歌傳盞急，詩成醉墨落箋斜。", "蘭亭樂事無絲管，待與羲之子細誇。"]'),
('0bb74006-5a63-4c0d-abc6-40a29d2b3c45','早朝馬上口占','鄭獬','宋','宋诗','song-poetry','','[]','赤城橫絕六鼇頭，夾道欄干覆御溝。',64,'全唐诗/poet.song.33000.json','["赤城橫絕六鼇頭，夾道欄干覆御溝。", "殘月畫樓雙闕曉，凉風綠樹萬家秋。", "聯飛群鵠愧豪彥，醉卧落花思舊遊。", "御史臨班望天陛，紫雲飛繞翠雲裘。"]'),
('e4becf5e-af5c-42ee-b6e8-839ff03e9032','早朝','鄭獬','宋','宋诗','song-poetry','','[]','花鬣斑虬駕早朝，玉欄宮殿壓雲濤。',64,'全唐诗/poet.song.33000.json','["花鬣斑虬駕早朝，玉欄宮殿壓雲濤。", "九州畫地中原壯，萬象橫天紫極高。", "日月輝明留闕角，龍蛇蟠結動旌旄。", "群仙遥望蓬萊拜，五色非烟繞赭袍。"]'),
('68b333eb-b3dd-44a6-843b-7c5a6902633b','恭和御製賞花釣魚','鄭獬','宋','宋诗','song-poetry','','[]','輦路鮮雲五色開，一聲清蹕下天來。',64,'全唐诗/poet.song.33000.json','["輦路鮮雲五色開，一聲清蹕下天來。", "水光翠繞九重殿，花氣醲薰萬壽杯。", "繡幕烟深紅匼匝，文竿風引綠徘徊。", "蓬山絕景無人到，詔許群仙盡日陪。"]'),
('9e0ca30e-1364-4da9-b340-2971329be86c','題垂虹橋寄同年叔楙秘校','鄭獬','宋','宋诗','song-poetry','','[]','三百欄干鎖畫橋，行人波上踏靈鼇。',64,'全唐诗/poet.song.33000.json','["三百欄干鎖畫橋，行人波上踏靈鼇。", "插天螮蝀玉腰闊，跨海鯨鯢金背高。", "路險截開元氣白，影寒壓破大江豪。", "此中自與銀河接，不必仙槎八月濤。"]'),
('8a7daec4-b3eb-42a5-9463-2569acf5dbbb','槜李亭','鄭獬','宋','宋诗','song-poetry','','[]','閒抱琴書槜李遊，仙壇古屋一筇留。',64,'全唐诗/poet.song.33000.json','["閒抱琴書槜李遊，仙壇古屋一筇留。", "驛橋通市人沽酒，湖水依城客放舟。", "葵扇桃笙聊却暑，蘋花楓葉已知秋。", "坡翁仙去詩聲在，寂寞林塘卧白鷗。"]'),
('481e3e06-feab-452d-ad67-6d7df23dc79c','月波樓','鄭獬','宋','宋诗','song-poetry','','[]','古壕鑿出明月背，樓角飛來兔影中。',64,'全唐诗/poet.song.33000.json','["古壕鑿出明月背，樓角飛來兔影中。", "野色更無山隔斷，天光直與水相通。", "溪藏畫舫青紋接，人住荷花碧玉叢。", "誰把金魚破清暑，晚雲深處待歸風。"]'),
('02285206-6dfc-44da-9692-debb45169be6','題淮陰侯廟','鄭獬','宋','宋诗','song-poetry','','[]','漢高不得淮陰將，天下雌雄未可知。',64,'全唐诗/poet.song.33000.json','["漢高不得淮陰將，天下雌雄未可知。", "力勸君王回蜀道，便携諸將破秦師。", "故人斬首誠非策，女子陰謀遂見欺。", "終使英雄鑒成敗，未圖功業自先疑。"]'),
('19cbdb2e-9c89-4412-8ef0-87d44bc3bb96','初春欲爲小飲先寄運使唐司勳運判張都官','鄭獬','宋','宋诗','song-poetry','','[]','人生長與賞心違，莫遣樽前笑語稀。',64,'全唐诗/poet.song.33000.json','["人生長與賞心違，莫遣樽前笑語稀。", "老去未羞花插帽，醉來不怕酒淋衣。", "免聽畫鼓催朝去，且駐金鞍待月歸。", "休道東風猶早在，落梅已撲翠苔飛。"]'),
('ee066816-a3c4-41c0-ad24-772cf047be0b','九日登有美堂','鄭獬','宋','宋诗','song-poetry','','[]','點檢東山窈窕娘，直須醉倒爲重陽。',64,'全唐诗/poet.song.33000.json','["點檢東山窈窕娘，直須醉倒爲重陽。", "山光湖水一時好，酒面菊花同色黄。", "便好共謀長夜飲，未應排出少年場。", "傷時感舊知何限，還憶荆州落寞鄉。"]'),
('9fa94d0b-68e3-43ff-a468-53b256de21e9','次韵張公達遊西池','鄭獬','宋','宋诗','song-poetry','','[]','醉漾蘭舟不忍歸，斜陽已落碧雲西。',64,'全唐诗/poet.song.33000.json','["醉漾蘭舟不忍歸，斜陽已落碧雲西。", "天開銀漢水初滿，春入武陵人自迷。", "殿倚鼇頭連並幕，橋飛虹影度金堤。", "遊人不惜殘花地，無限落紅粘馬蹄。"]'),
('530d0773-447a-4b62-ab42-f9129d04a344','呂稚卿唐彥範並賦遊西池亦成菲句','鄭獬','宋','宋诗','song-poetry','','[]','青翰龍舟雲外橫，黄金殿閣鏡中明。',64,'全唐诗/poet.song.33000.json','["青翰龍舟雲外橫，黄金殿閣鏡中明。", "波光柳色恰相似，酒味人心俱有情。", "醉灑珠璣留滿紙，晚騎鸞鳳下層城。", "遊人應解笑狂客，隔水映花聞語聲。"]'),
('5f3aca69-d776-4db3-b934-97446edf19cc','同彥範謁仲巽飲之甚樂仲巽且有北歸之期情見卒章輒用寫呈','鄭獬','宋','宋诗','song-poetry','','[]','明珠堆滿赤金盤，未買花前笑倚欄。',64,'全唐诗/poet.song.33000.json','["明珠堆滿赤金盤，未買花前笑倚欄。", "特地尋春難約伴，等閒携酒却成歡。", "人生試把從頭算，世事何煩著眼看。", "莫怪夜深猶換燭，它時相望在長安。"]'),
('33536e3f-051f-40c3-854b-df7364cac3cd','再和','鄭獬','宋','宋诗','song-poetry','','[]','海棠亂插滿琱盤，爲愛繁梢更繞欄。',64,'全唐诗/poet.song.33000.json','["海棠亂插滿琱盤，爲愛繁梢更繞欄。", "顧我有情還惜別，聞君未去且留歡。", "錦裀只就花邊卧，細袖偏宜燭下看。", "若背荆州容易去，故人於義未爲安。"]'),
('bb55b831-2367-4a6c-b5a5-5db7a79ec1a3','遊金明池','鄭獬','宋','宋诗','song-poetry','','[]','萬座笙歌醉復醒，繞池羅幕翠烟生。',64,'全唐诗/poet.song.33000.json','["萬座笙歌醉復醒，繞池羅幕翠烟生。", "雲藏宮殿九重碧，春入乾坤五色明。", "波底畫橋天上動，岸邊遊客鑑中行。", "金輿時幸龍舟宴，花外風飄萬歲聲。"]'),
('599cde67-183c-46ed-8943-af14edd91b79','盆池','鄭獬','宋','宋诗','song-poetry','','[]','綠髮柔莎碧甃連，湛如蛟穴貯寒泉。',64,'全唐诗/poet.song.33000.json','["綠髮柔莎碧甃連，湛如蛟穴貯寒泉。", "誰將寶鏡遺在地，照見浮雲浸破天。", "數鬣游魚纔及寸，一層綠荇小於錢。", "待將鬧物都除却，放出秋蟾夜夜圓。"]'),
('500689a7-4e89-48d5-afaf-cb00ccbe077e','李都尉芙蓉堂','鄭獬','宋','宋诗','song-poetry','','[]','堂上芙蓉花最饒，開時不見玉欄橋。',64,'全唐诗/poet.song.33000.json','["堂上芙蓉花最饒，開時不見玉欄橋。", "來從洛浦見羅襪，生在楚宮俱細腰。", "何處仙人來跨鳳，夜深明月好吹簫。", "剩收秋蕊爲佳釀，醉入飛雲解畫橈。"]'),
('ee99e836-ac74-4c55-a54a-068ba0828d64','東園招孫中叔','鄭獬','宋','宋诗','song-poetry','','[]','花路橫梢已礙馬，斷無人迹賞年芳。',64,'全唐诗/poet.song.33000.json','["花路橫梢已礙馬，斷無人迹賞年芳。", "綠楊成穗點著地，蝴蝶作團飛過牆。", "不禁夢回多黯鬰，長因酒後得凄凉。", "期君待與春翁約，買取東風任醉鄉。"]'),
('43a07325-a046-44c7-93a5-969629e42dc3','次韵元肅兄汴口阻風','鄭獬','宋','宋诗','song-poetry','','[]','風阻浪頭如駴馬，險於天塹欲摧車。',64,'全唐诗/poet.song.33000.json','["風阻浪頭如駴馬，險於天塹欲摧車。", "却隨宿雁留寒渚，深羨飛雲韂碧虛。", "對酒客懷真土梗，滿船生計只圖書。", "世無勇奡携之去，不得連鼇作鱠魚。"]'),
('bf9c8368-f3ff-4c14-b992-d4baa0034db4','次韵元肅兄三題汴渠夜泛','鄭獬','宋','宋诗','song-poetry','','[]','汴渠夜泛亦快意，月射長波如斷冰。',64,'全唐诗/poet.song.33000.json','["汴渠夜泛亦快意，月射長波如斷冰。", "不見湘靈揮寶瑟，空教水怪避犀燈。", "煙雲疊影相虧蔽，星斗翻芒互降升。", "好蓄金錢多買酒，滿船載去覓嚴陵。"]'),
('49758208-3dfc-4ffc-b343-dc0c9a38f404','雨夜懷唐安','鄭獬','宋','宋诗','song-poetry','','[]','歸心日夜逆江流，官柳三千憶蜀州。',64,'全唐诗/poet.song.33000.json','["歸心日夜逆江流，官柳三千憶蜀州。", "小閣簾櫳頻夢蝶，平湖煙水已盟鷗。", "螢依濕草同爲旅，雨滴空階別是愁。", "堪笑邦人不解事，區區猶借陸君留。"]'),
('97d13904-01fa-4eff-b228-365cacc875a8','過魏都','鄭獬','宋','宋诗','song-poetry','','[]','憶把貂裘買玉壺，重來不敢解金魚。',64,'全唐诗/poet.song.33000.json','["憶把貂裘買玉壺，重來不敢解金魚。", "當時曾謁將軍府，今日還乘使者車。", "歌管漸非人去後，樓臺依舊雪消初。", "韓門弟子偏怊悵，淚滿朝陽耆舊書。"]'),
('e3d8614e-d699-44af-9b71-50afafe56458','勸客飲','鄭獬','宋','宋诗','song-poetry','','[]','誰解西回滄海波，且聽白苧數聲歌。',64,'全唐诗/poet.song.33000.json','["誰解西回滄海波，且聽白苧數聲歌。", "人生所得只如此，世事到頭無奈何。", "酒海莫教空濩落，金堆安用鬰嵯峨。", "古今共是一丘土，只有劉生得計多。"]'),
('6ef589b7-43c5-42b1-b382-54c003366bae','初入姑蘇會飲','鄭獬','宋','宋诗','song-poetry','','[]','凉風飄灑入高閣，滿城綠樹飛雲濤。',64,'全唐诗/poet.song.33000.json','["凉風飄灑入高閣，滿城綠樹飛雲濤。", "渴來夢吞滄海闊，醉後眼掛青天高。", "湘江姹女碧瑶佩，金谷謫仙紅錦袍。", "吳兒柔軟不慣見，應笑儂家詩酒豪。"]'),
('a90e161c-f537-4b8e-9d43-c11153b65287','正夫飲遐舉家留佳什僕酷愛其金斗玉泉之句輒次高韵','鄭獬','宋','宋诗','song-poetry','','[]','相逢漸向白頭年，世路諳來盡付天。',64,'全唐诗/poet.song.33000.json','["相逢漸向白頭年，世路諳來盡付天。", "六印雖多終是客，一壺纔倒即爲仙。", "穿天入月捉詩句，搥鼓插旗飛酒船。", "長願醉眠渾不醒，虛名安用俗兒傳。"]'),
('6f13d50c-82ae-4208-87d2-fa34e0690507','次韵梁天機見寄','鄭獬','宋','宋诗','song-poetry','','[]','一聽秋聲鬢已凋，孤心驚起拂星杓。',64,'全唐诗/poet.song.33000.json','["一聽秋聲鬢已凋，孤心驚起拂星杓。", "輪囷自分爲蟠木，濩落寧堪作大瓢。", "新篋唱酬詩草滿，舊衣傾潑酒痕消。", "高篇已許臨佳菊，更作欄桿護翠條。"]'),
('70e587d1-eff6-49bd-8c12-b7ee0b3d19f1','往年與劉元忠諸公尋春夜歸今茲卧病感而成篇','鄭獬','宋','宋诗','song-poetry','','[]','已醒又醉倦遊客，乍雨却晴寒食天。',64,'全唐诗/poet.song.33000.json','["已醒又醉倦遊客，乍雨却晴寒食天。", "共繫紫騮芳樹下，却隨紅燭落花前。", "層城已報黄金鎖，外苑猶貪碧草眠。", "明月春風依舊好，竹溪散盡酒中仙。"]'),
('e703c5d7-e391-43c9-ba81-a04e90a8c885','喜吳幾道遷右正言知諫院','鄭獬','宋','宋诗','song-poetry','','[]','精金喜入陶鎔手，玉鑑直須明主知。',64,'全唐诗/poet.song.33000.json','["精金喜入陶鎔手，玉鑑直須明主知。", "志士本來能許國，古人所恨不逢時。", "漢成不用朱雲劍，舜帝嘗聞大禹辭。", "莫道孤居無感激，挼挲兩耳聽京師。"]'),
('057e0c96-d7ff-49b6-a432-da49abf96a5f','戲學張水部贈河南少尹','鄭獬','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','河南少尹鬢如絲，甪里先生是吏師。',64,'全唐诗/poet.song.33000.json','["河南少尹鬢如絲，甪里先生是吏師。", "花下放衙因試酒，竹間留客爲尋棋。", "年勞只許鈔書數，月俸長留買藥資。", "已說開春須上表，終南山下乞分司。"]'),
('1c5a75c7-0f15-4ab9-9817-d28a942f528e','施君作詩贈謙師亦求拙句乃作五十六字綴其後','鄭獬','宋','宋诗','song-poetry','','[]','聞道天台謙上人，溪魚野鳥共忘形。',64,'全唐诗/poet.song.33000.json','["聞道天台謙上人，溪魚野鳥共忘形。", "林間無事結跏坐，石上更安圓覺經。", "定處只應山鬼護，講時還有海龍聽。", "何年蠟屐緣雲徑，一叩靈仙不死庭。"]'),
('2d31dbaa-576e-4963-9e20-5ceea31443bc','送曹比部赴袁州','鄭獬','宋','宋诗','song-poetry','','[]','船頭獵獵兩旗翻，六月江風灑面寒。',64,'全唐诗/poet.song.33000.json','["船頭獵獵兩旗翻，六月江風灑面寒。", "一日却稱新太守，十年曾是舊郎官。", "中間憂患誠爲甚，向老風情亦未闌。", "紫背蛤蜊白醪酒，開樽長解憶長安。"]'),
('3c381965-100a-4977-aa67-23e7c1be54f4','次韵元肅兄見喜知荆州二首  其一','鄭獬','宋','宋诗','song-poetry','','[]','逾年謬掌鳳凰詔，擇日拜章芸若庭。',64,'全唐诗/poet.song.33000.json','["逾年謬掌鳳凰詔，擇日拜章芸若庭。", "擁節笑歸江漢國，飛帆醉拂斗牛星。", "留連物景詩千首，準擬交親酒百瓶。", "共採芳蘭晨事畢，不妨兒姪夜橫經。"]'),
('c2600e78-bf3a-405a-89b5-6ddbcedc207f','次韵元肅兄見喜知荆州二首  其二','鄭獬','宋','宋诗','song-poetry','','[]','西風原上鶺鴒鳴，喜見朱旗畫獸獰。',64,'全唐诗/poet.song.33000.json','["西風原上鶺鴒鳴，喜見朱旗畫獸獰。", "塵袖漸拋秦地遠，雲帆聊作楚江行。", "人家掩映寒塘水，秋物鮮明綠樹橙。", "欲表新阡在鄖國，不同張翰浪逃名。"]'),
('dca0306f-10f4-4966-a65e-dd5be7ad1a08','憶泛西湖','鄭獬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四面青山紫繡圍，平湖萬頃碧羅衣。',64,'全唐诗/poet.song.33000.json','["四面青山紫繡圍，平湖萬頃碧羅衣。", "風摇酒面金鱗活，月弄波光玉篆飛。", "醉客半眠紅燭下，畫船行唱採蓮歸。", "十年衣袖遮塵土，惆悵飛雲滿翠微。"]'),
('fcf6d34b-485c-4768-a52e-839bebb1bc03','次韵石秀才淮上偶作','鄭獬','宋','宋诗','song-poetry','','[]','出汴忽如魚脫網，長淮萬里斷煩囂。',64,'全唐诗/poet.song.33000.json','["出汴忽如魚脫網，長淮萬里斷煩囂。", "白雲已抱日光轉，碧浪更和天面摇。", "自此乘槎須犯斗，誰能鞭石解爲橋。", "玉京醉客無消息，不及蓬山兩信潮。"]'),
('acfc25cd-3102-4e5d-a14e-708086b34d16','酬盧載','鄭獬','宋','宋诗','song-poetry','','[]','三百年來無作者，杜陵氣象久焦乾。',64,'全唐诗/poet.song.33000.json','["三百年來無作者，杜陵氣象久焦乾。", "縱吟一夜鬼神哭，開卷滿天星斗寒。", "渾脫無蹤宜造化，塵泥有意污波瀾。", "傷懷刻句無人會，寄與江南庾信看。"]'),
('ca256860-590e-49ea-89f2-c43af3cd84a3','舟次蕪湖却寄維揚刁學士','鄭獬','宋','宋诗','song-poetry','','[]','柳葉初黄未解飛，東風還與賞心違。',64,'全唐诗/poet.song.33000.json','["柳葉初黄未解飛，東風還與賞心違。", "縱逢春處花期少，自過江來酒病稀。", "平子解酬青玉案，秋娘能唱縷金衣。", "揚州二十四橋月，長憶醉乘明月歸。"]'),
('74a3c2e4-3738-4ea6-b367-6501fa4c8f48','夏夜淮上寄隨子直','鄭獬','宋','宋诗','song-poetry','','[]','天面玻璃滑欲流，淮光浮動浩難收。',64,'全唐诗/poet.song.33000.json','["天面玻璃滑欲流，淮光浮動浩難收。", "夜凉明月都如水，雨後清風却似秋。", "幾日重來還把酒，一回相憶却登樓。", "窮愁著得新書就，好寄雙魚碧海頭。"]'),
('fd696360-a7df-449d-92cc-6f144d68f17c','曹伯玉駕部相會於姑孰既別得書及詩因以拙句奉寄','鄭獬','宋','宋诗','song-poetry','','[]','東風綽約過前溪，碧草纖纖苦未齊。',64,'全唐诗/poet.song.33000.json','["東風綽約過前溪，碧草纖纖苦未齊。", "春到好花隨處有，醉來佳客不相携。", "高眠未博黄金印，秀句如鎸白玉圭。", "倒指驛程今甚處，畫船應過楚江西。"]'),
('6bee5255-7f3f-41dd-b3cb-b85d14331873','素風堂','鄭獬','宋','宋诗','song-poetry','','[]','潁水纖纖清露石，仙翁於此買煙村。',64,'全唐诗/poet.song.33000.json','["潁水纖纖清露石，仙翁於此買煙村。", "唐朝三百盛冠蓋，丞相幾家餘子孫。", "耀世文章雖已遠，傳家清白至今存。", "由來人物能相繼，又見芝蘭秀一番。"]'),
('55409830-eb2a-441e-9dc2-94153c1ddbe5','致政李祠部  其一','鄭獬','宋','宋诗','song-poetry','','[]','畫省仙翁綠鬢斑，林間高掛兩朱轓。',64,'全唐诗/poet.song.33000.json','["畫省仙翁綠鬢斑，林間高掛兩朱轓。", "更無歸計買泉石，欲以清名遺子孫。", "閒作好詩消白日，都將生事付清尊。", "嗟予憂病爲疏闊，不得携筇奉笑言。"]'),
('b832e754-90c2-4f3e-99ee-e0a42f5fa8c2','致政李祠部  其二','鄭獬','宋','宋诗','song-poetry','','[]','尊酒還成世外名，二千石印一毫輕。',64,'全唐诗/poet.song.33000.json','["尊酒還成世外名，二千石印一毫輕。", "驥雖老去壯心伏，鶴自病來仙骨清。", "林下已能忘歲月，人間何必仕公卿。", "淮揚塵土無佳賞，每見山翁眼乍明。"]'),
('dd35bda8-7eb4-4cd3-b164-6627644fb0e4','寄長沙燕守度','鄭獬','宋','宋诗','song-poetry','','[]','魏都南館相逢日，鬥向春風倒一尊。',64,'全唐诗/poet.song.33000.json','["魏都南館相逢日，鬥向春風倒一尊。", "連夜花開駐歸騎，即時席上插降旛。", "雲藏夢澤煙蒲老，秋卷湘江雪浪翻。", "聞道玉厨新釀熟，莫將餘瀝酹潺湲。"]'),
('a786eb35-233c-4716-98c9-5d744d6d1bc7','送潁川使君韓司門','鄭獬','宋','宋诗','song-poetry','','[]','喜君又佩魚符去，駟馬雍容朱兩轓。',64,'全唐诗/poet.song.33000.json','["喜君又佩魚符去，駟馬雍容朱兩轓。", "自昔諸侯潁陰國，太平宰相魏公孫。", "水邊日落旌旗暗，花外風高鼓角喧。", "到部行春應未晚，綠村正是杏梢繁。"]'),
('32a0e187-821a-4887-a188-f6da4b69810e','次韵程丞相牡丹','鄭獬','宋','宋诗','song-poetry','','[]','曾倒金壺爲牡丹，矮床設座繞花壇。',64,'全唐诗/poet.song.33000.json','["曾倒金壺爲牡丹，矮床設座繞花壇。", "有人偷插玉釵上，到夜更留銀燭看。", "醉裏春風遺翠帽，歸時寒月送琱鞍。", "如今蘭棹催西去，惆悵明年誰倚欄。"]'),
('f7f6a505-7d2d-41a0-a046-d635938e0489','寄關彥長','鄭獬','宋','宋诗','song-poetry','','[]','黄金斗印未垂腰，繞舍湖山弄翠濤。',64,'全唐诗/poet.song.33000.json','["黄金斗印未垂腰，繞舍湖山弄翠濤。", "饑鳳羽毛寒不鎩，卧龍頭角老方高。", "樽前襟抱生平盡，醉裏文章氣格豪。", "休論升沉向衰俗，功名到底屬吾曹。"]'),
('c47e90f3-ae8a-4365-b334-8ce5223d5855','次韵酬項城姚子張到縣感事','鄭獬','宋','宋诗','song-poetry','','[]','膠西童子近之官，坐按春秋討隠桓。',64,'全唐诗/poet.song.33000.json','["膠西童子近之官，坐按春秋討隠桓。", "休嘆折腰向彭澤，猶勝索米困長安。", "來篇喜見萬金字，厚報恨無雙玉盤。", "莫就白雲買煙艇，磻溪久已棄魚竿。"]'),
('ea85b85c-fb56-499e-949e-9552d49cfa9b','送郭元之東下','鄭獬','宋','宋诗','song-poetry','','[]','梢梢十幅健帆風，大醉長歌下浙東。',64,'全唐诗/poet.song.33000.json','["梢梢十幅健帆風，大醉長歌下浙東。", "甲乙未能求將相，詩書多是誤英雄。", "百年盡寄閒心外，萬事都拋冷笑中。", "白面書生少奇策，不知誰建太平功。"]'),
('4ea67124-9671-43ac-b01f-e2513320cb0b','送隋孝廉之官桐廬','鄭獬','宋','宋诗','song-poetry','','[]','萬乘君王曾降詔，敝裘瘦馬入咸秦。',64,'全唐诗/poet.song.33000.json','["萬乘君王曾降詔，敝裘瘦馬入咸秦。", "太平策略三千字，天下英豪二十人。", "自合乘時攀日月，如何隨衆走風塵。", "桐廬主簿官雖小，百里之間亦有民。"]'),
('40cb87da-d3b7-4019-9662-fd6a12f9787c','和張公達暮春寄宋使君','鄭獬','宋','宋诗','song-poetry','','[]','獨繞欄干正惜春，不堪西望隴頭雲。',64,'全唐诗/poet.song.33000.json','["獨繞欄干正惜春，不堪西望隴頭雲。", "弄煙細柳纔三尺，著地殘花厚一分。", "梁苑草深平似熨，秦關山煖翠如薰。", "騎鯨李白時過我，未引金尊先說君。"]'),
('863abfa4-5a7f-40f3-a7b3-e7fd2ad5b2ec','再和','鄭獬','宋','宋诗','song-poetry','','[]','使君携酒送餘春，縹緲高懷倚白雲。',64,'全唐诗/poet.song.33000.json','["使君携酒送餘春，縹緲高懷倚白雲。", "新曲旋教花下按，好題只就席間分。", "阮公醉帽玉山倒，謝女舞衣沈水薰。", "自笑塵埃滿朱紱，良辰樂事兩輸君。"]'),
('f99c72f8-9738-4b39-9f9d-0a1a99f33fde','寄題沖雅虛心亭','鄭獬','宋','宋诗','song-poetry','','[]','高僧酷愛翠雲枝，雨後新陰翠入衣。',64,'全唐诗/poet.song.33000.json','["高僧酷愛翠雲枝，雨後新陰翠入衣。", "爲恨煙溪生處遠，自尋雲徑劚將歸。", "有時風雨鬥不解，只恐蛟龍活欲飛。", "好向繁梢結秋實，丹山正是鳳凰饑。"]'),
('eab7d5aa-e259-407f-bb45-9b3eb5eed26e','張寺丞見訝久不致書兼惠佳篇輒用奉答','鄭獬','宋','宋诗','song-poetry','','[]','數日看花生怕遲，杭州更有亂花圍。',64,'全唐诗/poet.song.33000.json','["數日看花生怕遲，杭州更有亂花圍。", "爲貪携酒尋春去，不及修書趁雁歸。", "且擊壯懷期篆鼎，莫緣華髮便沾衣。", "誰知寂寞寒山外，萬里蒼鷹正苦饑。"]'),
('80309ca9-8d9a-4a27-bf6a-65ccb013df42','奉詔赴瓊林苑燕餞太尉潞國文公出鎮西都','鄭獬','宋','宋诗','song-poetry','','[]','都門秋色滿旌旗，祖帳容陪醉御卮。',64,'全唐诗/poet.song.33000.json','["都門秋色滿旌旗，祖帳容陪醉御卮。", "功業迥高嘉祐末，精神如破貝州時。", "匣中寶劍騰霜鍔，海上仙桃壓露枝。", "昨日更聞褒詔下，別看名姓入烝彝。"]'),
('306ac3b0-915f-4a18-8a41-3b34f53f6cba','送程公闢給事出守會稽兼集賢殿修撰','鄭獬','宋','宋诗','song-poetry','','[]','越州太守何瀟灑，應爲能吟住集仙。',64,'全唐诗/poet.song.33000.json','["越州太守何瀟灑，應爲能吟住集仙。", "雪急紫濛催玉勒，日長青瑣聽薰絃。", "一時冠蓋傾離席，半醉珠璣落彩箋。", "自恨君恩渾未報，五湖終負釣魚船。"]'),
('78f86933-665d-451e-ac4f-157a338adb3b','寄程公闢','鄭獬','宋','宋诗','song-poetry','','[]','念昔都門手一携，春禽幾向苧蘿啼。',64,'全唐诗/poet.song.33000.json','["念昔都門手一携，春禽幾向苧蘿啼。", "夢回金殿風光別，吟到銀河月影低。", "舞急錦腰迎十八，酒酣金盞照東西。", "何時得遂扁舟去，雪棹同君泛剡溪。"]'),
('1a1c7b1b-e767-4203-b96a-f38dff3a6894','送公闢給事自青州致政歸吳中','鄭獬','宋','宋诗','song-poetry','','[]','青瑣仙人解玉符，秋風一夜滿江湖。',64,'全唐诗/poet.song.33000.json','["青瑣仙人解玉符，秋風一夜滿江湖。", "曾歌郢水非凡曲，未掃旄頭負壯圖。", "終日望君天欲盡，平生知我世應無。", "扁舟應約元宮保，瀟灑蓮涇二丈夫。"]'),
('27f5d491-dc11-471c-a36b-14d52bc5e6b9','鄖陽道中','鄭獬','宋','宋诗','song-poetry','','[]','白馬春風綠草長，行人踏破碧溪光。',64,'全唐诗/poet.song.33000.json','["白馬春風綠草長，行人踏破碧溪光。", "隔山啼鳥自相應，臨水幽花應更香。", "壠上驚飛青尾雉，桑間閒立蒨裙娘。", "白頭關吏還相問，不信相如是故鄉。"]'),
('a0087e76-4160-442d-91a8-ada25a48ada3','送石中允致仕歸新昌','鄭獬','宋','宋诗','song-poetry','','[]','鳳凰山下網羅疏，翠翮摇空去有餘。',64,'全唐诗/poet.song.33000.json','["鳳凰山下網羅疏，翠翮摇空去有餘。", "陶令已拋彭澤印，謝敷今作會稽居。", "碧峰四向晚吟處，啼鳥數聲春醉初。", "更放魚舠鑑湖上，芙蓉香裏卧看書。"]'),
('46cac846-e0c3-444a-87b2-0a65903bbaca','吳比部致仕歸蘄陽','鄭獬','宋','宋诗','song-poetry','','[]','蘧公四十已知非，長揖公卿卧翠微。',64,'全唐诗/poet.song.33000.json','["蘧公四十已知非，長揖公卿卧翠微。", "結綬才還雙闕下，上書便乞故鄉歸。", "伏轅赤驥相隨老，出網冥鴻自在飛。", "應向黄梅訪逋客，白雲飄灑紫荷衣。"]'),
('3f6284b2-bd1c-48d6-bf33-df2066d9c2d4','送宋屯田之湖南轉運判官','鄭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','綠綬郎官笑白頭，更携龍節領諸侯。',64,'全唐诗/poet.song.33000.json','["綠綬郎官笑白頭，更携龍節領諸侯。", "摶風初擊三千水，投刃方排十二牛。", "行色未拋京洛地，先聲已壓洞庭秋。", "漢家刺部官雖小，一鑑寒冰照八州。"]'),
('c70423af-7986-4b80-a53e-951e5d3a8a7c','送陳睦赴河中幕','鄭獬','宋','宋诗','song-poetry','','[]','紫皇初放第三榜，中有英豪絕世無。',64,'全唐诗/poet.song.33000.json','["紫皇初放第三榜，中有英豪絕世無。", "天廄本生騏驥子，雲霄又得鳳凰雛。", "不須虎鬥終全趙，自是龍驤首破吳。", "雖作蓮花帳前客，丹臺到了姓名殊。"]'),
('97c928f4-47b1-43dc-85b9-7d354cbf33c0','南歸呈王樂道','鄭獬','宋','宋诗','song-poetry','','[]','漸少塵沙眼漸開，駸駸歸騎不須催。',64,'全唐诗/poet.song.33000.json','["漸少塵沙眼漸開，駸駸歸騎不須催。", "春風自過燕山好，寒色還從易水回。", "歸雁却飛天北去，白雲應傍日邊來。", "行行上苑花如綴，共獻君王萬壽杯。"]'),
('905d732e-5f40-4d6b-a764-eee948b3ba82','聞南陽呂諫議長逝','鄭獬','宋','宋诗','song-poetry','','[]','子文三仕去何頻，一卧南陽竟沒身。',64,'全唐诗/poet.song.33000.json','["子文三仕去何頻，一卧南陽竟沒身。", "明主自應容直道，皇天何事殺忠臣。", "拄天力屈空留草，貫日心存不化塵。", "黄壤不知人世事，爲君慟哭楚江濱。"]'),
('736a4d04-d49d-4023-9d94-cb1ee75393c7','哀蘇明允','鄭獬','宋','宋诗','song-poetry','','[]','豐城寶劍忽飛去，玉匣靈蹤自此無。',64,'全唐诗/poet.song.33000.json','["豐城寶劍忽飛去，玉匣靈蹤自此無。", "天外已空丹鳳穴，世間還得二龍駒。", "百年飄忽古無奈，萬事凋零今已殊。", "惆悵西州文學老，一丘空掩蜀山隅。"]'),
('aaafc17f-eb61-4108-895e-c228cf7a5f89','傷賈老','鄭獬','宋','宋诗','song-poetry','','[]','世事一毫不掛眼，放懷只用酒爲年。',64,'全唐诗/poet.song.33000.json','["世事一毫不掛眼，放懷只用酒爲年。", "已從車後携一榼，更向杖頭留百錢。", "顧我曾傳丹鼎訣，疑君便是紫芝仙。", "忽如蟬蛻不復見，雨壞茅齋八九椽。"]'),
('b0576306-924f-4336-9c2c-c87f7752feee','樊秀才下第','鄭獬','宋','宋诗','song-poetry','','[]','平時愛子多集句，此日金刀得翦裁。',64,'全唐诗/poet.song.33000.json','["平時愛子多集句，此日金刀得翦裁。", "自謂羅中先得雋，豈知天外已遺才。", "爐開遂失黄金礦，石劃猶藏白玉杯。", "獨倚西風倍惆悵，却憂車馬到門來。"]'),
('fe83a921-96f1-4295-a54f-360444e5a507','張李二君獲薦喜而成篇兼簡岑令蔣掾','鄭獬','宋','宋诗','song-poetry','','[]','榜帖初傳見姓名，喜來把讀繞欄行。',64,'全唐诗/poet.song.33000.json','["榜帖初傳見姓名，喜來把讀繞欄行。", "長風又送二龍去，明月已看雙桂生。", "群玉聚來俱是寶，真金鍊出始爲精。", "雖知自是文章得，須待秦臺寶鑑明。"]'),
('d0cac054-4fcc-4cd5-8286-18a5f2a93a2c','勉學者','鄭獬','宋','宋诗','song-poetry','','[]','繞座群書如累玉，夜燈忘睡晝忘饑。',64,'全唐诗/poet.song.33000.json','["繞座群書如累玉，夜燈忘睡晝忘饑。", "文章須用聖賢斷，議論要通今古疑。", "孟子豈無仁義國，荀卿猶作帝王師。", "太平歧路安於掌，好跨大宛萬里馳。"]'),
('051ae92f-9f09-4b55-9854-a1725da3faa0','自貽','鄭獬','宋','宋诗','song-poetry','','[]','烏巾筇杖白雲夫，寄謝黄公舊酒壚。',64,'全唐诗/poet.song.33000.json','["烏巾筇杖白雲夫，寄謝黄公舊酒壚。", "懶性惟看高士傳，歸心空展舊山圖。", "病來瘦骨支離在，老去歡情積漸無。", "啼鳥落花應怪問，綠塵何事滿金壺。"]'),
('60a1452b-a770-4b2e-95e3-838edbec24aa','衰疾','鄭獬','宋','宋诗','song-poetry','','[]','大夢爲生固有涯，屢攻衰疾可驚嗟。',64,'全唐诗/poet.song.33000.json','["大夢爲生固有涯，屢攻衰疾可驚嗟。", "時於耳竅嘯秋蚓，併向目睛飛黑花。", "門外挂羅同翟尉，座隅占鵩類長沙。", "支離猶食三鍾粟，買取溳溪好住家。"]'),
('bf619e12-949b-42e1-bdbd-f5ce1aeab334','山中桃花','鄭獬','宋','宋诗','song-poetry','','[]','春入關山亦未遲，苧蘿山下見西施。',64,'全唐诗/poet.song.33000.json','["春入關山亦未遲，苧蘿山下見西施。", "不羞白髮欺雙鬢，且對清尊插一枝。", "縱落不隨流水去，僅開惟有白雲知。", "何須惆悵無人賞，自有春風二月時。"]'),
('afac15d2-739a-4ba2-983c-d6844b15e4cd','同賈運使章職方王推官賞梅','鄭獬','宋','宋诗','song-poetry','','[]','花前留客解金鞍，揀遍繁梢盡折殘。',64,'全唐诗/poet.song.33000.json','["花前留客解金鞍，揀遍繁梢盡折殘。", "翠帽插來無處著，玉盤收取與人看。", "無言有意空相對，欲去重來更繞欄。", "把酒殷勤須會取，風頭只待作春寒。"]'),
('11bd06b8-0ecc-4232-b0fb-58d53f0cb2ad','雪中梅','鄭獬','宋','宋诗','song-poetry','','[]','臘雪欺梅飄玉塵，早梅鬥巧雪中春。',64,'全唐诗/poet.song.33000.json','["臘雪欺梅飄玉塵，早梅鬥巧雪中春。", "更無俗艷能相雜，惟有清香可辨真。", "姑射仙人冰作體，秦家公主粉爲身。", "素娥已自稱佳麗，更作廣寒宮裏人。"]'),
('c4f81a67-96c9-41e7-86b6-e00bd228bb5b','菊','鄭獬','宋','宋诗','song-poetry','','[]','寶釘萬數擁寒枝，寂寞幽香蝶亦稀。',64,'全唐诗/poet.song.33000.json','["寶釘萬數擁寒枝，寂寞幽香蝶亦稀。", "未把玉欄移得去，直須翠帽插將歸。", "定逢野客尋常折，忍逐秋風取次飛。", "好備一尊相就飲，醉來從遣露霑衣。"]'),
('baf046de-5e94-4f5e-8ea1-e573ea740a17','齊山晚歸','鄭獬','宋','宋诗','song-poetry','','[]','飲散齊山晚，夕陽秋浦紅。',24,'全唐诗/poet.song.33000.json','["飲散齊山晚，夕陽秋浦紅。", "不須鞭五馬，十里聽松風。"]'),
('1b7abfc5-96ba-4279-b930-ea0c1c13903d','出都次南頓','鄭獬','宋','宋诗','song-poetry','','[]','駐馬綠陰下，離人正憶家。',24,'全唐诗/poet.song.33000.json','["駐馬綠陰下，離人正憶家。", "可憐桃李樹，猶有未開花。"]'),
('e4be2c4d-201a-4105-8638-7a9aba1163be','酴醿','鄭獬','宋','宋诗','song-poetry','','[]','清香無物敵，粉葉自成圍。',24,'全唐诗/poet.song.33000.json','["清香無物敵，粉葉自成圍。", "白玉瓏璁髻，珍珠纓絡衣。"]'),
('49652185-ac8e-4f03-b925-197dd56e526a','題僧文瑩所居壁','鄭獬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖頻送客，綠波舟檝輕。',24,'全唐诗/poet.song.33000.json','["西湖頻送客，綠波舟檝輕。", "春入蘿徑靜，浪花翻遠晴。"]'),
('e04daaf0-1ca9-4c0e-b00d-ae533554d8be','咏史','鄭獬','宋','宋诗','song-poetry','','[]','漢地龍蛇始遘迍，曹公崛起定經綸。',96,'全唐诗/poet.song.33000.json','["漢地龍蛇始遘迍，曹公崛起定經綸。", "陰謀用盡得天下，誰道彼雛解笑人。", "魏生被責灌將軍，股慄如何不自陳。", "若使當時有英氣，肯爲丞相掃門人。", "漢家行賞盡論功，禍福於人豈易窮。", "解把舊恩酬項伯，獨將大義斬丁公。"]'),
('84c83db6-5160-46f0-80ea-ced0d2ac99f3','讀蜀志','鄭獬','宋','宋诗','song-poetry','','[]','曹公屈指當時輩，天下英雄數使君。',32,'全唐诗/poet.song.33000.json','["曹公屈指當時輩，天下英雄數使君。", "髀肉消來還感泣，爭教漢鼎不三分。"]'),
('f0997d54-a980-416e-8c4c-457aa716bbc3','莊鵾辭海','鄭獬','宋','宋诗','song-poetry','','[]','歸路漸驚紅葉老，舊山已落白雲深。',32,'全唐诗/poet.song.33000.json','["歸路漸驚紅葉老，舊山已落白雲深。", "莊鵾聊欲辭滄海，越鳥終須憶故林。"]'),
('66e4ce23-f42b-4f2a-a5fa-d337db86c3f8','下第遊金明池','鄭獬','宋','宋诗','song-poetry','','[]','騎殺青都白玉麟，歸來狂醉後池春。',32,'全唐诗/poet.song.33000.json','["騎殺青都白玉麟，歸來狂醉後池春。", "人間得喪尋常事，不避郎君走馬塵。"]'),
('bb65ec75-c5b6-42d6-ad18-23f32ff8db53','久泊餘杭關外水涸不能行晚雨甚快解舟有日矣','鄭獬','宋','宋诗','song-poetry','','[]','初看紅芰小開頭，今見青房結子稠。',32,'全唐诗/poet.song.33000.json','["初看紅芰小開頭，今見青房結子稠。", "深謝晚雲憐滯客，故飛凉雨送歸舟。"]'),
('cf840a98-905a-42bf-8c49-8493acd4bdfa','畫屏','鄭獬','宋','宋诗','song-poetry','','[]','翠篠疏明臨晚水，紫葵點綴落晴沙。',32,'全唐诗/poet.song.33000.json','["翠篠疏明臨晚水，紫葵點綴落晴沙。", "山鷄對卧綠蒲葉，野鴨爭銜黄荇花。"]'),
('46b47d92-d7c6-4f45-a574-759e3bf82411','夷陵張仲孚以荆州無山爲戲輒書二絕  其一','鄭獬','宋','宋诗','song-poetry','','[]','使君終日倚朱欄，綠樹高樓掩映間。',32,'全唐诗/poet.song.33000.json','["使君終日倚朱欄，綠樹高樓掩映間。", "自有碧江無限好，荆州佳境不須山。"]'),
('1ee5b3b5-85db-4759-acaf-49ed27f14ec6','夷陵張仲孚以荆州無山爲戲輒書二絕  其二','鄭獬','宋','宋诗','song-poetry','','[]','雨後飛雲冉冉回，碧天都似鏡初開。',32,'全唐诗/poet.song.33000.json','["雨後飛雲冉冉回，碧天都似鏡初開。", "只應峽口多山處，不見秋光萬里來。"]'),
('d6fa339a-ad9c-48a4-a279-a396d0f94a30','再賦如山','鄭獬','宋','宋诗','song-poetry','','[]','小堂草草屋三間，暇日徜徉養壽閒。',32,'全唐诗/poet.song.33000.json','["小堂草草屋三間，暇日徜徉養壽閒。", "揭榜如山還自笑，何人不老似青山。"]'),
('a475f481-a2f7-4985-9db3-db93572e5b67','客意','鄭獬','宋','宋诗','song-poetry','','[]','已換春衫別後衣，此心長共白雲飛。',32,'全唐诗/poet.song.33000.json','["已換春衫別後衣，此心長共白雲飛。", "高堂壽酒年年事，趁取榴花及早歸。"]'),
('84e5a7a0-bf9f-46e9-9843-926b5807c3f9','讀司馬君實撰呂獻可墓誌','鄭獬','宋','宋诗','song-poetry','','[]','一讀斯文淚瀉襟，摩天直氣萬千尋。',32,'全唐诗/poet.song.33000.json','["一讀斯文淚瀉襟，摩天直氣萬千尋。", "知君不獨悲忠義，又有兼憂天下心。"]'),
('7d168025-2690-476c-be6a-8972b349d1a7','讀李英公傳','鄭獬','宋','宋诗','song-poetry','','[]','李密被誅猶不負，文皇顧命更何疑。',32,'全唐诗/poet.song.33000.json','["李密被誅猶不負，文皇顧命更何疑。", "豈將當日奔亡後，比得他年富貴時。"]'),
('53580b71-ce74-4ec9-86ee-455cbf742e3d','曉凉','鄭獬','宋','宋诗','song-poetry','','[]','銀河垂角斗星稀，曉簟微凉夢破遲。',32,'全唐诗/poet.song.33000.json','["銀河垂角斗星稀，曉簟微凉夢破遲。", "落月半庭人未起，好風摇動碧桐枝。"]'),
('7527de0b-abf9-4e8a-8db7-f1539bd0393c','三月','鄭獬','宋','宋诗','song-poetry','','[]','三月江南梅子青，春遊已過畫船橫。',32,'全唐诗/poet.song.33000.json','["三月江南梅子青，春遊已過畫船橫。", "酒懷索寞人初倦，已喜金杯弄水聲。"]'),
