('d4380cb1-7c3d-458d-a61c-85283d96f613','頃年嘗與董伯孫數子獵兔抵馬欄今日重來解鞍佛舍見高儀之題云躍馬飛鶻至此追念疇昔因紀一絕兼呈儀之','鄭獬','宋','宋诗','song-poetry','','[]','昔年嘗臂海東鶻，醉客高飛鐵馬群。',32,'全唐诗/poet.song.33000.json','["昔年嘗臂海東鶻，醉客高飛鐵馬群。", "今日見君題壁處，自憐曾是舊將軍。"]'),
('34315a56-592d-4bdd-aef6-e83f29c96e9b','浚溝廟蜥蜴','鄭獬','宋','宋诗','song-poetry','','[]','不歸大海不藏山，碧瓦朱欄綠樹閑。',32,'全唐诗/poet.song.33000.json','["不歸大海不藏山，碧瓦朱欄綠樹閑。", "應待老龍纔睡著，便偷雲雨落人間。"]'),
('42c2e757-9ef4-4f5a-aba4-4a30ce8bec8c','雨雪雜下  其一','鄭獬','宋','宋诗','song-poetry','','[]','雨鬥雪聲相雜下，飄蕭密勢灑空來。',32,'全唐诗/poet.song.33000.json','["雨鬥雪聲相雜下，飄蕭密勢灑空來。", "北風有意待寒臘，只放飛花一半開。"]'),
('b1b4ede3-6acf-4d96-a382-26900f150ed8','雨雪雜下  其二','鄭獬','宋','宋诗','song-poetry','','[]','楚江雲暖凍未得，雪粒飄來著地稀。',32,'全唐诗/poet.song.33000.json','["楚江雲暖凍未得，雪粒飄來著地稀。", "恰似小園寒食後，梨花零亂雨中飛。"]'),
('d059d8ae-45f0-4527-bef7-d912f6ca3482','祈雨','鄭獬','宋','宋诗','song-poetry','','[]','平地三尺雨，農家三尺金。',24,'全唐诗/poet.song.33000.json','["平地三尺雨，農家三尺金。", "我願此雨力，生穗長如林。"]'),
('f0937bf9-931d-41f9-aa40-dd6e7abf663f','春','鄭獬','宋','宋诗','song-poetry','','[]','雪後清風特地斜，柳條疏瘦未藏鴉。',32,'全唐诗/poet.song.33000.json','["雪後清風特地斜，柳條疏瘦未藏鴉。", "與君試去探春信，看到梅梢第幾花。"]'),
('da18fbd9-e42d-4d73-94d8-d54356a1f912','夏','鄭獬','宋','宋诗','song-poetry','','[]','避暑恨無雙羽翰，銀河亦恐浪花乾。',64,'全唐诗/poet.song.33000.json','["避暑恨無雙羽翰，銀河亦恐浪花乾。", "坐來已倦還臨水，卧去無眠復倚欄。", "擬截白雲鋪玉簟，好收明月貯金盤。", "如何一見張公子，清論如冰灑座寒。"]'),
('76709abb-7635-47cb-b286-698cba194bf0','行旅','鄭獬','宋','宋诗','song-poetry','','[]','捲衣上馬去駸駸，檐雨飄零楚客心。',64,'全唐诗/poet.song.33000.json','["捲衣上馬去駸駸，檐雨飄零楚客心。", "歸路漸驚紅葉老，舊山已落白雲深。", "莊鵬聊欲辭滄海，越鳥終須憶故林。", "初啟松阡青未合，嶺頭一望一沾襟。"]'),
('8cf67921-4ffa-405c-bfd4-a5c9cb144d40','紫花硯','鄭獬','宋','宋诗','song-poetry','','[]','耕得紫玻璃，鑿成天馬蹄。',24,'全唐诗/poet.song.33000.json','["耕得紫玻璃，鑿成天馬蹄。", "潤應通月窟，洗合就雲溪。"]'),
('839a053e-4730-4a9b-9e1d-e5e4af196936','新春詞  其一','鄭獬','宋','宋诗','song-poetry','','[]','春色應隨步輦還，珠旒玉几照龍顔。',32,'全唐诗/poet.song.33000.json','["春色應隨步輦還，珠旒玉几照龍顔。", "紫雲殿下朝元罷，便領東風到世間。"]'),
('c015e8cc-91d6-4f39-ac8c-7a7fedb93663','新春詞  其二','鄭獬','宋','宋诗','song-poetry','','[]','春風細拂綠波長，初過層城渡建章。',32,'全唐诗/poet.song.33000.json','["春風細拂綠波長，初過層城渡建章。", "草色未迎雕輦翠，柳梢先學赭衣黄。"]'),
('a719f7be-bbdc-4632-9232-dba1c3e36579','新春詞  其三','鄭獬','宋','宋诗','song-poetry','','[]','晴暉散入鳳凰樓，一桁朱簾不下鈎。',32,'全唐诗/poet.song.33000.json','["晴暉散入鳳凰樓，一桁朱簾不下鈎。", "漢殿鬥簪雙彩燕，并和春色上釵頭。"]'),
('bb4f3cce-9233-4e57-958b-173a5a1cb9ab','新春詞  其四','鄭獬','宋','宋诗','song-poetry','','[]','小池春破玉玲瓏，聲觸簾鈎漸好風。',32,'全唐诗/poet.song.33000.json','["小池春破玉玲瓏，聲觸簾鈎漸好風。", "閒繞欄干掐花樹，春痕已著半梢紅。"]'),
('6770aaf9-4007-48f0-8f6d-e243c245de06','松滋褚都督義門','鄭獬','宋','宋诗','song-poetry','','[]','貞觀得奇士，子孫宅荆土。',24,'全唐诗/poet.song.33000.json','["貞觀得奇士，子孫宅荆土。", "一家五百口，六世同所處。"]'),
('71d9a0a8-8a26-4c21-bca8-e284cc9afdc4','浮雲樓','鄭獬','宋','宋诗','song-poetry','','[]','樓在浮雲縹緲間，浮雲破處見朱欄。',32,'全唐诗/poet.song.33000.json','["樓在浮雲縹緲間，浮雲破處見朱欄。", "山光對入鄖城紫，溪影橫飛夢澤寒。"]'),
('c53ed912-07a4-48f1-a52c-9dcfd781e858','梅花','鄭獬','宋','宋诗','song-poetry','','[]','梅愛山傍水際栽，非因弱柳近章臺。',32,'全唐诗/poet.song.33000.json','["梅愛山傍水際栽，非因弱柳近章臺。", "重重葉葉花依舊，歲歲年年客又來。"]'),
('9960c5cd-4ace-4d47-82bb-6d50277686ac','謝賜飛白書','鄭獬','宋','宋诗','song-poetry','','[]','伏馹馳天闕，飛文下玉除。',72,'全唐诗/poet.song.33000.json','["伏馹馳天闕，飛文下玉除。", "奎成蒼頡字，龍受伏羲書。", "功業升平外，文章妙絕初。", "形聲秦隸拙，點畫蔡邕疏。", "軸動星辰轉，筆停風雨餘。", "珍藏傳萬世，安敢比瓊琚。"]'),
('81574bd4-02e4-423b-8249-3247bd34eacb','伏謁太神御殿詩','鄭獬','宋','宋诗','song-poetry','','[]','景煙滿殿曉香清，日角龍顔五色明。',64,'全唐诗/poet.song.33000.json','["景煙滿殿曉香清，日角龍顔五色明。", "五季積成天下亂，千年方有聖人生。", "重開混沌立萬象，獨斬蚩尤銷五兵。", "願作周公清廟頌，神孫世世告升平。"]'),
('9eda4133-b3dc-45fa-852b-f79c79c4057d','閔雨','鄭獬','宋','宋诗','song-poetry','','[]','潭底乖龍喚不譍，驕陽似欲敗西成。',32,'全唐诗/poet.song.33000.json','["潭底乖龍喚不譍，驕陽似欲敗西成。", "虛堂永夜耿無寐，起聽四郊車水聲。"]'),
('93906e7e-1fc7-4595-89b5-78532e844d6c','錢塘觀燈','鄭獬','宋','宋诗','song-poetry','','[]','碧海芙蓉徹夜開，亂花前後盡樓臺。',64,'全唐诗/poet.song.33000.json','["碧海芙蓉徹夜開，亂花前後盡樓臺。", "坐看萬里河漢外，移下一天星斗來。", "醉客倚欄吹玉笛，美人弄鏡插香梅。", "誰能飛入月宮去，捉住嫦娥不放回。"]'),
('28773015-2b9b-4e8c-a105-97b4fd4843a5','偶題','鄭獬','宋','宋诗','song-poetry','','[]','寸心不著一塵飛，坐見孤雲冉冉歸。',32,'全唐诗/poet.song.33000.json','["寸心不著一塵飛，坐見孤雲冉冉歸。", "萬境去來無不可，白鷗爭得見忘機。"]'),
('6a8abd1f-f4de-4db0-945f-4c4494d53d91','寄并州故人  其一','鄭獬','宋','宋诗','song-poetry','','[]','年來羈客減歡遊，少對清樽浣別愁。',32,'全唐诗/poet.song.33000.json','["年來羈客減歡遊，少對清樽浣別愁。", "社裏故人相憶否，夜來歸夢到并州。"]'),
('0e332d82-c087-4d64-bf91-07782fb79d07','寄并州故人  其二','鄭獬','宋','宋诗','song-poetry','','[]','去年寒食柳溪頭，著意尋花醉未休。',32,'全唐诗/poet.song.33000.json','["去年寒食柳溪頭，著意尋花醉未休。", "今日天涯最惆悵，滿江煙雨吊春愁。"]'),
('076f0d86-d0bb-49e2-a260-cc1eefb262c0','送吳中復鎮長沙','鄭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','初登西漢文章府，便領吳王第一州。',32,'全唐诗/poet.song.33000.json','["初登西漢文章府，便領吳王第一州。", "繞郭白雲衡嶽近，滿帆明月洞庭秋。"]'),
('be6c4047-ac9c-4bb6-9fbe-a9e44dd4bba4','城東','鄭獬','宋','宋诗','song-poetry','','[]','草濕煙村暴雨晴，踏沙閑信馬蹄行。',64,'全唐诗/poet.song.33000.json','["草濕煙村暴雨晴，踏沙閑信馬蹄行。", "客心到處不稱意，春色向人如有情。", "野外一雙新燕去，叢間三數小花明。", "松溪漁老應相笑，十載塵埃競姓名。"]'),
('f9d4fe02-1105-494f-87b2-042eca4ef29a','烏龍老栽松既以詩三首  其一','鄭獬','宋','宋诗','song-poetry','','[]','高標不畏雪霜侵，枉斸孤根出舊林。',32,'全唐诗/poet.song.33000.json','["高標不畏雪霜侵，枉斸孤根出舊林。", "但恐長安無地種，人家桃李自成陰。"]'),
('8a145b0a-9a7d-4709-a876-a47479048ad0','烏龍老栽松既以詩三首  其二','鄭獬','宋','宋诗','song-poetry','','[]','北山山下翠重重，禪老栽成夾道松。',32,'全唐诗/poet.song.33000.json','["北山山下翠重重，禪老栽成夾道松。", "蛇子蛇孫長鱗鬣，烏龍幻出萬蒼龍。"]'),
('cf6340e8-77c3-4308-a26e-8d7d1eb125f2','烏龍老栽松既以詩三首  其三','鄭獬','宋','宋诗','song-poetry','','[]','栽松初不爲茯苓，自要禪關門徑深。',32,'全唐诗/poet.song.33000.json','["栽松初不爲茯苓，自要禪關門徑深。", "禪老一朝飛錫去，不妨留下海潮音。"]'),
('26e535a4-4754-4632-b94d-3913a64cb119','詩一首','鄭獬','宋','宋诗','song-poetry','','[]','高論唐虞儒者事，賣交負國豈勝言。',32,'全唐诗/poet.song.33000.json','["高論唐虞儒者事，賣交負國豈勝言。", "憑君莫笑金槌陋，却是屠酤解報恩。"]'),
('977f2d79-dd9f-4241-b15e-ab0cdae36465','句  其一','鄭獬','宋','宋诗','song-poetry','','[]','未識春風面，先聞樂府名。',24,'全唐诗/poet.song.33000.json','["未識春風面，先聞樂府名。", "洗粧濃出塞，進艇客登瀛。"]'),
('de661c18-264a-4cdb-bf68-bb8c66240090','句  其二','鄭獬','宋','宋诗','song-poetry','','[]','好擁雙旌便東下，畫船明月綠楊津。',16,'全唐诗/poet.song.33000.json','["好擁雙旌便東下，畫船明月綠楊津。"]'),
('c847ef88-1833-4969-831e-93b6ca62d215','句  其三','鄭獬','宋','宋诗','song-poetry','','[]','東飛江雲北飛燕，同寄青春不相見。',16,'全唐诗/poet.song.33000.json','["東飛江雲北飛燕，同寄青春不相見。"]'),
('c1851c83-0fd7-4911-9086-82c1ddd8fb80','句  其四','鄭獬','宋','宋诗','song-poetry','','[]','朝來已與碧桃約，留住東風不放歸。',16,'全唐诗/poet.song.33000.json','["朝來已與碧桃約，留住東風不放歸。"]'),
('b9a4968d-8f1c-41dc-bb04-40210b42be95','句  其五','鄭獬','宋','宋诗','song-poetry','','[]','長亭搔首晚悠悠。',8,'全唐诗/poet.song.33000.json','["長亭搔首晚悠悠。"]'),
('e91a0eb9-ac42-4eea-bacc-3ec0ac59d469','次劉才邵送魏彥成韵','强至','宋','宋诗','song-poetry','','[]','國朝廣仁恩，法令去煩苛。',156,'全唐诗/poet.song.33000.json','["國朝廣仁恩，法令去煩苛。", "三官貴持平，除用不輕可。", "矯矯魏詳刑，儒術富而夥。", "餘事及刑書，議論不偏頗。", "能令舞文吏，無計得掀簸。", "計其所平反，陰功已堆垛。", "神方介以福，豐穫報勤播。", "當即趨要塗，鳴玉清以儺。", "誰云出處間，此事難預揣。", "秋風鄉思動，請郡向江左。", "猶冀款襟顔，已聞將轉舵。", "想見桐州民，延首候來舸。", "置酒樂佳辰，剩插黄花朵。"]'),
('c9aeaf1c-ea11-47c1-bb19-aaf25a9660bd','依韵答吳殿丞應之見寄','强至','宋','宋诗','song-poetry','','[]','古人不可見，空名留竹素。',120,'全唐诗/poet.song.33000.json','["古人不可見，空名留竹素。", "幸而並世生，千里或相去。", "懷賢我何勞，蓄道公其富。", "老驥伏櫪鳴，使看駑駘步。", "浩歌掉簪紱，思極江山趣。", "西風動遊袂，撇在千巖路。", "賤子匹馬來，邂逅一相晤。", "既見豁所懷，私心願執御。", "論議攻不破，牢若金城固。", "作詩遺長髯，知異衆人遇。"]'),
('a31bfdb7-6f1a-4328-9fbd-880aef1ba428','向負春遊辭以風雨開霽既久樂事未果因書百言聊以自戲','强至','宋','宋诗','song-poetry','','[]','常恨春日少，况遭風雨多。',120,'全唐诗/poet.song.33000.json','["常恨春日少，况遭風雨多。", "桃李冷不覺，□□如濁河。", "廣陌斷游騎，寂不聞行歌。", "方其正雨時，樂事空蹉跎。", "晴來又累朝，日暖風祥和。", "紅入桃李枝，綠轉池塘波。", "何曾到花下，把酒呼青蛾。", "屈指九十期，今已一半過。", "繫日乏長繩，欲却無神戈。", "花落解笑人，謂我前言何。"]'),
('1e2b7f22-9f12-4cde-8cc9-b39963b01011','道旁松','强至','宋','宋诗','song-poetry','','[]','何年澗底栽，移植俯官道。',48,'全唐诗/poet.song.33000.json','["何年澗底栽，移植俯官道。", "腹空蟻穴衆，枝瘦龍脊裊。", "斧斤須良材，霜雪豈終老。", "大有歲寒操，見盡桃李夭。"]'),
('466fa98c-8de1-4b44-bc4d-8524bbb0a41e','雷君自陝及門謁與書偕聊成短篇以答來貺','强至','宋','宋诗','song-poetry','','[]','一官偶來泗，舉動畏謗嘲。',120,'全唐诗/poet.song.33000.json','["一官偶來泗，舉動畏謗嘲。", "萬事不掛齒，終日口欲膠。", "所學未信時，尤欲密歛包。", "賢者或我顧，未免談屢交。", "雷侯將家子，而至自陝郊。", "踵門貺予書，享饋煩弦匏。", "始見氣頗勁，既語理不殽。", "愛子欲子薦，言畢徒啁啁。", "托蔭須高林，而乃依寸茅。", "盍行游鉅公，一言變魚蛟。"]'),
('3a08aaaa-dd81-4c1d-9719-ee43279b92f2','聞杭饑','强至','宋','宋诗','song-poetry','','[]','客從吾鄉來，告我歲大歉。',216,'全唐诗/poet.song.33000.json','["客從吾鄉來，告我歲大歉。", "百金易斗粟，富者頭屢撼。", "餓殍相枕藉，億口盡虛頷。", "客言尚未竟，予淚已成點。", "避席駭相問，予衷不能掩。", "位卑俸給薄，用度抑難減。", "是以之官日，盡室來未敢。", "予行弟獨留，居常動予慊。", "歲凶吾産薄，慮其苦粗淡。", "所以聞客言，私懷輒興感。", "客遽前止予，君言固足貶。", "善自憂家爲，微俸誠亦忝。", "上有天子明，封章日可剡。", "先陳劭耕稼，次述抑聚斂。", "澄汰兵籍冗，惇尚土木儉。", "坐俠四海富，寧患食不糝。", "胡爲所謀狹，而復自戚慘。", "再拜起謝客，予言愧塵玷。"]'),
('ae429fca-3edf-4d14-a89b-ed4e937966e5','上知郡都官','强至','宋','宋诗','song-poetry','','[]','列郡二千石，所理我與共。',216,'全唐诗/poet.song.33000.json','["列郡二千石，所理我與共。", "臨淮守最賢，萬口交一頌。", "彼邦困飛蝗，我境欲集鳳。", "彼民粒不充，我黍地無空。", "嚴乎如秋霜，巨猾弗得縱。", "斷乎如蓍龜，吏法不敢弄。", "鈴齋晝觀書，朱轓春勸種。", "明堂購衆材，我公實梁棟。", "行吐胸中奇，勳名光有宋。", "賤生何爲者，碌碌備僚從。", "天幸所與薄，半歲侍羈鞚。", "燕雀勢力小，鵝雁食口衆。", "貧賤兩雖甘，瀝懇輒披控。", "朝廷重爲邑，外臺薦方用。", "豈惟進寸蹠，抑可利微俸。", "私心覬公舉，如昔望郡貢。", "媒衒士所醜，未罪已自訟。", "公如飛一章，舉族免饑凍。"]'),
('36a2ebfd-53eb-4de9-8719-28b195f5e977','呈屯田','强至','宋','宋诗','song-poetry','','[]','溪水日夜落，稍稍露沙面。',72,'全唐诗/poet.song.33000.json','["溪水日夜落，稍稍露沙面。", "經旬更不雨，深處亦成澱。", "巨篙架空航，澀若泝淺淀。", "况乃載百指，數纜安可縴。", "念此歸思發，急逾强弩箭。", "公如惜滯留，願借長風便。"]'),
('e805a94d-b173-4d84-a9a2-6815145ec636','送藥王圓師','强至','宋','宋诗','song-poetry','','[]','吳僧甚商賈，嗜利角毫芒。',264,'全唐诗/poet.song.33000.json','["吳僧甚商賈，嗜利角毫芒。", "或以翳自業，利心劇虎狼。", "今時愚鄙人，平居吝私囊。", "寒餓來求仁，一毫不肯將。", "不幸病且亟，呼醫計倉忙。", "惟醫所欲求，萬金弗較量。", "吳僧業醫者，十室九厚藏。", "張口待人哺，喋喋厭酒粱。", "求其不爾徒，蕭叢揀蘭芳。", "圓師何許人，出家本衢梁。", "自圓之先師，三世爲醫王。", "圓尤得術精，一丸起膏肓。", "雖掛吳僧籍，亦吳其衣章。", "仁義薰厥心，愈彼不願償。", "人以財啗圓，惡如唾霑裳。", "晨齋未有餘，一餠蔬充腸。", "行橐無長物，秋風藥裹香。", "昨因赴人急，挈然來浦陽。", "始見已可愛，氣溫語端詳。", "再見結所好，佛外喜縑緗。", "住久見益數，乃知數事長。", "作詩聊紀師，豈曰爲行光。"]'),
('342c7380-e827-4cc3-8d1a-20105e62296f','題婺源胡氏翛然堂','强至','宋','宋诗','song-poetry','','[]','歙山碧參差，歙水綠演漾。',156,'全唐诗/poet.song.33000.json','["歙山碧參差，歙水綠演漾。", "之子山水間，築室傲天壤。", "山空鳥飛鳴，水凈魚下上。", "觀魚悟至樂，聽鳥悅幽響。", "一樽泯悲歡，萬事齊俯仰。", "人境兩翛然，無復塵區想。", "故人石渠英，緣以命堂榜。", "作詩羨高懷，中服非外奬。", "嗟今急名人，疾足投世網。", "心撓迹固喧，求得道已枉。", "茲理曾莫知，所趨岐已兩。", "予亦慕子徒，泉石久思往。", "何當伴琴觴，一鼓東南槳。"]'),
('854e738d-d9ed-4a03-b038-a93f281e14d6','携印謁新守宿至德上方翌日馬上追書十四韵','强至','宋','宋诗','song-poetry','','[]','携符拜州守，半舍度微徑。',168,'全唐诗/poet.song.33000.json','["携符拜州守，半舍度微徑。", "有僧謁道傍，云我迓邑令。", "因徐指叢林，佛宇頗嚴浄。", "願驅大夫馬，一宿憩征鐙。", "我生嗜煙蘿，聞此愜幽興。", "乃留驗僧言，金碧果暉映。", "捨策游上方，塵襟覺疏瑩。", "山氣亂朝暮，谷響答鐘磬。", "清風中宵來，雲歛月垂鏡。", "微吟不知旦，坐席若初定。", "遂行登修塗，回首謝巖磴。", "咨予秉微尚，碌碌奚足競。", "一月兩移府，未暇救民病。", "徒爲章服裹，折腰損真性。"]'),
('b50c9905-bbed-4146-a052-96b7e772f9a4','予連日奔走吏事蚤出暮還君然兄數賜臨問乃不果一見辱遺佳句謹依韵和酬','强至','宋','宋诗','song-poetry','','[]','朝出鷄聲新，暮歸馬蹄苶。',48,'全唐诗/poet.song.33000.json','["朝出鷄聲新，暮歸馬蹄苶。", "思君不得往，一飯或三輟。", "自從伐木興，友道寖欲滅。", "夫子眷獨勤，聊解予心結。"]'),
('91d0666b-6973-4061-b6e1-638d0c9c10c9','橫溪回道中作','强至','宋','宋诗','song-poetry','','[]','赤雲蔽層霄，旱日作炎酷。',168,'全唐诗/poet.song.33000.json','["赤雲蔽層霄，旱日作炎酷。", "解带蔭廣厦，膚汗發如沐。", "世無廣寒宮，何地避蒸溽。", "嗟嗟尚未已，里胥報甚速。", "云有邑頑民，飲酒溢鼠腹。", "半酣張空拳，中者致殞踣。", "甲令著定憲，繼踵當視覆。", "驅車不敢緩，冒暑走山曲。", "敝蓋無丈陰，託庇何跼促。", "因思古賢宰，民鮮犯鞭扑。", "子賤弗下堂，政務自清肅。", "顧予今何人，爲治乃不淑。", "民既冒重辟，己亦苦匍匐。", "胡不樹善治，泰然處華屋。"]'),
('a09e3caf-8585-4b01-970d-9d42f543da99','祠仙姑回馬上作','强至','宋','宋诗','song-poetry','','[]','至和歲甲午，德音絕常軌。',204,'全唐诗/poet.song.33000.json','["至和歲甲午，德音絕常軌。", "寬徭且宥罪，外復講群祀。", "君言一朝發，人神共悅喜。", "今我官浦陽，距邑越十里。", "聞有仙姑祠，獨弗識何氏。", "按圖得本原，云是黄帝女。", "當年追仙遊，茲地倏輕舉。", "于今數千載，廟貌尚留此。", "幾欲私謁款，吏事日勞止。", "遽會郡符降，奉行德音止。", "以廟隸邑境，俾我即祠所。", "詰朝叩庭下，牲體已夙庀。", "巋然重林間，楹桷極華美。", "姑一婦人焉，血食反無已。", "丹朱雖男兒，而又作堯子。", "生失四海位，沒同若敖鬼。", "大夫不自立，始信徒爲爾。"]'),
('4b7d0bc2-a057-479d-99f4-69ddb6734b35','久雨','强至','宋','宋诗','song-poetry','','[]','雨師握天令，汲汲不停駕。',96,'全唐诗/poet.song.33000.json','["雨師握天令，汲汲不停駕。", "疾驅鞭群龍，俛首隨叱咤。", "乘怒作霶霈，不復息晝夜。", "羲和久埋輪，縮手喜閑暇。", "山川盛奔溢，若虞歷陽化。", "農民驗甲子，其應旱在夏。", "我疑上天漏，誰能補天罅。", "慰此農民心，無使憂早稼。"]'),
('0a8f5846-e9d6-4d59-8ebb-7c44b4c12b6d','寄辟疆','强至','宋','宋诗','song-poetry','','[]','憶昨枉君軒，始來就客邸。',216,'全唐诗/poet.song.33000.json','["憶昨枉君軒，始來就客邸。", "爾僕方息肩，顧我遽屈體。", "守閽前通名，倒屣出致禮。", "相見吐論議，所學愈根柢。", "徐爲出巨編，徹若涉清濟。", "昏膜得篦刮，塵心逾易洗。", "我亦露狂簡，君曾不訶詆。", "于時園正花，長日甕盛醴。", "插枝必滿頭，飲醆須露底。", "未幾踏歸鐙，相將灑別涕。", "戀戀有情照，數數辱書扺。", "自言困道途，僅能足鹽米。", "頻吟口燥吻，久騎肉消髀。", "首飛詩人蓬，腸苦孟郊薺。", "學舍勉棲託，亨會復傾徯。", "黄卷樂往聖，青襟列諸弟。", "愛子乏先容，何人堪密啟。", "努力著要策，隨詔獻文陛。"]'),
('fd100593-c61b-4b12-b726-ccca79c96eff','伯夷詩','强至','宋','宋诗','song-poetry','','[]','昔紂爲不道，毒心無生靈。',132,'全唐诗/poet.song.33000.json','["昔紂爲不道，毒心無生靈。", "四海如在鼎，誰能救將烹。", "周武從天人，戎衣舉仁兵。", "伯夷獨何爲，乃諫不聽行。", "紂徒久厭主，一朝倒戈迎。", "天下既宗周，大冊書武成。", "夷義愈爲耻，寧死弗苟生。", "周粟惡不食，雙目且餓瞑。", "紂無王者實，徒有王者名。", "雖曰臣伐君，紂德匹夫輕。", "吁夷豈不知，意在銷奸萌。"]'),
('8cdcf516-f4fc-4e68-9868-933d2d960f21','書感','强至','宋','宋诗','song-poetry','','[]','擇己要有持，擇人要有別。',96,'全唐诗/poet.song.33000.json','["擇己要有持，擇人要有別。", "淺夫脫所守，柔顔附炎熱。", "庸兒昧所擇，目前事苟悅。", "彼柔有時變，爾炎有時歇。", "歇者既死灰，變者遂剛鐵。", "平時綢繆地，一朝等楚越。", "古人論淡交，君子保常節。", "作詩貽知言，不爲昧者說。"]'),
('c71106b5-e648-4b3a-b433-32d6f204ef7f','奉和純甫秋扇','强至','宋','宋诗','song-poetry','','[]','粲粲機中練，作扇圓中規。',156,'全唐诗/poet.song.33000.json','["粲粲機中練，作扇圓中規。", "盛夏天無風，廣宇猶蒸炊。", "汗流既浹體，蚊齒仍毒肥。", "團扇當爾日，功利兩得施。", "一入君掌握，汗却蚊攘披。", "秋風刮地來，凉氣襲空帷。", "功竟勢亦去，退藏乃其宜。", "聖人制器用，用舍各有時。", "弓所以在鳥，鳥盡弓胡爲。", "蹄所以在兔，兔獲蹄何之。", "葛屨乃履霜，刺譏見于詩。", "作扇本禦暑，暑退當棄遺。", "奚必昧用舍，託怨班婕妤。"]'),
('54156bcd-33c1-4613-aafe-f39b77405d33','八月十六夜與宗哲純甫翫月','强至','宋','宋诗','song-poetry','','[]','結客城東樓，明月初出海。',96,'全唐诗/poet.song.33000.json','["結客城東樓，明月初出海。", "漸如水精盤，天宇無寸靄。", "清光如何買，厥價珠百琲。", "中秋一夕過，已覺人意改。", "冰輪縱遲遲，此夜復誰待。", "老蟾益自張，吐輝增十倍。", "把酒共月語，世態何足罪。", "自有昭昭暉，千古萬古在。"]'),
('6ea37726-df01-48e2-a448-160c26b6b93c','冬日偶書呈縣學李君擇之','强至','宋','宋诗','song-poetry','','[]','北風吹嚴雪，草木無媚姿。',156,'全唐诗/poet.song.33000.json','["北風吹嚴雪，草木無媚姿。", "野田一穗盡，雀鼠猶苦饑。", "浦陽槩窮山，不與陰冬宜。", "今我雖旅宦，一身十口隨。", "有酒奉親壽，呼妻伴兒嬉。", "幽腸尚多感，悁結對此時。", "念子客千里，形影外更誰。", "空齋抱吟膝，敝案覆飲巵。", "我本依頼少，校子反有餘。", "何日富貴塗，引子並足馳。", "朝得位夔契，暮致君軒羲。", "收身結嘉客，量金買妖姬。", "人間有閑愁，安能到雙眉。"]'),
('93d7bac5-5eae-4978-b945-cf9576f90a66','送純甫仙尉','强至','宋','宋诗','song-poetry','','[]','秋晚送歸客，別酒風前酣。',144,'全唐诗/poet.song.33000.json','["秋晚送歸客，別酒風前酣。", "一揖不回歸，撇然就征驂。", "挽裾問客故，捨我何其甘。", "客言有慈母，三歲淮之南。", "今將拜嘉慶，歸心劇風帆。", "薄親厚他人，倒置理豈堪。", "顧予失所問，汗顔爲客慚。", "客生富豪家，妙年穿青衫。", "初仕已絕足，不與群駑參。", "掾邑尚牽制，逸驥受轡銜。", "縱之使自馳，萬里日可貪。", "持此作親壽，行矣毋少淹。"]'),
('2724305b-620f-427d-98ce-8b72ad0d9445','將別純甫四十字奉呈','强至','宋','宋诗','song-poetry','','[]','我馬將北馳，子車亦南挽。',48,'全唐诗/poet.song.33000.json','["我馬將北馳，子車亦南挽。", "車馬無留行，相去即相遠。", "風林秋聲乾，落日孤峰晚。", "後會未可知，莫使別觴淺。"]'),
('8bfeb9ec-a44c-4984-ba4a-ea98775612f2','將有東陽之行宗哲爲具話別以詩見招因答來貺','强至','宋','宋诗','song-poetry','','[]','秋高山城幽，風動林葉吼。',48,'全唐诗/poet.song.33000.json','["秋高山城幽，風動林葉吼。", "百感從中來，將分故人手。", "故人惜輕別，樽酒欲相厚。", "未飲已頹然，別恨濃於酒。"]'),
('a2fcb75f-435c-4952-897d-aa6d6b1cdaa8','別筠陽','强至','宋','宋诗','song-poetry','','[]','憶初來筠陽，風土習未穩。',120,'全唐诗/poet.song.33000.json','["憶初來筠陽，風土習未穩。", "家人畏山氣，一日或數飯。", "愁來數去期，三載若天遠。", "居之既累月，吏事頗云簡。", "山水慣可觀，鷄彘肥堪饌。", "却愁解印紱，奪此養疏懶。", "觴詠趣滋適，不覺滿銓限。", "門前迎新官，槌鼓鬧田阪。", "顧予謝鄧侯，寧有邑人挽。", "水聲與山光，念此違耳眼。"]'),
('3a0089cc-7913-4ac3-8aa1-e9a5f9dc0960','寄純甫','强至','宋','宋诗','song-poetry','','[]','相從浦陽官，三十月盈缺。',108,'全唐诗/poet.song.33000.json','["相從浦陽官，三十月盈缺。", "出必並轡游，居常對案啜。", "予褊子能恕，子短予還訐。", "久而見交心，中不容間舌。", "乃於窮秋時，忽作遠道別。", "別腸如亂絲，一寸知幾結。", "別語如悲笳，一聲凡數咽。", "咽極繼以號，旁顧亦慘切。", "匹馬獨來歸，山城雨初歇。"]'),
('3af2b836-611d-4542-8e19-879135131b50','依韵答貫中見貽','强至','宋','宋诗','song-poetry','','[]','魚蝦泳大海，龍困污池埋。',192,'全唐诗/poet.song.33000.json','["魚蝦泳大海，龍困污池埋。", "鸞鳳氣塞吭，百鳥鳴其喈。", "猶吾呂夫子，短褐包壯懷。", "舉脚踏青雲，失勢寸步乖。", "却視後來輩，厭己猶積柴。", "否屯豈我獨，升泰奚人皆。", "一別春四歸，聚首邈不諧。", "前日忽踵門，謁與行李偕。", "相迎把交臂，似合已擘釵。", "于時節清明，花凈無纖霾。", "共引不算觴，傾瀉猶長淮。", "歌詩互挑戰，舒慘出百骸。", "愁吟慘春暉，樂咏舒寒荄。", "男兒萬里心，無作伏櫪騧。", "天王下科詔，羅俊基泰階。", "盍行取好官，一爲光同儕。"]'),
('c0f428bc-c32e-4141-a475-9a83b4105d7b','野園移植小松','强至','宋','宋诗','song-poetry','','[]','平生歲寒心，頗好歲寒色。',144,'全唐诗/poet.song.33000.json','["平生歲寒心，頗好歲寒色。", "一松如人長，慘淡窮山側。", "樵兒日過之，有意斧斤得。", "予心異爾意，野圃爲移植。", "醉聽疏聲眠，吟到細陰息。", "落落巖澗姿，相對永朝夕。", "如言千載後，其長可千尺。", "人生雖百年，相期眇無極。", "且結無情游，汝固予何易。", "豈待百年外，人松兩殊迹。", "人爲松下土，松化土上石。", "我生始逾壯，足以伴寒碧。"]'),
('917d717c-b7db-4efd-8245-3900183b7754','公立煎茶之絕品以待諸友退皆作詩因附衆篇之末','强至','宋','宋诗','song-poetry','','[]','造化于草木，所與有薄厚。',192,'全唐诗/poet.song.33000.json','["造化于草木，所與有薄厚。", "茶生天地間，建溪獨爲首。", "南土衆富兒，一餠千金售。", "公立須南官，好居衆富右。", "俸錢未到門，已入園夫手。", "買藏惟恐遲，秘之逾瓊玖。", "前日發箱篋，出以奉賓友。", "蒼玉碾底碎，浮雲碗面走。", "一飲睡魔竄，空腸作雷吼。", "茶品衆所知，茶德予能剖。", "烹須清泠泉，性若不容垢。", "味回始有甘，苦言驗終久。", "吁茶特不幸，而出三代後。", "不及餘草木，盡掛詩人口。", "禹貢籍九州，瑣細登橘柚。", "古若有此茶，商紂不酣酒。"]'),
('2304940d-077a-4a77-a622-b53178225d83','范鉞進士遺樓徹司馬庭石以質交樓作詩美之因邀某同作','强至','宋','宋诗','song-poetry','','[]','樓君仕塗傑，范子儒林選。',144,'全唐诗/poet.song.33000.json','["樓君仕塗傑，范子儒林選。", "論交二人者，誠至不以勉。", "范也車將西，樓也酒以餞。", "胡然膠漆地，猶假外物顯。", "范子庭前石，千年立蒼蘚。", "移入樓君圃，重可載十輦。", "堅以示固交，此意豈云淺。", "怪不涉剜刻，險不到崖巘。", "坦然久要情，無向石間辯。", "其堅竟有泐，其重尚可轉。", "不若照以心，兩確乃吾善。", "永結忘形游，嵌巖君勿羨。"]'),
('4c03218c-10cd-40f6-a629-99d5a5edccf0','和施耕進士憶竹','强至','宋','宋诗','song-poetry','','[]','夫子卧古屋，趣敵巖谷深。',96,'全唐诗/poet.song.33000.json','["夫子卧古屋，趣敵巖谷深。", "六籍環一身，口誦頭不簪。", "瘦碧久去眼，寂寞清風心。", "朝思蔭之醉，暮思繞以吟。", "秋空碧新弄，無處停幽禽。", "安得青玉枝，來作半畝陰。", "終朝對几榻，歲寒結知音。", "於焉傲富貴，追蹤晉賢林。"]'),
('44ae5b4b-648b-4882-a12c-e2766547375d','京華對雪','强至','宋','宋诗','song-poetry','','[]','嘉祐歲庚子，長安一尺雪。',120,'全唐诗/poet.song.33000.json','["嘉祐歲庚子，長安一尺雪。", "落地還成冰，后土凍欲裂。", "出門望天街，層城裹銀闕。", "健馬載高冠，傍人指夔卨。", "拜表瑶墀歸，酒面風前熱。", "萬井莫回頭，窮閻正騷屑。", "曉突無青煙，饑唇閟殭舌。", "咄嗟路邊子，未死衣百結。", "亦有待次人，空囊磨歲月。", "愁吟徒爾爲，泱漭天地闊。"]'),
('c6aa50d8-d63b-41bf-8d54-c458a622ac18','與任道及順久二師賦小閣見月','强至','宋','宋诗','song-poetry','','[]','醉領玉川子，夜入支公院。',121,'全唐诗/poet.song.33000.json','["醉領玉川子，夜入支公院。", "危閣邀共登，身在霜空半。", "缺月穿雲來，塵區未應見。", "長飈蕩寸靄，天宇痕無線。", "坐久吹青燈，寒光可對面。", "飄颻釋苑秀，灑落儒林彥。", "相逢愛憂清景，險語寫幽玩。", "野令才素慳，斗爲吟毫健。", "詩成萬象索，孤影轉樓殿。", "遊屨絕出門，高僧應作伴。"]'),
('3cfd6383-1287-474b-9846-47d31551a70b','誡言','强至','宋','宋诗','song-poetry','','[]','君子言欲艱，出口終身懼。',120,'全唐诗/poet.song.33000.json','["君子言欲艱，出口終身懼。", "衆人易由言，朝出暮已渝。", "言之于一身，譬若戶藉樞。", "爾樞苟不慎，彼戶將誰扶。", "不重一語言，是輕六尺軀。", "志言要有成，不成陷半塗。", "耻言在克悛，不悛行卒污。", "今吾觀衆人，一言異朝晡。", "爾志既可見，爾耻復若無。", "行將小人歸，嗚呼爾非夫。"]'),
('8da42780-8b24-459d-bc68-a4d5c07dc31b','賀陳右司生辰','强至','宋','宋诗','song-poetry','','[]','悠悠大塊間，萬類紛相敵。',264,'全唐诗/poet.song.33000.json','["悠悠大塊間，萬類紛相敵。", "偉哉拔俗人，真宰豈無力。", "六經陷邪說，釋儒共一律。", "天未喪斯文，公生抱絕識。", "著書羅古今，射策開胸臆。", "前輩幾欲盡，後來昧所適。", "天將激頹波，公生秉孤直。", "數諫難居中，三已無慍色。", "海宇屬無虞，天工或曠職。", "天保祐皇帝，公生藴奇德。", "培擁棟梁姿，一旦壯王國。", "禁網雖小寬，疲俗未全逸。", "惟天念我民，公生富才術。", "發揚雲雨勢，諸方待膏澤。", "天既責公深，眉壽夫何惜。", "行看佩相印，不羨登仙籍。", "南山雅望重，北斗威聲赫。", "稟生固難朽，吐納自不息。", "惟昔軒冕徒，尤喜山林迹。", "留侯追赤松，志就亦何益。", "傅說爲列星，但已脫寰域。", "孰如我公貴，與國長無極。"]'),
('7a21cc82-d4ca-4add-89cf-027398009748','送張升甫三十韵','强至','宋','宋诗','song-poetry','','[]','歲餘客秦雍，處俗失大方。',288,'全唐诗/poet.song.33000.json','["歲餘客秦雍，處俗失大方。", "眼前紛朋游，外同異中腸。", "最得張子晚，一見合柔剛。", "拜我十年兄，本非以其長。", "直緣父兄舊，及此三紀强。", "子之先大夫，疇昔倅餘杭。", "予時以童子，進謁升公堂。", "仲兄齒予亞，同學隸州庠。", "行聯坐接席，無異彼雁行。", "此時君尚孩，縱記今亦忘。", "去住忽南北，中間異行藏。", "後予與君兄，鄉貢入帝鄉。", "見面初驚疑，偕問徐乃詳。", "同年忝進士，茲復同省郎。", "伊予論契好，始見今髮蒼。", "昨君解下邽，東去隨薦章。", "歸來婦翁家，春風到秋霜。", "予居幸對舍，有酒呼隔牆。", "往還興頗熟，間外絕毫芒。", "乘月步橫橋，觀漁立回塘。", "詩句迭唱酬，稍稍積巾箱。", "自許先功名，知我尚激昂。", "放言遺形骸，不以我爲狂。", "古稱管鮑交，千載竊相望。"]'),
('0638849c-a9c1-40b6-9aa3-f41b1d552266','送吳令常甫之武平','强至','宋','宋诗','song-poetry','','[]','朝廷重一邑，悼昔容備員。',288,'全唐诗/poet.song.33000.json','["朝廷重一邑，悼昔容備員。", "自嚴薦舉法，頗號近得賢。", "仕者既擇地，主恩那罄宣。", "遐封暨惡壤，十必九棄捐。", "武平杳何所，閩裔天南偏。", "林密毒虺藏，吐瘴蟠長煙。", "冬候氣亦暖，里俗衣不綿。", "舊令昨請代，闕榜張三銓。", "無人議一往，常甫獨不然。", "丈夫志四海，豈安廬室邊。", "畏避屬衰怯，我今幸壯年。", "所寄有民社，勇去無山川。", "吳天破新臘，雪片衝離筵。", "闔坐勸別杯，情厚禱亦虔。", "藥餌慎勿疏，善保食與眠。", "柂牙起驚濤，餞車散江壖。", "吏民前塗奔，爭迎上瀧船。", "到脩府中謁，首低小侯前。", "主人知才名，應以塵土憐。", "下車轉春首，訟未臨婚田。", "遠人喜新君，有訴恐不先。", "據案掃滯務，一决如流泉。", "呼兒伴兒戲，邑事樂靜便。", "地寬人物稀，林實雜海鮮。"]'),
('bdffdc12-6c8a-4dd5-b159-9451df2aced0','曾元恕累日不相見以詩垂寄依韵和答','强至','宋','宋诗','song-poetry','','[]','丈夫收功名，要在少壯時。',144,'全唐诗/poet.song.33000.json','["丈夫收功名，要在少壯時。", "今予四十强，才短良時遺。", "俯首入掾曹，所託真一枝。", "動靜繫他人，何異馬受縻。", "事業乖聖賢，饑寒愧妻兒。", "浩歌望青雲，致身分已遲。", "江湖久去眼，終日懷釣絲。", "元恕知我深，愛惡非衆隨。", "憐我事冗宦，役役猶兒嬉。", "十日不一見，敢以奔走辭。", "與子結永好，交情保無移。", "相從文酒歡，晚歲滄洲期。"]'),
('88296668-0c0a-4e0d-aef9-b5c40988fd40','走筆成一篇答徐君先輩見寄','强至','宋','宋诗','song-poetry','','[]','定交初何年，昔齒會稽學。',264,'全唐诗/poet.song.33000.json','["定交初何年，昔齒會稽學。", "君壯我尚少，道復先我覺。", "子時于衆人，百鳥一鸑鷟。", "學官程諸生，題品或義卓。", "衆方縮手顧，君筆已一捉。", "落紙千餘言，渾如玉出璞。", "辭場或鼓行，無敢犯鋒矟。", "有時談遺經，聖賢在口角。", "憤疾異說妄，摘抉三傳駮。", "語氣清不休，旱天冽雷雹。", "南北俄乖張，同時去師幄。", "未幾會京國，君羽正濯濯。", "以文試有司，好古拙雕琢。", "一失太常第，聞子繼屯剝。", "翠鎩累在毛，龜剔釁由殻。", "古人亦憂患，千載名愈卓。", "予雖綴小官，夙志負山嶽。", "簿領但戕性，祿粟不周啄。", "再命作陋邑，舉動尤齷齪。", "旋巢子何所，距我幸非邈。", "寄詩冬爲期，當遂笑一握。", "待將得喪理，同付尊酒濁。"]'),
('3d5f571c-5df1-4093-b8fa-31765bb6e0a7','送元恕','强至','宋','宋诗','song-poetry','','[]','我本生窮閻，才命兩乖塞。',208,'全唐诗/poet.song.33000.json','["我本生窮閻，才命兩乖塞。", "再試得一第，失足落銓格。", "去年赴選集，摩肩雜隸役。", "吏口駢名呼，摧沮氣填臆。", "僦居在閑坊，門巷少人迹。", "于時苦病吟，誰肯顧越{血/与}。", "高冠縱一臨，車馬有屈色。", "平生青雲志，跕跕若墜翼。", "羨君富詞才，時志復兩得。", "解褐拜初命，便綴審官籍。", "秋高馬足健，駕言往京國。", "諸父列禁嚴，南北羅第宅。", "往來伯叔間，此行穩棲息。", "君家世儒林，圖史况山積。", "燈火今可親，幽探勉餘力。", "京都號紛華，君志定非溺。", "勿貽雙親念，此外慎眠食。"]'),
('5f2d370e-0f21-4445-a32e-b85203c1280c','早行澠池道中','强至','宋','宋诗','song-poetry','','[]','二年別咸秦，八月過崤澠。',96,'全唐诗/poet.song.33000.json','["二年別咸秦，八月過崤澠。", "碎石隠地起，險塗抱山轉。", "我馬無完蹄，我僕有重趼。", "林紅烈炬暴，澗白亂流淺。", "夙駕露濕衣，夕休獨臨饌。", "轍迹環九州，孔子未能免。", "咨予獨何人，安坐顔輒靦。", "區區適其宜，誓將策疲軟。"]'),
('96e139c8-6261-4bf0-a3c4-5a0246f353cd','乙巳十月七日過黄河中流遇巨浪偶作','强至','宋','宋诗','song-poetry','','[]','清旦絕大河，拍堤滾黄沙。',144,'全唐诗/poet.song.33000.json','["清旦絕大河，拍堤滾黄沙。", "巨舟忽摇簸，心悸眼亦花。", "咨予豈輕生，將身試魚蝦。", "忠信固所憑，此理懼或差。", "定息神魂寧，歸心眇天涯。", "故鄉念昔游，湖面貼碧紗。", "醉舫穿芰荷，坦腹如眠家。", "天水自照映，鷗鷺相交加。", "雖無風波憂，齷齪未足誇。", "豈如尋河源，安穩浮靈槎。", "脫略遺近觀，飄飄薄飛霞。", "低頭顧濁流，卑險吾汝嗟。"]'),
('eb2bd480-f082-4b10-978c-4d97046c4d8f','過潼關','强至','宋','宋诗','song-poetry','','[]','巨方信天開，嵽嵲土山口。',120,'全唐诗/poet.song.33000.json','["巨方信天開，嵽嵲土山口。", "豈惟控內外，勢不漏飛走。", "一夫或當關，可敵萬夫守。", "山河此襟带，怙險聖所否。", "明皇晚倦勤，意恃太平久。", "絕艷荒真妃，轉盼六宮醜。", "祿山假天性，恩豢不知厚。", "鐵騎長驅來，哥舒苦徒手。", "吾君暢道德，四海一父母。", "人心自固結，茲關復何有。"]'),
('3aa05515-da5f-40e0-b9ee-0d9069fbd890','苦雨','强至','宋','宋诗','song-poetry','','[]','關輔連歲旱，耕地千里赤。',168,'全唐诗/poet.song.33000.json','["關輔連歲旱，耕地千里赤。", "官家放租稅，猶有道邊瘠。", "群國乞膏雨，童巫叫蜥蜴。", "神聽久寂寞，民意轉凄惻。", "天公忽瞑目，一怒乖龍殛。", "雨師偃其旁，驚起振厥職。", "不復計多寡，傾瀉信朝夕。", "入地知幾犁，地上但盈尺。", "渹如三峽注，那辨四檐滴。", "落勢曾未停，廬井反憂溺。", "始知天公難，不易人願適。", "舉頭告風伯，速吹濕雲坼。", "却還秋日光，迤邐照阡陌。", "俾民布新種，來歲飽麰麥。"]'),
('258e60f1-39c6-445a-86e0-f5026a7a3552','幕中偶書','强至','宋','宋诗','song-poetry','','[]','劉侯驅車東，幕府賓客稀。',132,'全唐诗/poet.song.33000.json','["劉侯驅車東，幕府賓客稀。", "憑几獨蕭然，真與萬事違。", "巢燕無世情，閑堂時一歸。", "東風忽怒號，輒來撼窗扉。", "攪我靜中趣，聒聒無停威。", "塵沙亦侵人，猶喜勢力微。", "日暮風稍息，出戶聊振衣。", "行吟視庭木，枝空但花飛。", "幽思感晚春，浩歌送斜暉。", "翟公大書門，怨激恐已非。", "俗物喜去眼，杜子吾庶幾。"]'),
('862961cd-ba04-4961-91b9-65d9f1aab20f','徙居','强至','宋','宋诗','song-poetry','','[]','人生如寄客，况復真客宦。',156,'全唐诗/poet.song.33000.json','["人生如寄客，况復真客宦。", "南舟與北車，來往若征雁。", "殘暑赴西雍，冉冉忽秋晏。", "三徙乃定居，什物旋營辦。", "騰移費負挈，猶恐僕夫訕。", "幕府文書稀，食息有餘閒。", "短才乏所補，公給浪蒙豢。", "懼辜主人恩，從事不敢慢。", "南軒有佳趣，流渠瀉幽澗。", "潺潺無時休，弄水悅童丱。", "關中氣候晚，時菊始云綻。", "亦有終南雲，朝暮生顧盼。", "浩歌一樽酒，常分任鵬鷃。"]'),
('7d8baf7c-581b-4f71-8b94-72c2b45d03d4','幕中書懷','强至','宋','宋诗','song-poetry','','[]','宦游老歲月，春花漸空枝。',144,'全唐诗/poet.song.33000.json','["宦游老歲月，春花漸空枝。", "坐耗鏡中顔，日饒鬢邊絲。", "流俗宜重輕，青雲勢參差。", "剛腸寡所合，出門復何之。", "趨向於今乖，考古聊自怡。", "黄卷有聖賢，目覽心與期。", "君子顧萬世，小人較一時。", "不見九原骨，貴賤共狐狸。", "惟有賢愚名，縱久亦兩岐。", "退之賦二鳥，無乃爲物移。", "信己一推天，孟子真吾師。", "得喪付濁醪，身外非所知。"]'),
('ad709ca1-cb90-4901-88f0-0dc2dc9abf1e','九日與諸君飲','强至','宋','宋诗','song-poetry','','[]','寒暑當遞遷，日月會陽九。',48,'全唐诗/poet.song.33000.json','["寒暑當遞遷，日月會陽九。", "綠鬢驚秋風，黄花泛樽酒。", "行樂重此辰，登高命諸友。", "古人感塵世，宜開笑歌口。"]'),
('7e7fd378-2a37-4d6f-9067-6385bd4ebdb7','送粹中赴舉','强至','宋','宋诗','song-poetry','','[]','朔風攪疏林，短日寒無暉。',96,'全唐诗/poet.song.33000.json','["朔風攪疏林，短日寒無暉。", "有客氣軒昂，束書赴禮闈。", "行橐雖云輕，滿抱藏珠璣。", "出以售春官，善價其可希。", "骨肉送出門，稚子猶牽衣。", "我爲舉別觴，一言庶不違。", "京師足紛華，慎勿事輕肥。", "白首有雙親，待子得官歸。"]'),
('09ff219f-d49c-4833-b876-ee327a7a7b1f','石亢之出銅雀臺硯相示信筆題其後','强至','宋','宋诗','song-poetry','','[]','銅臺遺荒基，寂寞千載下。',48,'全唐诗/poet.song.33000.json','["銅臺遺荒基，寂寞千載下。", "黄埃朽壤間，所得或片瓦。", "硯材世共珍，購金不論把。", "浪好昧所別，往往亂真假。"]'),
('2bc59d5a-a5e8-424b-87af-33304cb142d4','聞毀','强至','宋','宋诗','song-poetry','','[]','憶初向關中，觸熱事西走。',204,'全唐诗/poet.song.33000.json','["憶初向關中，觸熱事西走。", "淋漓汗征衣，早夜犯星斗。", "歡然赴所知，辛苦復何有。", "主人喜賓至，相見勞杯酒。", "誓將效毫髮，聊以塞所厚。", "遇事因輒言，何嘗計從否。", "平生性坦率，間或忤交友。", "是非長安城，側身避讒口。", "彼奸乘其前，吾慮亦已後。", "二叔誣周公，三人惑曾母。", "青蠅亂黑白，視潔以爲垢。", "聖賢且不免，予免焉能苟。", "浩歌動歸歟，至此信不偶。", "春風憶東南，巖花映溪柳。", "南山有屋廬，釀熟喚鄰叟。", "何時理扁舟，舊物入吾手。", "回頭謝狺狺，投北汝誰受。"]'),
('5a6bc142-f06e-4cf7-ba5c-991eea2e8d98','壬子歲旱','强至','宋','宋诗','song-poetry','','[]','熙寧歲壬子，春旱初可怪。',120,'全唐诗/poet.song.33000.json','["熙寧歲壬子，春旱初可怪。", "不雨訖夏尾，天地一爐鞴。", "赤日裂厚土，黄埃沒經界。", "農夫望雲霓，脰折意未懈。", "侍中守北門，撫俗先罷瘵。", "閔雨憂更深，遍禱劇齋戒。", "老宮與佛廟，三日一往拜。", "冠者厭於呪，褐者勞於唄。", "雨應絕不聞，煩鬰何由快。", "憑誰訴天公，請執乖龍械。"]'),
('b1895d1c-06de-406b-a6de-0c24b8a5ace9','予初春被病中夏少間勉入省局偶成二十二韵','强至','宋','宋诗','song-poetry','','[]','東風吹春來，移疾聊少休。',264,'全唐诗/poet.song.33000.json','["東風吹春來，移疾聊少休。", "寒熱戰予軀，漸如錯春秋。", "侵尋日以劇，謁告牒屢投。", "性命吾自安，所負空食羞。", "交親每問訊，愛者或見憂。", "伏枕數晦朔，忽忽月四周。", "有叟肆囁嚅，咄哉我何尤。", "騰口狀予疾，張大實頗浮。", "背憎詋休咎，唯恐予疾瘳。", "寧獨冀術勝，仍欲悅予仇。", "叟乎汝何愚，天命非爾謀。", "生死籍素定，理莫移恩讎。", "身世如寄客，日月速置郵。", "引照盍自儆，霜雪滿汝頭。", "胡然不如止，脅肩諂貴游。", "干進苟朝暮，利吻銛戈矛。", "予今偶不死，官意滋悠悠。", "却來坐省局，心迹逾林丘。", "北扉對新篁，陰薄幹已脩。", "薰風送瀟灑，不博千戶侯。", "富貴功名間，有待終無求。", "鸞鳳志寥廓，燕雀徒啾啾。"]'),
('98ba4d05-e3ab-412f-a2bb-5041aad3eeda','某蒙君章兄寵示櫻桃佳篇輒依韵奉和','强至','宋','宋诗','song-poetry','','[]','炎蒸有正色，下與地氣關。',240,'全唐诗/poet.song.33000.json','["炎蒸有正色，下與地氣關。", "相結成含桃，使冠百果班。", "獨憂赤日曝，坐變紅成殷。", "多應絳闕種，流落來塵寰。", "金盤瀉不定，四走如循環。", "睡龍失火齊，頷空皆血潸。", "以口比樊素，白傅誇嬌鬟。", "却嗟荔子陋，遠在炎荒山。", "每歲貢天子，險路勞緣扳。", "豈如盛京洛，地廣生不慳。", "朝須暮可進，先御後匪頒。", "離樹既不久，弗改猶童顔。", "吁嗟唐中宗，游樂芳林閑。", "君臣失儀度，口摘省手攀。", "不聞薦先廟，書在史冊間。", "愈籍爭詩豪，勁句嘗往還。", "予知青冥賜，難到山溪灣。", "林園幸自有，圓顆赫不黫。", "雖熱豈厭食，縱密寧忍刪。", "况此鮮嫩質，非並青梅頑。"]'),
('af3b6287-2a26-4fdf-9f9d-09f5b076a474','群牧司雨中池上作','强至','宋','宋诗','song-poetry','','[]','累朝困炎威，一雨轉愁意。',48,'全唐诗/poet.song.33000.json','["累朝困炎威，一雨轉愁意。", "偶看碧蘆叢，宛在滄洲地。", "岸草閑自滋，庭葉紛以墜。", "移床就幽窗，檐溜聒清睡。"]'),
('64be9127-f08c-4876-9ce7-7c9f104301b6','送章傳道東歸三十八韵','强至','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','一日或數篇，數日哦一軸。',288,'全唐诗/poet.song.33000.json','["一日或數篇，數日哦一軸。", "夫子之於詩，夜補晝不足。", "長吟天地間，萬象困題目。", "天徒飽其才，而特餒其腹。", "聲名三十載，半百事場屋。", "今年試春官，淡榜輒不錄。", "東風吹殘花，客淚迸京轂。", "回頭謝青雲，却抱來時玉。", "河陽謁相公，每見輟飯沐。", "贐金實空囊，禮遇駭僮僕。", "遂游西諸侯，騎馬度函谷。", "長安尋素交，零落半丘木。", "惟有終南山，相看似舊綠。", "東李雅好客，既親意轉篤。", "授館如投家，晨杯繼宵燭。", "羸馬殘青芻，饑僮厭餘肉。", "予方坐幕府，陷嫉苦流俗。", "群吠耳且盈，介立趣頗獨。", "得君倍歡然，坦不置邊幅。", "論情雖云晚，聞誼固已夙。", "二章初交鋒，懦氣令避縮。", "自笑不量力，强和旋取衄。", "從此遺形骸，留饌或脫粟。", "有酒時招邀，共醉小軒竹。"]'),
('51302cdb-5f76-4028-959c-f1d4f8a4737d','予以病久不赴朝謁因灸三里穴罷信筆偶書','强至','宋','宋诗','song-poetry','','[]','竊祿了無補，卧疴慚有日。',48,'全唐诗/poet.song.33000.json','["竊祿了無補，卧疴慚有日。", "空聽朝雞鳴，阻挂朝衣出。", "啟處不自安，灼艾加諸膝。", "庶幾起沈苶，犬馬委微質。"]'),
('1f712185-fd8b-45d9-a996-0ed3c773a6ad','立秋後病作此寫懷','强至','宋','宋诗','song-poetry','','[]','卧病喜秋至，昏煩庶以平。',48,'全唐诗/poet.song.33000.json','["卧病喜秋至，昏煩庶以平。", "清風不少濟，宿疢仍相攖。", "凉葉猶未振，陰蛩已先鳴。", "四時順萬物，奚獨戕吾生。"]'),
('c5242b33-e4d5-4f8f-bea5-061291b1cfb2','入山謁怡然上人因成短篇皆書即時事','强至','宋','宋诗','song-poetry','','[]','行穿六松陰，鳥語逢人寂。',108,'全唐诗/poet.song.33000.json','["行穿六松陰，鳥語逢人寂。", "林僧洗山缽，正了寒堂食。", "揖我喜滿顔，吟窗半軒闢。", "鳳凰不無情，天外送佳色。", "春風動花雨，枝上或涓滴。", "羨師得安住，我亦有閑適。", "出門懶鞍馬，把袂步幽石。", "石盡浮泥深，恰恰露雙屐。", "臨別心徘徊，野店更一息。"]'),
('830b77dd-c027-4364-bfa8-65d23f78bc0b','僧副普濟過予詰其師名僧職之所自則曰嘗濟活饑民百萬朝廷論酬以得之欽嘆不足繼以詩云','强至','宋','宋诗','song-poetry','','[]','佛子葦麻衆，槩能蠶食人。',144,'全唐诗/poet.song.33000.json','["佛子葦麻衆，槩能蠶食人。", "庸奴買師名，納貲不計緡。", "普濟釋苑秀，類同行佛均。", "往歲東陽饑，愁聲聒蒼旻。", "天民坐欲死，誰肯發一囷。", "師勇營饘糜，全活百萬民。", "外臺上其事，朝廷嘉師仁。", "相府議優賞，美號寵厥身。", "汝往貳爾正，示勸出聖神。", "今時士大夫，體雖具纓紳。", "十九飽妻孥，何暇及困貧。", "視師固有激，抑可警其倫。"]'),
('a61d8450-6ae2-42dc-ac26-6ec27d4cae5e','墨蟹','强至','宋','宋诗','song-poetry','','[]','瑣瑣江湖中，忽在幽人壁。',96,'全唐诗/poet.song.33000.json','["瑣瑣江湖中，忽在幽人壁。", "短螯利雙鉞，長跪生六戟。", "骨眼驚自然，熟視審精墨。", "初疑朿穴朿，猶带浮泥黑。", "橫行竟何從，躁心固已息。", "終朝牆壁間，頗有肥霜色。", "我來空持杯，左手莫汝食。", "誰奪造化功，生成歸筆力。"]'),
('a0afb7a4-8ade-4719-aa52-fd24da894479','棲雲閣','强至','宋','宋诗','song-poetry','','[]','越山東南號勝絕，古寺巖洞窮高深。',112,'全唐诗/poet.song.33000.json','["越山東南號勝絕，古寺巖洞窮高深。", "山雲出爲洞口雨，或時散作巖下陰。", "不有神物此蟠據，安得氣類長相尋。", "寺僧愛雲恐雲遠，置閣雲上躡以臨。", "豈惟憂懷獨舒悅，更許遊客開塵襟。", "客來祇知寓暫賞，不道歸去還塵侵。", "寧如僧住得安穩，終日自共雲無心。"]'),
('d308e1c9-afd4-4787-a2c4-27bc6fa7bcee','陸君置酒爲予唱陽關即席有作','强至','宋','宋诗','song-poetry','','[]','陽關何處草烟平，不識陽關空記名。',128,'全唐诗/poet.song.33000.json','["陽關何處草烟平，不識陽關空記名。", "古人驅車欲西過，吟成繕寫離群情。", "天涯此去故人絕，雖有樽酒同誰傾。", "古人幽怨幾時盡，至今愁殺陽關聲。", "陸君酒酣喜自唱，坐上客淚俄縱橫。", "杯盤咫尺意萬里，忽若身在關山行。", "耳傍宛聞車馬動，簾外已覺邊風生。", "乃知樽酒須故舊，爲君一飲無餘觥。"]'),
('e0912974-ef8d-4137-9416-bfce92035869','結交行','强至','宋','宋诗','song-poetry','','[]','貴友高車照簪組，富友黄金輕糞土。',128,'全唐诗/poet.song.33000.json','["貴友高車照簪組，富友黄金輕糞土。", "二友方論富貴交，以漆傾膠入心腑。", "一朝金盡囊無餘，門前不見簪組車。", "貴人今車底似昔，早失黄金舊時客。", "由來結交要勢均，一輕一重難爲人。", "滔滔世上耳餘輩，寂寥管鮑今埃塵。", "交情以勢不以義，今日雖同明日異。", "君子結交自有持，賤貧富貴不我移。"]'),
('742b306d-30ca-4157-9717-d6c24d75fe1e','依韵和李評文思','强至','宋','宋诗','song-poetry','','[]','我心烱烱君應識，萬事都慵獨吟癖。',176,'全唐诗/poet.song.33000.json','["我心烱烱君應識，萬事都慵獨吟癖。", "二年客眼看京華，可見無媒進無益。", "勢門所喜在佞豪，直語空拳無一懌。", "愛君挺拔生貴家，不學庸兒醉朱碧。", "兩提試筆賦翰林，落落金聲天上擲。", "改丞殿省頭不回，直把群經重研摭。", "相逢憐我猶滯濡，四十金閨未通籍。", "勢門宜不容此身，頼有君家好投迹。", "書齋延坐開新編，光焰文章追祖白。", "更邀詩社同襟期，脫略形骸一疏戚。", "公侯必復君勿遲，志士由來輕尺璧。"]'),
('6012eddd-915e-46c5-8c35-30bef4fc6645','贈賈麟','强至','宋','宋诗','song-poetry','','[]','賈君貌古文章老，虬髯鋪胸犀插腦。',288,'全唐诗/poet.song.33000.json','["賈君貌古文章老，虬髯鋪胸犀插腦。", "戲誇才力驚衆人，談笑千篇筆端掃。", "酒酣座上披天真，鏟去崖岸露懷抱。", "今年禮部更新書，續詔九州登俊造。", "宿儒晚秀趨術茫，肝愁胃苦搜辭藻。", "獨君所向異爾爲，長袖陂陀踏幽草。", "行窮兩徑躋巖巔，指點晴江辨秋島。", "却騎匹馬歸湖山，古寺相逢情愈好。", "空樽無物醉故人，輒出囊錢具梨棗。", "更長坐久然青燈，語雜譏諧欲顛倒。", "我方正色起問君，何乃終年事枯槁。", "齒牙未豁才有餘，一賦從容成腹藁。", "琢磨高論馳古今，足歷天衢騁王道。", "駑群沓沓猶爭先，驥騄胡然甘伏皁。", "君徒俛首不我答，我反慚顔汗如澡。", "丈夫貴富難近窺，一第定非論晚早。", "豈同祖誼名漢朝，位不公卿身已夭。", "何時却掛吳淞帆，霜蟹初肥恰新稻。"]'),
('f031fa53-3023-4346-9aa9-47954eef2ba7','前日以詩贈賈麟進士繼蒙和答而楊蟠從事亦隨次元韵鄙思不休輒復自和二篇  其一','强至','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','賈生俊辯凌諸老，二十漢廷冠插腦。',288,'全唐诗/poet.song.33000.json','["賈生俊辯凌諸老，二十漢廷冠插腦。", "魁奇遠裔空傳家，慘淡壯年翻却掃。", "巧心用過金幾緡，憤淚頃乾玉三抱。", "五湖夢數歸何時，四海形單生不造。", "鄉宴無心聽鹿鳴，時平有口歌魚藻。", "每舒意氣拂劍光，懶把窮通叩蓍草。", "江河飲肺吞阮劉，風月吟腸笑郊島。", "君才慎勿恃晚成，俗態由來尊少好。", "衆人競進皆揠苗，獨子甘貧猶嗜棗。", "囊裝未抵一羽輕，筆力堪支泰山倒。", "閑身自放壠上耕，愁面誰憐澤邊槁。", "幽尋騎馬衫覆韉，冷卧乏氈床露藁。", "無勞兒女憫滯材，豈竟乾坤厄吾道。", "從前平步封公侯，亦有逢辰出輿皁。", "光華聖旦髮可晞，涵泳儒流身已澡。", "收還事業幸未遲，揖取功名須及早。", "不然一世成虛生，雖曰百年如實夭。", "公朝富貴弗汝慳，仕路高車似麻稻。"]'),
('dfc8d30a-d349-4e6b-a385-de8406b5454c','前日以詩贈賈麟進士繼蒙和答而楊蟠從事亦隨次元韵鄙思不休輒復自和二篇  其二','强至','宋','宋诗','song-poetry','','[]','愛君氣幹霜松老，一見相投許肝腦。',288,'全唐诗/poet.song.33000.json','["愛君氣幹霜松老，一見相投許肝腦。", "豈同世上秋葉交，不及歲寒如電掃。", "有才無命三十强，寂寞吟齋膝長抱。", "愁來遍踏公卿門，綻褐不縫誰改造。", "文章直吐元化胚，天樸豈須施斧藻。", "長篇下筆縱立成，一字未曾傷草草。", "辭源奔注吞衆人，有似驚潮沒孤島。", "善君取友論片能，不學常情求百好。", "琢磨六藝相與游，我愧性靈昏椹棗。", "平湖綠凈時招邀，爛熳清尊爲君倒。", "客塗見月凡幾圓，倦馬聲饑奴色槁。", "路傍甲第欺儒冠，奴厭腥肥馬餘藁。", "我疑造物偏膏粱，富貴何緣慳有道。", "貫糜巨室君空囊，朱紫摩肩君衣皁。", "大鵬寧合安尋常，怒翼天池終刷澡。", "功名豈必收目前，兩鬢未銀猶得早。", "顔彭骨朽千萬年，漫與後人論壽夭。", "君其努力攀青雲，盛醉春風釀香稻。"]'),
('b0d9ffc8-bf17-4e35-b8d2-a2201cc50789','題惟晤師斑竹杖','强至','宋','宋诗','song-poetry','','[]','蜀江濯錦含文漪，竹生江岸初綠滋。',192,'全唐诗/poet.song.33000.json','["蜀江濯錦含文漪，竹生江岸初綠滋。", "錦波一浸入竹肌，萬洗不落斑在皮。", "又聞淚點灑舜妃，遺迹漸染傳今時。", "搯不受爪滑可持，隠起高節無屈欹。", "江神雖寶莫自私，煙根忽逐霜刀離。", "截而爲杖得者誰，龐眉大士今一枝。", "斒斕頗與壞衲宜，朝躋山巔暮江湄。", "山備兕虎江蛟螭，爾杖未折莫汝危。", "足力自健無險巇，安用童子兩肩爲。", "當年常竹紋無奇，猶託變化神葛陂。", "况此已是斑龍兒，長恐一旦風雲隨。", "復整頭角還天逵，未必久爲師有之。"]'),
('b3d39e66-f818-4dbc-9f0b-e9a18b668b1a','和禮之喜雪十二韵','强至','宋','宋诗','song-poetry','','[]','水官司冬不舉職，天地當凜氣輒溫。',192,'全唐诗/poet.song.33000.json','["水官司冬不舉職，天地當凜氣輒溫。", "頑風伺隙倒天令，掃蕩不使繁雲屯。", "陰崖邃谷殆窮臘，空有雪意乘朝昏。", "宿荄老玘亦借便，欲洩陽氣芽株根。", "往往百怪竊窺視，思以沴疫傷群元。", "頼吾太守爲民切，百拜默與上帝言。", "臣因視民問農計，亟雪猶可望有年。", "知民所欲弗帝告，安用備位稱守藩。", "至誠一發動天聽，霄垠地堮俄瓊璠。", "混然上下共一色，直疑元氣猶胚渾。", "狂風埋藏反失勢，却授威柄還水官。", "既云豐年在冬雪，豫擬癡腹盈朝餐。"]'),
('9a66ac89-6228-481e-9a74-0ac2436147e3','送關景芬秘書赴山陽尉','强至','宋','宋诗','song-poetry','','[]','峨冠初上童兒首，君已老成予輒友。',288,'全唐诗/poet.song.33000.json','["峨冠初上童兒首，君已老成予輒友。", "肺肝相照二十年，今日不殊前日厚。", "紛紛共笑薄媚徒，對面論心回面否。", "吁君意氣非昔粗，猶著青衫從吏部。", "得官將尉古山陽，有藴無施州縣後。", "山陽楚邑爲最雄，聒聒衆咻千萬口。", "階庭聽命趨上官，守閣使臺靴日走。", "舟車冗客來百須，政逐從違成好醜。", "君才遇事有卷舒，公道當官膽如斗。", "或時畏縮類懦夫，私請不容毫髮受。", "往行素守裨長官，肯到縣廳同木偶。", "頗聞彼俗殊東南，例重市門輕隴畝。", "鹽商茗販白刃隨，切與椎埋破淵藪。", "能聲自可博己知，懶趁庸兒媒左右。", "吳江日暮山川愁，疏樹烟頭排敝帚。", "北帆欲掛傾別觴，還有陰風吹散酒。", "醒難爲別醉幾何，人世無時好分手。", "知君此去忘故園，淮月楚雲惟我有。"]'),
('fc604f3e-c00e-4a8b-9e91-be796a532ac4','送吳判官','强至','宋','宋诗','song-poetry','','[]','雨乾青活淮上山，君領善課趨帝關。',192,'全唐诗/poet.song.33000.json','["雨乾青活淮上山，君領善課趨帝關。", "春風滿路馬足健，翩然征轡不可攀。", "吁君登科越一紀，中又困躓罹苦艱。", "蒼虬垂髯猛虎卧，青衫四十鬢欲斑。", "我疑君胸典籍府，千軸萬卷羅其間。", "聖經賢史及怪說，叩之不已如循環。", "有時啟口論時病，往往憤發涕欲潸。", "位卑道屈志未就，姑以大筆誅雄奸。", "就令君居太史局，猶足上下馬與班。", "剛然古膽貫白日，不爲權貴柔正顔。", "退之常患天地惠，偏向君子懷獨慳。", "高冠大笏盡知己，行矣得意東南還。"]'),
('a04c6987-2fe5-4d33-9f1e-9946954016ca','贈徐君强','强至','宋','宋诗','song-poetry','','[]','浦陽窮僻山縈迴，徐子匹馬窮山來。',256,'全唐诗/poet.song.33000.json','["浦陽窮僻山縈迴，徐子匹馬窮山來。", "十年不見安否外，怪子面黝身紅埃。", "自言壯圖醉無幾，獨有古膽剛不摧。", "日于篇章遣孤憤，袖出巨軸爲我開。", "密行細書幾千字，一一紙上皆瓊瑰。", "渾然天成有警句，直若未剖元氣胚。", "間工磨琢弄纖巧，真宰手把天葩裁。", "詩人古亦少達者，非特徐子如寒灰。", "孟郊老獨張籍瞽，李杜落魄皆何哉。", "剔抉幽秘奪造化，雖甚寒餓天弗哀。", "又疑才命不俱得，既奪之命止與才。", "子今所往但逢蹇，絆驥兩足猶駑駘。", "浦陽山深尚春淺，桃李纔蕊花正梅。", "子時過我值訟簡，花下一飲將百杯。", "酒酣慷慨起勸子，更厲頭角需風雷。", "縱令不偶竟窮死，猶愈空腹冠崔嵬。"]'),
('eb14927e-25fb-483d-bf7b-386d983fc4ec','邑舍東池近日荷花盛開輒書短篇奉邀宗哲純甫二同僚','强至','宋','宋诗','song-poetry','','[]','前時乘暇到池上，荷花未開荷葉小。',96,'全唐诗/poet.song.33000.json','["前時乘暇到池上，荷花未開荷葉小。", "彌旬風雨隔追賞，期會簿領復煩擾。", "今朝始得臨舊堤，花開已繁葉將老。", "古人最謂行樂急，癡兒漫欲官事了。", "錢楊與我近同趣，一樽今待共君倒。", "聯鑣且來趁花飲，莫待紅稀并綠槁。"]'),
('5308757d-056a-418f-b3d8-7c9dcd6e47bf','七夕','强至','宋','宋诗','song-poetry','','[]','七月七日暑氣徂，此夕何夕樂且娛。',224,'全唐诗/poet.song.33000.json','["七月七日暑氣徂，此夕何夕樂且娛。", "世傳牽牛會織女，雨洗雲路迎霞車。", "初因烏鵲致語錯，經歲一會成闊疏。", "牛女怒鵲置諸罪，拔毛髠腦如鉗奴。", "星精會合不可詰，我疑此說終誕虛。", "又言星能遺人巧，羅列瓜果當庭除。", "綵絲貫針望星拜，夜深乞巧勞僮愚。", "吾聞樸散形器作，人奪天巧天無餘。", "匠心女手劇淫巧，工與造化分錙銖。", "薦紳大夫一巧宦，坐取公相如指呼。", "間乘巧言惑主聽，能改荼蘗成甘腴。", "纖辭麗曲騁文巧，剜刻聖道無完塗。", "星如有巧更可乞，益恐薄俗難持扶。", "我願星精遺人拙，一變風化猶古初。"]'),
('ae883702-722a-4da7-8b69-49a49194e3cf','題藴忠上人歙硯','强至','宋','宋诗','song-poetry','','[]','山僧有硯名龍尾，此石來從歙溪水。',168,'全唐诗/poet.song.33000.json','["山僧有硯名龍尾，此石來從歙溪水。", "通明直可照髮毛，瑩滑不容安手指。", "案上長疑片月生，匣中自有浮雲起。", "蒼然顔色涵秋波，不學端州誇嫩紫。", "溪匠琢爲寒瓦形，如從銅雀初飄零。", "只仍故狀不復改，獨有亂點生繁星。", "高閑上人妙書札，什襲藏來時一發。", "拂開輕霧磨烟煤，揮灑霜毫冰紙滑。", "咄嗟此硯何爲哉，世上別有潤色材。", "胡不往焉與徘徊，日濡大筆把詔裁，無久滯此空塵埃。"]'),
('161cea04-2392-4847-90d9-8acb9688eacb','通判國博中齋詩','强至','宋','宋诗','song-poetry','','[]','天下以中爲大本，天地得中能自生。',272,'全唐诗/poet.song.33000.json','["天下以中爲大本，天地得中能自生。", "古之聖賢一用中，政刑禮樂萬事平。", "於戲後世中道喪，政分寬猛刑重輕。", "禮非儉陋則奢僭，樂不專一須鏘鏗。", "其間萬事亦頗僻，或過不及誰與繩。", "今公奮然力追救，大署中字爲齋名。", "謂中之迹不可見，粲焉其道存六經。", "尚書洪範有皇極，春秋王道爲權衡。", "在易之爻貴二五，于詩無邪義甚明。", "子思著篇究根柢，王通命說垂儀刑。", "夜探群書味中理，雞鳴而作還奉行。", "出處語默皆時中，措諸萬事無側傾。", "有時賓至相與樂，咏歌亦作中和聲。", "檐前竹樹有中色，四序不改長青青。", "公今一州貳守政，千里猶變中庸甿。", "異時朝廷贊天子，擴之四海中道成。", "至得攝齊升公齋，一聽中論退服膺。"]'),
('713b3c52-87bf-4acf-8e97-4692baa5a97a','還府推楊學士無爲編','强至','宋','宋诗','song-poetry','','[]','蜀山秀色參天起，子雲文章摩玉壘。',288,'全唐诗/poet.song.33000.json','["蜀山秀色參天起，子雲文章摩玉壘。", "關右衣冠從古名，伯起光華擅楊氏。", "後來氣象幾寂寥，今日西州聞學士。", "吁雄述作擬聖人，蹭蹬三朝官不徙。", "震雖有時無雄文，而又晚齡纔得仕。", "豈知學士丁妙年，一日青雲趨萬里。", "高才大筆驅古今，奄有震雄兼二美。", "布衣平昔抱經綸，浩蕩著書窮日晷。", "幽居獨占無爲山，因以名編仍號子。", "鑿開元氣爭化工，剔出微情泣山鬼。", "先儒浮妄遭芟鋤，直與六經相表裏。", "青衫冗掾錯致身，四十摩肩雜胥史。", "日趨官府舊學荒，已分清流將絕齒。", "前時輒辱授此編，如以咸韶震聾耳。", "夜侵燈燭晝廢餐，若涉江河徐見涘。", "乃知無爲非不爲，道化自行而已矣。", "立朝本此足有施，堯舜吾君那出是。", "天球豈合藏窮家，再拜持編復齋几。"]'),
('bb311f95-8af7-4f82-af94-0ff523c14d2f','謝通判國博惠建茶','强至','宋','宋诗','song-poetry','','[]','建溪春早地未暖，建俗巧計催春陽。',208,'全唐诗/poet.song.33000.json','["建溪春早地未暖，建俗巧計催春陽。", "茶傍萬口噪地烈，驚破芽英不得藏。", "猶嫌旂槍已老硬，獨愛鳥嘴嫩未長。", "擷而焙之一朝就，更範圭璧爲圓方。", "南州尚珍北固重，自非富貴寧預嘗。", "浦陽賤官性怯酒，素許茶味爲最良。", "日分牒訴費齒舌，口吻鎮燥喉無漿。", "建溪奇品遠莫致，日夕夢想馳閩鄉。", "塵埃填心渴欲死，忽拜公賜喜可量。", "拆封碾破蒼玉片，雲脚浮動甌生光。", "愚知公賜豈徒爾，欲俾下吏蠲俗腸。", "滌除詩冗起清思，驅逐睡興窮縑緗。", "玉川不暇盡七碗，已覺兩腋清風翔。"]'),
('b1606fb0-2c67-4ae3-b878-49d6abab34b5','予家畜貍花二貓一日貍者獲鼠未食而花者私竊之以去家人不知以爲鼠自花獲也因感而作二貓詩','强至','宋','宋诗','song-poetry','','[]','貍貓得鼠活未食，戲局之地或前後。',128,'全唐诗/poet.song.33000.json','["貍貓得鼠活未食，戲局之地或前後。", "貓欺鼠困縱不逐，豈防厥類怠其守。", "花貓狡計伺貍怠，帖耳偷銜背之走。", "家人莫究貍所得，只見花銜鼠在口。", "予因竊覘見本末，却笑家人反能否。", "主人養貓不知用，謬薄貍能服花厚。", "花雖利鼠乃欺主，竊貍之功亦花醜。", "人間顛倒常大此，利害于貓復何有。"]'),
('1da2ee55-0d37-442c-9a65-61cfb44bf670','純甫以予去歲九日赴東陽今年復趨府作菊花問答見遺因以戲答  其一','强至','宋','宋诗','song-poetry','','[]','問籬菊，何事秋香欠春馥。',28,'全唐诗/poet.song.33000.json','["問籬菊，何事秋香欠春馥。", "淵明歲歲走征途，冷落重陽誰采劚。"]'),
('be67fbaa-201b-4c33-ac31-d0e1523d5a58','純甫以予去歲九日赴東陽今年復趨府作菊花問答見遺因以戲答  其二','强至','宋','宋诗','song-poetry','','[]','籬菊答，自古人生有離合。',28,'全唐诗/poet.song.33000.json','["籬菊答，自古人生有離合。", "不得淵明泛玉觴，還有子真携酒榼。"]'),
('6ad532ca-bdfe-4a71-9ad5-e4c6a5cac7a0','泉上人畫牡丹','强至','宋','宋诗','song-poetry','','[]','芳樹不合生深堂，座上似已聞生香。',176,'全唐诗/poet.song.33000.json','["芳樹不合生深堂，座上似已聞生香。", "乃知丹青逼造化，獨有真假爭毫芒。", "枝外霏微包雨露，筆迹淋漓濕縑素。", "遊蜂蛺蝶頻往來，今日經營知汝誤。", "蜀川趙昌妙花樹，前後無人昌獨步。", "師今合昌成一人，畫手紛紛那敢措。", "上人筆下如有神，一掃欲空西洛春。", "姚黄魏紫色憔悴，自覺筆假勝天真。", "天工栽花苦榮謝，畫工運巧無冬夏。", "天工巧極誰論價，輸帛傾金只酬畫。", "將令世俗尊造化，呼僮捲障不復掛。"]'),
('aa5d4cb1-b857-4e9f-8a01-74a89edb025a','和樓志國范君武讀胡尉臨安所獲顔魯公書斷碑','强至','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','書名唐世凡幾人，魯公運筆獨有神。',384,'全唐诗/poet.song.33000.json','["書名唐世凡幾人，魯公運筆獨有神。", "當年一字百金直，異代儻獲宜爾珍。", "公嘗道直不容內，江湖出走刺史輪。", "東南揮翰落幾郡，在處巨蹟刊堅珉。", "石堅字巨未應泐，旋復五代遺荒屯。", "州鎮尋兵寺觀火，缺碑毀碣埋泥塵。", "乾坤豈亦愛字寶，不使久屈卒不伸。", "脗合陰假好事手，得此斷石溪山垠。", "苔封土蝕初莫省，一洗爛若開三辰。", "不由名氏驗體法，氣質渾厚知顔筋。", "點端屹如泰山立，畫勁森似長戟陳。", "寧同棗木浪傳刻，少陵尤惡肥失真。", "蒼茫疑聞地靈泣，爲失此石后土貧。", "好事得之不自有，能廣墨本遺其倫。", "始從君武愜傳玩，大句感發驚儒紳。", "寫公勛德無一欠，何必讀史勞吾唇。", "青衫志國繼高唱，首論書法詞逾新。", "末言公忠死賊刃，不覺憤淚霑予巾。", "昔人謂書乃心畫，浮沉直撓皆相循。", "公心遠可此書鑒，體不姿媚一以淳。", "嚴嚴古氣自盤薄，宜汝希烈不得臣。", "雖云筆力奪元化，濟以忠誼重萬鈞。", "後來忠誼弗公學，磨鉛臨帖虛終身。", "李斯篆隸豈不好，彰彰奸迹流自秦。"]'),
('e0da2ab5-88c7-425f-a187-b0e03df21937','送裴光世赴舉','强至','宋','宋诗','song-poetry','','[]','光世出門頭懶回，身將西去犯斗魁。',256,'全唐诗/poet.song.33000.json','["光世出門頭懶回，身將西去犯斗魁。", "風雲自繫鵬鵠健，里道正爲驊騮開。", "憶初鄉賦選主司，數州側腦聽外臺。", "一朝吾鄉騰薦口，姓名喜得丁與裴。", "筆摇試席動千指，匠精反愧木盡材。", "六人既拔里中傑，黑白自可消怨猜。", "君名稍稍近人底，豈是天意激後來。", "主司南宮頃第一，又嘗禮部預揀才。", "頗傷辭律變新進，怪僻一鼓波遂頹。", "既而移書六人者，歷數文弊有可哀。", "且言文章貴體要，試格尤要合準裁。", "六人既拜主司教，青雲捷路知力推。", "方今最曰場屋公，實藝可進那用媒。", "君胸二紀富珍藴，每向紙上揮瓊瑰。", "掛名省壁定顯赫，續取科第仍崔嵬。", "明年躍馬游街塵，請君飲乾臨別杯。"]'),
('bab52f0d-a819-4508-803b-33c1644a698c','走筆送張伯起','强至','宋','宋诗','song-poetry','','[]','男兒剛腸逾古鐵，每到傷離猶暫折。',112,'全唐诗/poet.song.33000.json','["男兒剛腸逾古鐵，每到傷離猶暫折。", "離緒不啻亂繭絲，纔攪衷腸便成結。", "憶昨送子秋風前，薄酒三行歌數闋。", "我歌多感酒易醺，子車爲我澀不發。", "今來與子舉別觴，還是去年分臂日。", "人生歲歲有離恨，爭遣綠鬢不爲雪。", "安得共子並翼飛，四方上下無時別。"]'),
('e9d188c6-46c4-4c76-84e5-48fced45a562','臨洺驛雨中作','强至','宋','宋诗','song-poetry','','[]','朔野無花春意薄，斧聲惟見桑枝落。',112,'全唐诗/poet.song.33000.json','["朔野無花春意薄，斧聲惟見桑枝落。", "北人是日競條桑，手執懿筐共操作。", "客亭繫馬吟寒廳，細雨纏愁牢似縛。", "多情北燕能傍人，如說春心繞疏箔。", "故鄉桃李應滿園，爛熳香風隨處著。", "十年游宦辭江湖，塵土日侵雙鬢惡。", "天涯懷抱傾東南，悶對青燈舉幽酌。"]'),
('a2f3dd3d-ceb6-4fb7-800a-c1a6b4d13e1e','丙午寒食厚卿置酒壓沙寺邀諸君觀梨花獨蘇子由不至以詩來邀席客同作予走筆依韵和之','强至','宋','宋诗','song-poetry','','[]','種梨易長地舊淤，春風一掃無枯株。',224,'全唐诗/poet.song.33000.json','["種梨易長地舊淤，春風一掃無枯株。", "沙頭古寺枕城角，樓殿自與人迹疏。", "看花置酒三月破，點檢座客惟欠蘇。", "酒酣花底不知處，恍若身世游蕊珠。", "銅臺割據古豪盛，樂事已去惟邱墟。", "直須及時結勝賞，莫局官事同轅駒。", "林僧迎我屢前揖，野鳥避客遥相呼。", "咸陽有花遠莫見，豈若此地來須臾。", "風前嗅雪不宜緩，春芳過眼猶奔車。", "繁枝向月合照映，亂片落地無掃除。", "樽邊酩酊不復計，馬上倒載聊拚扶。", "子由閉戶自懶出，花與雙眼知何辜。", "天姿必欲貴純白，紅杏可婢桃可奴。", "君詩險絕不容和，梁園騁思慚相如。"]'),
('2a7e0646-c595-40c8-ba47-c93b4f46ba10','寒食安厚卿具酒饌邀數君子遊壓沙寺觀梨花獨蘇子由不至詩來命座客同賦予既次韵和之明日上巳安復置酒招予與蘇又明日清明予屈二君爲射飲之會而蘇君仍用前韵作詩見及予亦復和','强至','宋','宋诗','song-poetry','','[]','花前爛醉如泥淤，猶恐花過嗟空株。',224,'全唐诗/poet.song.33000.json','["花前爛醉如泥淤，猶恐花過嗟空株。", "壓沙梨開百頃雪，春晚未賞計已疏。", "厚卿置酒趁寒食，蜂喧蝶鬧人意蘇。", "林間把盞誰我侑，鳥歌聲滑如溜珠。", "魏都風流重行樂，艷妝麗服明郊墟。", "我初聞招便勇往，恨不插翼附駿駒。", "峨眉夫子趣獨異，靜坐幕府煩邀呼。", "車公不到座寂寞，大句落紙來須臾。", "樽邊弄筆輒强和，布鼓乃敢當雷車。", "主人明朝復命客，是日禊事修祓除。", "日涵花氣暖不散，酒力易著起要扶。", "清明予亦飲射圃，罰觶屢困辭不辜。", "杯盤一飽藉脫粟，那有白飯餘君奴。", "梨花好在期共醉，功名身外終何如。"]'),
('5feb7cb9-593f-44a1-ba23-39586a0abdd7','送川僧玘上人歸雪竇','强至','宋','宋诗','song-poetry','','[]','釋子群群蹈一轍，類能恐誘鼓師說。',64,'全唐诗/poet.song.33000.json','["釋子群群蹈一轍，類能恐誘鼓師說。", "彼上人者劍外來，獨許清吟調風月。", "就我乞詩歸甬東，三叩賓階通刺謁。", "何時腰下解瓶盂，巖竇應逢先臘雪。"]'),
('e9d06b20-48f5-4ee8-bc83-01a540e6b213','小桃值風零落殆盡偶成鄙句奉呈諸君','强至','宋','宋诗','song-poetry','','[]','小桃庭前祗一株，無數花開艷新繡。',128,'全唐诗/poet.song.33000.json','["小桃庭前祗一株，無數花開艷新繡。", "破蕊脈脈向人笑，鬧枝酣酣索春鬥。", "只見蜜蜂來往喧，不道雙燕共時候。", "醉吟繞花日幾遭，坐卧欲來花下就。", "東風昨夜忽顛狂，曉枝點檢不依舊。", "惜無錦帳闊百步，遮藏免被風力驟。", "小兒地上拾亂片，猶愛殘香再三嗅。", "桃兮開落奈汝何，却取餘杯醉春晝。"]'),
('8b8aab5b-e4c4-4aa0-a799-08265b8dd0ca','近承楊子遣垂和池上短篇愛而有贈且攄予懷','强至','宋','宋诗','song-poetry','','[]','楊子文格少已遒，自關以西鮮此流。',344,'全唐诗/poet.song.33000.json','["楊子文格少已遒，自關以西鮮此流。", "逸興一發不言休，詩吟千篇酒百甌。", "始謂富貴力可求，行年四十差厥謀。", "相逢渭水初清秋，氣俊秋隼辭長虬。", "歡然一見分輒投，往來自爾月屢周。", "忽聞屋角鳴春鳩，感時出門寫我憂。", "載酒興慶荒池頭，半酣繫馬聊登舟。", "紛紛涉水驚眠鷗，晚陽欲落孤煙收。", "開元盛事空林丘，流年數百如回眸。", "陳迹隨感來吟搜，偶作短句詒同遊。", "楊子既見遽和酬，筆落紙上不暫留，詩珍玉案書銀鈎。", "詩人乃是天地讎，造化萬物遭剜鎪。", "天公報之甚操矛，少使稱遂多窮愁。", "子嘗兩舉試此州，病坐試席出則瘳。", "筆力健可掣十牛，及與命鬥力弗侔，翻被命屈豈自由。", "嗟予所學淺以浮，不與造化爲怨仇。", "胡然天公亦我尤，剛腸勁貌寡媚柔。", "觸忤貴勢在轉喉。", "蒼顔常調祗自羞，使看平步趨公侯。", "子來我語徒啾啾，天高聽卑誠謬悠。", "不若且默真良籌，有酒一醉春風樓。"]'),
('947affb0-860f-418c-9b88-b96d047533d8','送李去病楊元老','强至','宋','宋诗','song-poetry','','[]','君王赫怒超前古，威令風馳奮皇武。',192,'全唐诗/poet.song.33000.json','["君王赫怒超前古，威令風馳奮皇武。", "將士咸懷敵愾心，桓桓孰可當貔虎。", "岷峨橫抹西南坤，河池散關當北門。", "堅城高寨礙飛鳥，天兵百萬方雲屯。", "給軍自古資巴蜀，接軫連檣轉芻粟。", "正須將漕得其人，賦役平均軍食足。", "三分才具超常倫，不獨摛藻追淵雲。", "究宣德意可預見，抉剔奸蠹蘇疲民。", "使星入蜀今重應，芒寒色正相輝映。", "川合東西幾萬家，佇瞻玉節交相慶。", "行聞盡錄平戎功，給餉正與提兵同。", "紫泥封詔看西去，歸來聯騎朝王宮。"]'),
('4bd03439-8939-4bf6-817d-b42e5d9282bb','賣松翁','强至','宋','宋诗','song-poetry','','[]','窮山老松幹百尺，縱有愛者勢難值。',272,'全唐诗/poet.song.33000.json','["窮山老松幹百尺，縱有愛者勢難值。", "小松聳擢未及丈，何亦冷落守巖石。", "由來世眼習繁侈，競事妖紅與爛白。", "往往破産聚名卉，未見有一號松癖。", "城中有客賣桃李，美價高下隨意得。", "咄嗟彼叟何爲者，浪負松本窮九陌。", "行求善價吻欲燥，力弛還立朱門側。", "過之千百絕一顧，寧復肯許一錢直。", "音聲猶带澗風澀，顔色尚染嵐煙黑。", "松材雖良人未見，其奈桃李有春色。", "嗟哉子計信疏矣，豈宜肩入芳菲域。", "速培舊土養松幹，待棟明堂柱帝宅。", "予疑叟非鬻松者，無乃矯世爲所特。", "衆趨時好逞穠艷，何獨孑孑衒皴碧。", "群雄馳騁尚譎詐，軻以仁義游六國。", "時乎釋老肆分籍，愈以原道破群惑。", "叟乎叟乎予爾知，獨行矯世難爲力。"]'),
('022d5dfa-a808-4b41-8017-d2666caf5cb8','與盛毅同賦暮角行','强至','宋','宋诗','song-poetry','','[]','城頭滾滾寒烟起，城裏無人冷如水。',124,'全唐诗/poet.song.33000.json','["城頭滾滾寒烟起，城裏無人冷如水。", "一聲暮角聒地來，聲中宛轉含餘哀。", "逡巡流入單于調，耳邊似近單于臺。", "坐客未終聽，對面淚雙迸。", "那復將軍絕塞眠，朔風吹落玉帳邊。", "狼烟未盡不待曉，恨不立起銘燕然。", "何人始製角中曲，幽怨到今傳不足。", "吁嗟畫角終無情，百年日月銷此聲。"]'),
('dad85644-e10d-4b79-9084-5e4ba45c555b','冬雪行','强至','宋','宋诗','song-poetry','','[]','幼年壯氣寒逾熱，更喜朱顔照飛雪。',128,'全唐诗/poet.song.33000.json','["幼年壯氣寒逾熱，更喜朱顔照飛雪。", "門前地厚堆玉塵，屐齒千回狂走折。", "今來過壯能幾秋，眼未見雪心先愁。", "病膚隠粟出門懶，敝袍盡日紅爐頭。", "此身知更十年後，雪屋能如今坐否。", "層衾沒頷定晝眠，那復吟邊開凍口。", "壯齡衮衮洪濤奔，百年浩蕩未易論。", "人間萬事亦顛倒，且對今雪空清樽。"]'),
('b37b61c3-e7ad-479f-8d18-da1d029632dc','送盛君方','强至','宋','宋诗','song-poetry','','[]','秋風木葉飛邊徼，日暮銅臺別杯釂。',224,'全唐诗/poet.song.33000.json','["秋風木葉飛邊徼，日暮銅臺別杯釂。", "燕姬一曲聲未終，交臂方携忽南棹。", "相公鎮魏從辟書，玉帳三年奉談笑。", "密謀直道裨主人，飽食庸兒或陰誚。", "君殊不顧但自若，烱烱誠心復誰照。", "相公還朝數論薦，援手無人在廊廟。", "薦章未報人事改，魏國門前客相弔。", "聖賢尚覬後世知，萬事那能目前料。", "方今擢才不待次，道路紛紛走嚴召。", "朝廷必欲收真才，豈有如君使常調。", "讀書適用非苟知，脫略空言直趨要。", "有餘利刃未一施，可惜青萍反居鞘。", "誰能出力終提携，會看驚人露芒耀。", "君如弗偶好言命，予亦徐當卜耕釣。"]'),
('4b63c648-7096-462c-b947-e435c756dcc1','送知府吳龍圖','强至','宋','宋诗','song-poetry','','[]','國初以來治蜀者，處置盡自乖崖公。',320,'全唐诗/poet.song.33000.json','["國初以來治蜀者，處置盡自乖崖公。", "當時奏使便宜敕，不與天下州府同。", "行之已及八十載，奸宄銷伏誰之功。", "因循至此漸抏敝，有未曉者時相攻。", "鞭笞小罪亦檢察，不許略出常科中。", "下民知之頗不懼，州縣往往藏群凶。", "側身斂足未動者，實以累朝恩澤隆。", "公之初來蜀人喜，慈愛久著民情通。", "衆心歡然恥犯法，捄藥浮薄歸醇醲。", "盡將約束付僚吏，興起學校還文翁。", "二年美化極沾洽，遠近循服如偃風。", "上將歸公問誰代，當使間作如笙鏞。", "遂求元老得青社，其人廊廟之宗工。", "往年鎮撫有異績，大旆再來遣于東。", "公今與之合符去，到必奉詔參夔龍。", "大資舊德固無慮，剖判自出其心胸。", "所憂厥後嗣之者，忠定良法還如空。", "養頑活狡作淵藪，不免剪殄煩興戎。", "蒙之憤懣久填臆，言賤不得通九重。", "頌公上殿起居罷，第一用此聞宸聰。"]'),
('6d539d64-3ea3-46fe-81f4-20b8d896fc22','京師逢徐良溫叟明府','强至','宋','宋诗','song-poetry','','[]','弱冠相逢今四十，當年壯氣虬龍蟄。',64,'全唐诗/poet.song.33000.json','["弱冠相逢今四十，當年壯氣虬龍蟄。", "交情獨在酒盞深，人事細論衣袖濕。", "詩書誤身浪自憐，公相滿眼誰可揖。", "蒼顔已變長安風，後會更應尤戢戢。"]'),
('ee4927a7-5154-472e-ae2b-2a2eede7f0f4','小疾中元恕相別往長安信筆成篇奉送','强至','宋','宋诗','song-poetry','','[]','一春三月少見晴，濕雲不飛壓花老。',128,'全唐诗/poet.song.33000.json','["一春三月少見晴，濕雲不飛壓花老。", "君來別我西出關，病裏傷離似翁媼。", "和風吹面纔幾程，即入風流洛陽道。", "司農水利無留行，洛城花開爲誰好。", "漢唐陳迹到可尋，猶有山川豁懷抱。", "憶昨行春從魏公，興慶池邊玉樽倒。", "公今已爲泉下游，往事憑君問煙草。", "官家諸路急使才，歸對明光切須早。"]'),
('05669761-0be1-4e83-bd62-40fd22e670dc','題可久上人房素屏','强至','宋','宋诗','song-poetry','','[]','雕軒畫室吳僧居，花草禽魚屏面集。',128,'全唐诗/poet.song.33000.json','["雕軒畫室吳僧居，花草禽魚屏面集。", "豈如蕭爽大士堂，雪山數尺平頭立。", "滿齋虛白已自生，隔坐紛華不容入。", "霜毫一掃都無痕，獨有淋漓粉光濕。", "好丹世上空紜紜，趣與師同百無十。", "常時吟客惟我來，共愛此屏微靜翕。", "目睛難駐手試捫，指下琉璃無寸澀。", "願乘醉筆留幾行，爲寫高僧白雲什。"]'),
('77f7cc80-d048-4897-a41f-b63e55d85851','送王賓玉','强至','宋','宋诗','song-poetry','','[]','相如昔乘使者車，縣令負弩當前驅。',240,'全唐诗/poet.song.33000.json','["相如昔乘使者車，縣令負弩當前驅。", "頗矜意氣誇里閭，檄詞爛熳肆欺誣。", "歸來不說民饑臞，餘佞更留封禪書。", "江山清絕冠天區，豈甘久被斯人汙。", "邇來炳靈軼古初，耆俊相繼馳亨衢。", "堂堂御史今名儒，志節慷慨忠義俱。", "才高識遠器有餘，不似文園淺丈夫。", "一朝持節歸成都，使星皎皎臨坤隅。", "輟從憲府恩意殊，霜威鶚擊正所須。", "奸胥所在察于荼，交券計斤良可吁。", "鋤凶芟穢忌踟躕，元惡須行七日誅。", "惡除惠澤益霑濡，頓使枯瘠都豐腴。", "坐茵未暖氈氍毹，詔歸還直承明廬。", "朝廷急賢恢遠圖，碧雞金馬不用渠。", "以人報國功難逾，諸生中有何武無。"]'),
('526b82cd-abcd-4f41-ace9-41fce5cf26f4','謝三門提舉輦運宋叔達郎中寄古碑雜言','强至','宋','宋诗','song-poetry','','[]','長安古名都，漢唐以來帝王宅。',282,'全唐诗/poet.song.33000.json','["長安古名都，漢唐以來帝王宅。", "當時高冠大带接迹公卿間，聲名大半文章伯。", "能書萬變軼出意象外，那跼體法就常格。", "傑詞精翰在處勒琬琰，從此關西富碑石。", "咸陽原頭螭蟠龜負不知數，風雨皴剝塵土蝕。", "荒郊壞宇大者卧榛莽，小者老祠佛廟往往龕屋壁。", "憶初來長安，于此心頗溺。", "朝披夕購自忘倦，一紙不吝百金易。", "豈惟讀辭玩點畫，漢唐往事皆歷歷。", "始者累一以至百，今既累百至千未免廣搜覓。", "古人載書兼兩懼猜謗，今我車載不足更囊積。", "中郎知我有碑癖，封寄數本跨數驛。", "中郎中郎雖欲遂愚癖，愚也字學不進。", "文格不長，翻愧嗜此苦無益。", "雖然古人亦或有所嗜，又恐一朝捨此愚意無以適。", "碑乎誓將蓄汝永吾好，不已聖猶賢博奕。"]'),
('55acb9c5-bcef-402f-8a6f-89d37613aa3e','李花','强至','宋','宋诗','song-poetry','','[]','地暖春纔半，蹊深氣已暄。',48,'全唐诗/poet.song.33000.json','["地暖春纔半，蹊深氣已暄。", "風光何處好，雪浪此時翻。", "勻似金刀翦，裝成玉杖繁。", "夭桃漫相壓，吏部竟誰言。"]'),
('5b9264ea-6eab-4caa-8202-67b6ae41816f','曉鐘','强至','宋','宋诗','song-poetry','','[]','縹緲驚春夢，鏗轟送曉聲。',48,'全唐诗/poet.song.33000.json','["縹緲驚春夢，鏗轟送曉聲。", "敲烟出野寺，催月下山城。", "窗映東方白，燈留半壁明。", "隠然餘韵在，群動已營營。"]'),
('76dbc5c8-1ccf-4a84-9127-aa3a23ab4dee','閏月晦日','强至','宋','宋诗','song-poetry','','[]','乾坤一傳舍，日月兩征輪。',48,'全唐诗/poet.song.33000.json','["乾坤一傳舍，日月兩征輪。", "邂逅逢餘閏，連綿送晚春。", "巢邊迎燕熟，枝上數花頻。", "漸暖茅檐日，吾將理葛巾。"]'),
('3a1352f3-1112-470d-9232-26cc5e948ded','落花','强至','宋','宋诗','song-poetry','','[]','林間花自飛，物理不應悲。',48,'全唐诗/poet.song.33000.json','["林間花自飛，物理不應悲。", "偶對飄殘地，休論艷發時。", "有情香水面，無數點河湄。", "蜂蝶含餘意，徘徊繞舊枝。"]'),
('324e5de5-6110-4c15-88bb-c49a579909e4','因訪楊公濟遂同步野夫家省其母野夫時就試南宮','强至','宋','宋诗','song-poetry','','[]','馬繫揚雄宅，門過孟母鄰。',48,'全唐诗/poet.song.33000.json','["馬繫揚雄宅，門過孟母鄰。", "升堂予獨拜，同井子兼親。", "萬卷先生富，千金舊産貧。", "早將安穩字，去慰杏園春。"]'),
('fbb8140b-c3be-4b7a-8f3c-c9964b4f1d44','同楊公濟賦破山得開字','强至','宋','宋诗','song-poetry','','[]','無物終天地，青山豈免開。',48,'全唐诗/poet.song.33000.json','["無物終天地，青山豈免開。", "萬人鑱秀骨，一氣失全胚。", "漫貯崇朝雨，猶防浩劫灰。", "何年巨靈手，曾此擘崔嵬。"]'),
('d64d8fbb-1edd-47aa-85da-a0a52f0f60b1','同楊公濟賦晚過西村','强至','宋','宋诗','song-poetry','','[]','空影倒波面，晚陽留樹梢。',48,'全唐诗/poet.song.33000.json','["空影倒波面，晚陽留樹梢。", "人煙青近郭，鳥道暗長郊。", "世外空搔首，溪邊懶結茅。", "滄浪那敢羨，漁父定吾嘲。"]'),
('801f826d-de5a-4540-b5f9-5e00cd983d86','苦雨','强至','宋','宋诗','song-poetry','','[]','雨脚灑不斷，魚龍沸巨溟。',48,'全唐诗/poet.song.33000.json','["雨脚灑不斷，魚龍沸巨溟。", "浮泥溢平地，暴水入中庭。", "門巷絕尋訪，壺觴誰醉醒。", "頑雲速收斂，渴欲睹天晴。"]'),
('84777cc2-353f-4602-abd2-2a9d05518c1e','螢','强至','宋','宋诗','song-poetry','','[]','幸藉炎蒸力，因遷腐草蹤。',48,'全唐诗/poet.song.33000.json','["幸藉炎蒸力，因遷腐草蹤。", "清宵能自照，暗室肯相容。", "雨巷幽光晦，風簾亂點重。", "臨書方汝頼，惟恐有鳴蛬。"]'),
('cca7467b-a624-49be-a143-3a3c3b0355d1','種藥','强至','宋','宋诗','song-poetry','','[]','百藥吾誰辨，農皇舊有經。',48,'全唐诗/poet.song.33000.json','["百藥吾誰辨，農皇舊有經。", "傾金購善種，按譜驗真形。", "易地防根瘦，他時欲劑靈。", "天時縱不雨，灌溉頼園丁。"]'),
('8d22e1b8-4f5c-459a-b8dc-5873fda075fa','贈於潛張定國','强至','宋','宋诗','song-poetry','','[]','蕭散前川令，才高氣亦剛。',48,'全唐诗/poet.song.33000.json','["蕭散前川令，才高氣亦剛。", "學攻諸子短，能涉衆人長。", "日月銷書卷，功名撫劍鋩。", "他年有大用，莫漫比柴桑。"]'),
('6eb67dec-2f53-49af-8427-499e58f0612f','某近與和叔游景愛之不足因吟短篇以贈','强至','宋','宋诗','song-poetry','','[]','夫子南州傑，相逢出肺肝。',48,'全唐诗/poet.song.33000.json','["夫子南州傑，相逢出肺肝。", "平生潛聖閫，壯歲尚儒冠。", "鴟鷃霄垠擊，蛟龍井底蟠。", "恥將孤憤劍，容易向人彈。"]'),
('a463cb6e-b163-4470-8faa-1c38afe50519','贈李熊先輩二首  其一','强至','宋','宋诗','song-poetry','','[]','崷崒閩人秀，夫君得最完。',48,'全唐诗/poet.song.33000.json','["崷崒閩人秀，夫君得最完。", "文章醇不雜，氣質渾無刓。", "場屋聞新詔，鄉閭正素冠。", "天應老賢業，頭角壯年蟠。"]'),
('255fbf22-41df-4049-ac7a-22f429a0761e','贈李熊先輩二首  其二','强至','宋','宋诗','song-poetry','','[]','詔書一日至，多士競軒眉。',48,'全唐诗/poet.song.33000.json','["詔書一日至，多士競軒眉。", "獨有儒林傑，方纏風樹悲。", "饑腸惟飽學，正口絕柔辭。", "從古器大者，於中成就遲。"]'),
('2e5bc6f0-ecc7-4737-aa7f-64c6700a3c80','與王仲密諸君泛湖','强至','宋','宋诗','song-poetry','','[]','十月清霜後，孤舟顥氣間。',48,'全唐诗/poet.song.33000.json','["十月清霜後，孤舟顥氣間。", "酒邊頹白日，棹底倒青山。", "境勝歡憂泯，吟頻物象慳。", "吾儕一笑後，魚鳥伴誰閒。"]'),
('2778d0ee-0ad4-4dd2-ba23-93dc259d5b06','急棹趁吳門','强至','宋','宋诗','song-poetry','','[]','寒日山尖落，孤烟樹杪屯。',48,'全唐诗/poet.song.33000.json','["寒日山尖落，孤烟樹杪屯。", "水流天欲動，舟急岸如奔。", "縹緲穿雲角，蒼茫望郭門。", "片心爭宿鳥，去去近黄昏。"]'),
('67361351-6fac-46e7-a9a5-b56a1fd4512f','初入汴','强至','宋','宋诗','song-poetry','','[]','山勢隨淮斷，河流带地渾。',48,'全唐诗/poet.song.33000.json','["山勢隨淮斷，河流带地渾。", "嚴風疏樹影，落日露沙痕。", "客興雙蓬鬢，吟懷一酒尊。", "舟行那敢緩，霜意滿乾坤。"]'),
('db8bd9a4-14a8-4c97-b84a-22724df3361f','新鶑','强至','宋','宋诗','song-poetry','','[]','未見攀花宿，纔聞隔葉歌。',48,'全唐诗/poet.song.33000.json','["未見攀花宿，纔聞隔葉歌。", "可憐毛羽細，莫怪語言多。", "匹馬春風路，輕舟夜月波。", "數聲來入耳，最奈客愁何。"]'),
('f7d7bfff-cd0b-4034-8812-bb2594cb8724','轂下春日','强至','宋','宋诗','song-poetry','','[]','楊柳長安陌，游車錦繡香。',48,'全唐诗/poet.song.33000.json','["楊柳長安陌，游車錦繡香。", "漫傾春日酒，誤入少年場。", "意氣青雲客，風流白面郎。", "致身愁獨晚，檢點鬢毛蒼。"]'),
('55f39f7a-41fa-45b8-a955-3db9a921822f','寒食前二日對雨','强至','宋','宋诗','song-poetry','','[]','紅濕花枝軟，青涵柳色鮮。',48,'全唐诗/poet.song.33000.json','["紅濕花枝軟，青涵柳色鮮。", "未開新禁火，自起欲晴煙。", "坐卧銷佳節，招尋憶舊年。", "故鄉游樂地，心折泛湖船。"]'),
('4cf9ea54-0808-428c-8f9c-4379a40ccc96','對雨寄楊公濟','强至','宋','宋诗','song-poetry','','[]','江海歲云晏，雨冥風自凄。',48,'全唐诗/poet.song.33000.json','["江海歲云晏，雨冥風自凄。", "葉光群木洗，翅濕幾禽低。", "靜榻欹寒枕，孤城隠暮鼙。", "少陵車馬客，催踏草堂泥。"]'),
('3505097c-1287-4af2-9ebc-eeb32475b435','雨中呈丁評事','强至','宋','宋诗','song-poetry','','[]','騷雅丁夫子，年來客路岐。',48,'全唐诗/poet.song.33000.json','["騷雅丁夫子，年來客路岐。", "故關春夢後，獨館雨留時。", "詩有龜兒掌，游須驥子隨。", "君家千歲鶴，應解念歸遲。"]'),
('b4c44261-b622-414a-938a-bff361e8d298','歸鳥','强至','宋','宋诗','song-poetry','','[]','日落群山靜，天寒獨鳥歸。',48,'全唐诗/poet.song.33000.json','["日落群山靜，天寒獨鳥歸。", "聲悲故巢遠，影入片雲微。", "蹤迹憐吾滯，青冥羨汝飛。", "莫爲雙翼誤，須避暗中機。"]'),
('791e21ab-a5de-46aa-a590-500d68546f78','宿慧安院','强至','宋','宋诗','song-poetry','','[]','積淖厭行路，解鞍欣曲肱。',48,'全唐诗/poet.song.33000.json','["積淖厭行路，解鞍欣曲肱。", "疾風穿敝屋，細雨濕青燈。", "聒夜有饑鼠，觀空無定僧。", "中宵塵累息，山水思填膺。"]'),
('812f488e-d86f-4b62-b01e-29f6d329912f','九日病中泊舟召伯堰','强至','宋','宋诗','song-poetry','','[]','采采南山菊，還應滿故園。',48,'全唐诗/poet.song.33000.json','["采采南山菊，還應滿故園。", "全家泊孤埭，多病負清樽。", "木末秋聲老，天涯雨氣昏。", "鄉關吟望外，愁淚有雙痕。"]'),
('a059d3d1-365a-480f-985c-c157b6eb32c9','某爲府曹伏蒙吳先生以詩見寄謹依韵奉酬','强至','宋','宋诗','song-poetry','','[]','瘦馬風埃裏，蕭疏分亦安。',48,'全唐诗/poet.song.33000.json','["瘦馬風埃裏，蕭疏分亦安。", "閒趨京兆尹，冷甚廣文官。", "錦繡頒詩句，松筠映歲寒。", "天邊師坐闊，南望祇長嘆。"]'),
('9e46dbe4-79a9-409f-a59d-5e7684f11e6c','同盛任道賦暮陰','强至','宋','宋诗','song-poetry','','[]','野館臨空闊，江城起暮寒。',48,'全唐诗/poet.song.33000.json','["野館臨空闊，江城起暮寒。", "年光去天末，雪意上雲端。", "自失歸禽影，能侵病客肝。", "莫將愁對景，入夜轉漫漫。"]'),
('40e608e8-d147-4871-84a0-164f0a1989de','次韵禮之齋中述懷','强至','宋','宋诗','song-poetry','','[]','僻坐治孤學，取書窺古人。',48,'全唐诗/poet.song.33000.json','["僻坐治孤學，取書窺古人。", "高風凜如在，千載邈相親。", "欲滿詩書腹，寧規富貴身。", "獨君知己厚，無亦慮吾貧。"]'),
('242cfa37-06ff-40fa-bb25-38dc9624d4d4','春雨一篇呈純甫賢僚縣庠諸彥','强至','宋','宋诗','song-poetry','','[]','漠漠陰常結，垂垂勢未收。',48,'全唐诗/poet.song.33000.json','["漠漠陰常結，垂垂勢未收。", "潤多宜土脈，落久驗溪流。", "與物知無間，於花似有讎。", "少年車馬客，惆悵爲君游。"]'),
('4059c43f-901c-4ed5-b921-642f321a6653','二月大寒偶書短句','强至','宋','宋诗','song-poetry','','[]','上天誰與問，四序曷相干。',48,'全唐诗/poet.song.33000.json','["上天誰與問，四序曷相干。", "已季春成暮，當溫氣反寒。", "農心憂地凍，俗眼惜花殘。", "我豈殊民意，身爲父母官。"]'),
('4594bdde-04a3-4e48-af58-5003484c3cc3','經春罕嘗見花今出湖上悉已離披','强至','宋','宋诗','song-poetry','','[]','飛花何太急，春在豈須忙。',48,'全唐诗/poet.song.33000.json','["飛花何太急，春在豈須忙。", "亂點不經眼，殘枝猶斷腸。", "愁看湖色浄，怯照鬢毛霜。", "回首壯遊地，幽襟付淺觴。"]'),
('5d5817bc-898c-4458-ab1d-ca3d7542433b','山中遇雨','强至','宋','宋诗','song-poetry','','[]','馬上凉秋雨，隨愁入亂山。',48,'全唐诗/poet.song.33000.json','["馬上凉秋雨，隨愁入亂山。", "垂垂衣袖重，點點鬢毛斑。", "猿鳥寒聲外，漁樵古畫間。", "片時全嶺暗，急趁暮鐘還。"]'),
('12f09014-3728-4f7b-87b9-802f98deb8b7','純甫小池生雙蓮','强至','宋','宋诗','song-poetry','','[]','造化有詭異，雙蕖共萼翻。',48,'全唐诗/poet.song.33000.json','["造化有詭異，雙蕖共萼翻。", "凌波洛神艷，泣竹舜妃魂。", "得所雖欣地，猶孤尚笑根。", "聖朝不言瑞，圖獻恨無門。"]'),
('7350c063-1cfc-4636-93e6-7affe688dd77','和純甫獨往至德上方避暑','强至','宋','宋诗','song-poetry','','[]','敝屋數楹隘，炎曦一線長。',48,'全唐诗/poet.song.33000.json','["敝屋數楹隘，炎曦一線長。", "梅仙厭煩溽，蕭寺得清凉。", "山鳥聒幽耳，澗泉蠲渴腸。", "茲遊君獨勝，河朔浪飛觴。"]'),
('19a075b4-b060-45bc-ae3a-91f6749d7a29','通判國博惠建茶且有對啜之戲因以奉謝','强至','宋','宋诗','song-poetry','','[]','數餠建溪春，求逾尺璧珍。',48,'全唐诗/poet.song.33000.json','["數餠建溪春，求逾尺璧珍。", "封從鄉國遠，惠與郡僚均。", "午榻忘搘臂，晨觴厭啟唇。", "拜嘉當對啜，相待况如賓。"]'),
('8080b414-f672-4d5e-b0c9-33c68ad7660d','書窗','强至','宋','宋诗','song-poetry','','[]','一室微吟地，開窗更欲虛。',48,'全唐诗/poet.song.33000.json','["一室微吟地，開窗更欲虛。", "入雲驚紙破，照月愛櫺疏。", "野色連朝夕，秋光滿屋廬。", "何如謝太守，遠岫獨相於。"]'),
('94408627-0b9c-440f-aec0-5b3cd1442e27','寄題張殿直長春亭','强至','宋','宋诗','song-poetry','','[]','甲第俯河湄，修亭面勢宜。',48,'全唐诗/poet.song.33000.json','["甲第俯河湄，修亭面勢宜。", "琴樽長有樂，草木似無衰。", "境勝青山敵，心閒白日遲。", "祖良迷大隠，獨與赤松期。"]'),
('2757d83a-c9d8-43c3-bbdb-0ab6edb776c2','寄題郭明府寺丞潁上西齋','强至','宋','宋诗','song-poetry','','[]','退築謀何早，閑居興頗濃。',48,'全唐诗/poet.song.33000.json','["退築謀何早，閑居興頗濃。", "渠流通潁派，窗列隔淮峰。", "玉麈談賓盛，牙籤載籍重。", "雨巾時墊角，一代慕林宗。"]'),
('f4e16b54-2342-40ed-8041-af8b37fdf3f5','奉答雅均途中見寄二首  其一','强至','宋','宋诗','song-poetry','','[]','濁流非猛激，無以頓澄明。',48,'全唐诗/poet.song.33000.json','["濁流非猛激，無以頓澄明。", "此邑先膏潤，今予力潔清。", "人皆疑矯行，君獨照真誠。", "一得途中什，譊譊衆口平。"]'),
('a6128a11-d214-4c7d-8846-349333f87e55','奉答雅均途中見寄二首  其二','强至','宋','宋诗','song-poetry','','[]','貧固誠吾分，廉斯亦士常。',48,'全唐诗/poet.song.33000.json','["貧固誠吾分，廉斯亦士常。", "漫多愚執守，愧少子文章。", "雖幸相逢近，猶嗟此別長。", "何時却南轡，重把論詩觴。"]'),
('f9e7bea1-4f1c-4636-a796-621dab136f3d','觀棋','强至','宋','宋诗','song-poetry','','[]','鬥智不鬥力，一枰思解圍。',48,'全唐诗/poet.song.33000.json','["鬥智不鬥力，一枰思解圍。", "防人甚勍敵，平地有危機。", "蝸角爭先後，狼心競是非。", "傍觀縮手者，往往見精微。"]'),
('e0831574-7557-40ae-b089-9c5e274451a1','九日過後漫題堂前雙菊','强至','宋','宋诗','song-poetry','','[]','花日金相照，條風翠競翻。',48,'全唐诗/poet.song.33000.json','["花日金相照，條風翠競翻。", "誰言羞晚艷，自喜勝孤根。", "客土深培力，家人一溉恩。", "秋香真好在，未易負清樽。"]'),
('ef221b00-f64c-49ec-89c1-0cd9e57f59e5','和純甫紅葉','强至','宋','宋诗','song-poetry','','[]','秋園無艷色，特地起西風。',48,'全唐诗/poet.song.33000.json','["秋園無艷色，特地起西風。", "間向煙林翠，時呈霜片紅。", "霞光青漢襯，燈炬碧紗籠。", "不解隨松柏，染裁煩化工。"]'),
('4bd2399c-27dd-47cc-9989-b164435ff891','再次韵和純甫紅葉之什','强至','宋','宋诗','song-poetry','','[]','徒密嗤翠幄，有文殊紫屏。',48,'全唐诗/poet.song.33000.json','["徒密嗤翠幄，有文殊紫屏。", "因霜變顔色，點樹作丹青。", "廢苑掃還聚，疏林生易形。", "秋風無別艷，祝爾莫飄零。"]'),
('38bcaf90-3554-4d76-ad5b-70036b2b03de','挺山道中早行有感二首  其一','强至','宋','宋诗','song-poetry','','[]','晨興事行役，寸祿此時輕。',48,'全唐诗/poet.song.33000.json','["晨興事行役，寸祿此時輕。", "撲面風霜緊，隔林鷄犬鳴。", "遥天分淡色，殘月露微明。", "便欲投簪去，無田可力耕。"]'),
('ed12f44c-6ddc-4fc8-8a2a-c5eacaf9f1dd','挺山道中早行有感二首  其二','强至','宋','宋诗','song-poetry','','[]','山驛孤燈盡，霜天片月低。',48,'全唐诗/poet.song.33000.json','["山驛孤燈盡，霜天片月低。", "還家人自喜，戀櫪馬頻嘶。", "野水分微白，巢禽驚穩棲。", "前村應曙色，依約數聲雞。"]'),
('6fd902c8-b9e1-4de8-86f5-16a7e97d6310','宿山寺','强至','宋','宋诗','song-poetry','','[]','蒼莽窮山路，蕭森古寺門。',48,'全唐诗/poet.song.33000.json','["蒼莽窮山路，蕭森古寺門。", "夢深宵殿月，淚迸曉枝猨。", "人事隨群動，山情阻細論。", "城中塵沒眼，愁思滿歸軒。"]'),
('079c7de0-2226-4938-aa40-e5397a0a0b3c','某承乏東陽周親惠然顧訪未幾告別以詩餞之','强至','宋','宋诗','song-poetry','','[]','親戚富貴合，賤貧宜見疏。',48,'全唐诗/poet.song.33000.json','["親戚富貴合，賤貧宜見疏。", "獨君從遠道，爲我枉高車。", "相得未逾月，薄言還故廬。", "風霜正凄暮，臨別尚躊躇。"]'),
('105f6b80-cd61-41f1-b49c-59e6e0951388','晚登至德上方偶書短篇呈山主雲公','强至','宋','宋诗','song-poetry','','[]','城市隔半舍，好山寧在深。',48,'全唐诗/poet.song.33000.json','["城市隔半舍，好山寧在深。", "亂雲歸別塢，落日照疏林。", "能解外緣縛，始堅安住心。", "冠裳方我誘，漫作愛山吟。"]'),
('73f6fd64-19ad-4342-8811-b5fe7b34efb2','離東坡後寄題義師上方','强至','宋','宋诗','song-poetry','','[]','山水東陽富，僧居更翠微。',48,'全唐诗/poet.song.33000.json','["山水東陽富，僧居更翠微。", "晴峰露秋骨，古樹減煙圍。", "啼鳥遠相應，孤蜂閑自歸。", "予生秉幽尚，夢想在禪扉。"]'),
('df3090ca-f032-46e8-bd7c-282825c50f06','劉叔茂及第後往廣德拜親過吳江新治','强至','宋','宋诗','song-poetry','','[]','今歲同升客，如君有幾人。',48,'全唐诗/poet.song.33000.json','["今歲同升客，如君有幾人。", "青年登一第，白首具雙親。", "喜氣生軍壘，歡迎聚邑民。", "諸兄在天祿，勉去繼清塵。"]'),
('fa764343-33e2-476b-af2e-493547179829','惠山泉','强至','宋','宋诗','song-poetry','','[]','封寄晉陵船，東南第一泉。',48,'全唐诗/poet.song.33000.json','["封寄晉陵船，東南第一泉。", "出瓶雲液碎，落鼎月波圓。", "正味云誰別，繁聲祇自憐。", "要須茶品對，合煮建溪先。"]'),
('287a6e43-4003-4d33-b3c9-9c48f0f8f6c0','官滿將見舍弟','强至','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三歲別吾弟，今歸心始降。',48,'全唐诗/poet.song.33000.json','["三歲別吾弟，今歸心始降。", "從茲得安寢，無夢過重江。", "預驗鵲音喜，行看雁影雙。", "西湖猶可泛，酤酒市羊羫。"]'),
('31a44077-6ca9-48dc-88ae-eb2e78a48f15','途中寄純甫','强至','宋','宋诗','song-poetry','','[]','諸友分携地，重陽欲近天。',48,'全唐诗/poet.song.33000.json','["諸友分携地，重陽欲近天。", "共誰搴菊蕊，獨立憶梅仙。", "對飲乖今日，傷離似去年。", "佳山足吟賞，應自有新篇。"]'),
('a950d544-ac37-4f17-bb92-d7a0a9641e14','志遠法師挽辭','强至','宋','宋诗','song-poetry','','[]','寂寞湖邊寺，荆溪目已瞑。',48,'全唐诗/poet.song.33000.json','["寂寞湖邊寺，荆溪目已瞑。", "窗雲猶曉白，竹徑自寒青。", "野鳥悲吟動，門人感涕零。", "里無梁補闕，誰可法師銘。"]'),
('ac955e8d-0491-4071-b0fb-b6412d367d43','庚子歲除輦下作','强至','宋','宋诗','song-poetry','','[]','呼兒來秉燭，點檢鬢邊絲。',48,'全唐诗/poet.song.34000.json','["呼兒來秉燭，點檢鬢邊絲。", "志在驚時晚，年加願曉遲。", "京華猶旅食，世態益吾悲。", "四十明朝是，愁吟杜子詩。"]'),
('ed2df538-2be0-49c4-aedf-bfb3f1201d9c','久雨見月','强至','宋','宋诗','song-poetry','','[]','千門却燈燭，久雨愛冰輪。',48,'全唐诗/poet.song.34000.json','["千門却燈燭，久雨愛冰輪。", "愁眼開今夕，清光對故人。", "更長頻側帽，望極反霑巾。", "幾爲浮雲掩，行藏類此身。"]'),
('ed851f35-504f-4d19-a66e-6a6e0b0006e2','立春','强至','宋','宋诗','song-poetry','','[]','宿凍歸何處，池塘漲暖波。',48,'全唐诗/poet.song.34000.json','["宿凍歸何處，池塘漲暖波。", "日盤花面永，風入鳥聲和。", "俎菜堆生葉，閨裳剪薄羅。", "獨憐詩酒興，早較昨宵多。"]'),
('24dc5ee7-d7a0-4db4-bd1b-a3c7716dd04c','依韵和粹中早春','强至','宋','宋诗','song-poetry','','[]','寒威猶壓曉，淑氣已回春。',48,'全唐诗/poet.song.34000.json','["寒威猶壓曉，淑氣已回春。", "不道朱顔舊，剛憐華歲新。", "震雷將出地，蟄戶莫存身。", "漸報鶑花信，眉頭日漸伸。"]'),
('3d14b167-809b-4527-bcfc-910a6136d03a','早春寄擇之','强至','宋','宋诗','song-poetry','','[]','北陸寒威盡，東郊晝景添。',48,'全唐诗/poet.song.34000.json','["北陸寒威盡，東郊晝景添。", "風和引禽哢，水暖出魚潛。", "草木回生意，乾坤待澤漸。", "寧知巖谷下，經歲嘆才淹。"]'),
('c22fcde2-c09b-4080-8d91-547466d91891','正月三日郊外馬上作','强至','宋','宋诗','song-poetry','','[]','長日牽人事，新年散馬蹄。',48,'全唐诗/poet.song.34000.json','["長日牽人事，新年散馬蹄。", "和風吹凍柳，殘雪點春泥。", "意愜境自勝，興來杯屢携。", "徘徊羨飛鳥，曉逐野雲低。"]'),
('aa9e8743-1909-4293-a093-b7d55a041adf','禁烟節同子玉徐先生野步','强至','宋','宋诗','song-poetry','','[]','繫馬道邊樹，杖藜坡外岡。',48,'全唐诗/poet.song.34000.json','["繫馬道邊樹，杖藜坡外岡。", "風來花自笑，露過草猶香。", "樂事論三月，吟懷騖八荒。", "時平那有感，雙淚肯浪浪。"]'),
('6d544172-d023-40b2-b44a-ffbe08999d99','春色','强至','宋','宋诗','song-poetry','','[]','淺深花面染，來去柳邊浮。',48,'全唐诗/poet.song.34000.json','["淺深花面染，來去柳邊浮。", "雨氣那能洗，年光亦共流。", "濃濃交野綠，拂拂上朱樓。", "轉恐紛華眼，蕭條不愛秋。"]'),
('2524b3f2-fbb7-459b-b4f4-aad8419869bf','題劉有方御藥翠巖亭','强至','宋','宋诗','song-poetry','','[]','購石黄金費，開軒翠玉叢。',48,'全唐诗/poet.song.34000.json','["購石黄金費，開軒翠玉叢。", "端居憐象魏，遠意自衡嵩。", "花弄疏簾日，禽呼靜榻風。", "移山寧有術，未易笑愚公。"]'),
('089389e6-e538-462a-92b1-4d3732211047','升之元真觀讀書','强至','宋','宋诗','song-poetry','','[]','白日無停運，青雲要早圖。',48,'全唐诗/poet.song.34000.json','["白日無停運，青雲要早圖。", "寓居鄰上士，述作笑潛夫。", "案冗書籤滿，窗明樹影孤。", "徘徊拂塵壁，一半舊題無。"]'),
('ccdebfa1-a69c-40e8-9626-55e411ff6f5e','送李厚秘校赴相州戶曹','强至','宋','宋诗','song-poetry','','[]','迎婦金貂宅，之官銅雀臺。',48,'全唐诗/poet.song.34000.json','["迎婦金貂宅，之官銅雀臺。", "俱新是婚宦，有素獨憐才。", "簿領時能撥，圖書日可開。", "無勞嘆州縣，自足脫塵埃。"]'),
('e8320b0b-bc38-4e07-bf33-887ce9b2fc55','醉卧','强至','宋','宋诗','song-poetry','','[]','彭澤終朝飲，杯乾入醉鄉。',48,'全唐诗/poet.song.34000.json','["彭澤終朝飲，杯乾入醉鄉。", "眩頭遺野幘，坦腹委藜床。", "吏部甕邊卧，山公馬上狂。", "何如此安穩，寢興爲吾長。"]'),
('1fa386e6-d6ce-4b20-bbb6-ec42da67debf','和叔以琴詩見貽因成一篇奉答','强至','宋','宋诗','song-poetry','','[]','製就七絃器，斲殘千古桐。',48,'全唐诗/poet.song.34000.json','["製就七絃器，斲殘千古桐。", "正聲希世出，群耳此時聾。", "徽暗列星隠，意存流水空。", "憑君莫輕撫，留取和薰風。"]'),
('84e323ca-dfbe-413b-bb18-cb74058e71f7','古劍','强至','宋','宋诗','song-poetry','','[]','只因耕戰地，得此古龍泉。',48,'全唐诗/poet.song.34000.json','["只因耕戰地，得此古龍泉。", "磨拭自今日，埋藏曾幾年。", "無將試蛟窟，宜待靜狼烟。", "寄語奸邪輩，當鋒莫向前。"]'),
('96b44d4e-0c98-4476-bcb4-1e2af50a3b7e','壓書玉兔','强至','宋','宋诗','song-poetry','','[]','白玉雙蹲兔，工深刻楮勞。',48,'全唐诗/poet.song.34000.json','["白玉雙蹲兔，工深刻楮勞。", "長疑奔月窟，渾欲動霜毛。", "似喜書成穴，猶驚筆有毫。", "案間誰汝待，自覺守株高。"]'),
('d0a2c423-daa9-4628-9332-eab773bfb136','睢陽春日偶書二首  其一','强至','宋','宋诗','song-poetry','','[]','凍柳輕能舞，枯河暖亦流。',48,'全唐诗/poet.song.34000.json','["凍柳輕能舞，枯河暖亦流。", "東風應自好，遠客獨含愁。", "攬鏡傷吟鬢，無錢買釣舟。", "誰能終日興，大半在滄洲。"]'),
('33c270c2-78ba-4b31-86d2-359530c92193','睢陽春日偶書二首  其二','强至','宋','宋诗','song-poetry','','[]','楊柳亡隋岸，風塵舊宋州。',48,'全唐诗/poet.song.34000.json','["楊柳亡隋岸，風塵舊宋州。", "寄家盈百指，憶弟濕雙眸。", "旅宦那能定，人生本自浮。", "旋酤街北酒，準擬送春愁。"]'),
('26101833-1ee7-46e5-99cd-77fc820be509','睢陽別包進甫','强至','宋','宋诗','song-poetry','','[]','飲遍長安酒，春風送馬蹄。',48,'全唐诗/poet.song.34000.json','["飲遍長安酒，春風送馬蹄。", "異鄉憐會合，明日復東西。", "行興看君速，歸期恨我稽。", "門前客星瀨，到日濯塵泥。"]'),
('442cad5e-e664-46c8-8a93-56da922eeedf','別希魯回馬上口占','强至','宋','宋诗','song-poetry','','[]','兄佐諸侯幕，愚居孝子廬。',48,'全唐诗/poet.song.34000.json','["兄佐諸侯幕，愚居孝子廬。", "奔馳他自得，情味獨相於。", "先送秋帆動，還嗟友席虛。", "平生感知淚，今日爲漣如。"]'),
('6b104368-e3a0-43fb-8778-0c58126da029','大風','强至','宋','宋诗','song-poetry','','[]','正月明朝盡，東風半夜狂。',48,'全唐诗/poet.song.34000.json','["正月明朝盡，東風半夜狂。", "乾坤摇蓋軸，草樹拔毫芒。", "亂瓦飄無數，寒沙走更忙。", "聖時讒口絕，天令莫乖常。"]'),
('83def6a6-cad8-4ff3-ac79-d2e24cd6188f','寄盛子美俞元功二先輩','强至','宋','宋诗','song-poetry','','[]','彼美吳州傑，相從蕭寺居。',48,'全唐诗/poet.song.34000.json','["彼美吳州傑，相從蕭寺居。", "聊窮三尺律，肯恃五車書。", "前有殊尤等，行當選擢初。", "秋風吹客袂，鄉思復何如。"]'),
('55e55e0d-4147-400f-9b42-1ae49b75f929','寄公立','强至','宋','宋诗','song-poetry','','[]','一朝揮別袂，九日在征岐。',48,'全唐诗/poet.song.34000.json','["一朝揮別袂，九日在征岐。", "識我相思意，如君獨坐時。", "榴花須滿盞，菊蕊况盈枝。", "目下重陽淚，宜看杜牧詩。"]'),
('3549a4ba-6f13-4e53-9bb0-1ed0b4288875','寄俞君度','强至','宋','宋诗','song-poetry','','[]','夫子憊已甚，平生心向存。',48,'全唐诗/poet.song.34000.json','["夫子憊已甚，平生心向存。", "黄金空舊産，白首寄他門。", "獨酌醉應淺，愁吟聲更吞。", "飄零那復久，知己有平原。"]'),
('71bc1d13-9293-4e17-a8f9-2149bb7a248c','過洺州','强至','宋','宋诗','song-poetry','','[]','朔野風煙古，臨洺氣象存。',48,'全唐诗/poet.song.34000.json','["朔野風煙古，臨洺氣象存。", "魏風沿土性，漳水抱城根。", "故壘盤荒草，殘碑落近村。", "太平民産富，桑柘半郊原。"]'),
('6407d28d-07af-46ea-8ddf-09b08aed92f5','北都春日','强至','宋','宋诗','song-poetry','','[]','日出車馬道，風來城市塵。',48,'全唐诗/poet.song.34000.json','["日出車馬道，風來城市塵。", "關河應自昔，花草不知春。", "雲靜鳥翻翼，冰消魚動鱗。", "太平無一事，把酒勸耕民。"]'),
('9b062268-5499-41d1-960e-94dc2ffdb699','出大名府北郭','强至','宋','宋诗','song-poetry','','[]','驅車出近郭，野色感年華。',48,'全唐诗/poet.song.34000.json','["驅車出近郭，野色感年華。", "河靜水猶凍，地寒林未花。", "細風吹斷柳，殘雪隠虛沙。", "鄉思東南闊，歸飛羨暮鴉。"]'),
('ae534e07-e89c-4fe7-87cf-6e7c4e87f316','馬上口占','强至','宋','宋诗','song-poetry','','[]','出郭塵埃少，驅車節物便。',48,'全唐诗/poet.song.34000.json','["出郭塵埃少，驅車節物便。", "歸心忘澤國，病眼豁霜天。", "鳥雀飛荒圃，牛羊卧晚田。", "吟邊摇落意，疏木起孤烟。"]'),
('90f2b44d-6cbb-4efa-8625-08d32841852d','二月過半猶未見花昨日逢之珍云已有小桃因成短句','强至','宋','宋诗','song-poetry','','[]','不覺春過半，開花始見桃。',48,'全唐诗/poet.song.34000.json','["不覺春過半，開花始見桃。", "年光雙鳥翼，世事一鴻毛。", "有興撫清景，將愁付濁醪。", "家林應爛漫，南望首空搔。"]'),
('8c915558-8e91-4704-a100-4094d1170a1e','偶書呈公勝','强至','宋','宋诗','song-poetry','','[]','朔吹朝還暮，繁雲凝復開。',48,'全唐诗/poet.song.34000.json','["朔吹朝還暮，繁雲凝復開。", "不能成雪意，只解作寒媒。", "薄宦家千里，長吟酒一杯。", "西鄰鄭夫子，乘興幾時來。"]'),
('ffdb8c0a-0d39-4884-b4fe-ef3cdda9e103','走筆送楊正臣先輩還吳','强至','宋','宋诗','song-poetry','','[]','客衣沾魏土，歸馬望吳雲。',48,'全唐诗/poet.song.34000.json','["客衣沾魏土，歸馬望吳雲。", "一紀困游宦，異鄉愁送君。", "驊騮行得路，鴻雁去成群。", "何日江天酒，重論別後文。"]'),
('a8c308dc-1764-4543-b512-4daf794e6c63','居魏歲餘未嘗見江鄉故人今無悔如雄過此相見甚喜席間率成短篇呈之','强至','宋','宋诗','song-poetry','','[]','經年大河北，終日故鄉心。',48,'全唐诗/poet.song.34000.json','["經年大河北，終日故鄉心。", "入耳欣吳語，開懷慰越吟。", "天寒裘領薄，日暮酒杯深。", "早晚論邊策，長纓試請擒。"]'),
('8be7baac-192c-4b0f-ac19-e9bc07ef0163','新秋夜月寄故人','强至','宋','宋诗','song-poetry','','[]','客心宜靜夜，月色澹新秋。',48,'全唐诗/poet.song.34000.json','["客心宜靜夜，月色澹新秋。", "影落三湘水，詩傳八咏樓。", "何窮對酒望，幾處捲簾愁。", "若問相思意，隨君萬里遊。"]'),
('0f7c2026-0175-425a-89f2-b50c4794a552','依韵和留臺崔庫部局中自遣','强至','宋','宋诗','song-poetry','','[]','儒林文雅作，蕭散欲揮金。',48,'全唐诗/poet.song.34000.json','["儒林文雅作，蕭散欲揮金。", "老去安時態，秋來慰夙心。", "誰陪黄菊酒，自喜白頭吟。", "賓客霜臺少，詩成每獨斟。"]'),
('1309307c-7a51-4fc3-8bde-7a3d36a659ed','自零口夜至渭南縣作','强至','宋','宋诗','song-poetry','','[]','月黑征途暗，羸駒傍險行。',48,'全唐诗/poet.song.34000.json','["月黑征途暗，羸駒傍險行。", "村遥微認火，縣近忽聞更。", "落寞殊鄉意，喧啾小市聲。", "故園流水在，想像見冰清。"]'),
('68b6b886-91a3-473e-a48b-5b73e70d5798','送長安僉判鮮于子駿還闕','强至','宋','宋诗','song-poetry','','[]','相望蜀父老，應嫌駟馬遲。',48,'全唐诗/poet.song.34000.json','["相望蜀父老，應嫌駟馬遲。", "三冬辭幕府，千里走京師。", "富貴那能滯，文章自有知。", "關山含雪意，別酒對秦姬。"]'),
('55360a43-a19d-4953-9c89-67b1912eb653','長安春日','强至','宋','宋诗','song-poetry','','[]','白入雙吟鬢，衰侵一病身。',48,'全唐诗/poet.song.34000.json','["白入雙吟鬢，衰侵一病身。", "年光不貸老，春色似欺人。", "鳥破日邊霧，花飄風外塵。", "還將感時淚，對酒灑咸秦。"]'),
('3dff3b22-9f29-42b9-98cb-63ab0132a238','題光和年西嶽碑','强至','宋','宋诗','song-poetry','','["\u534e\u5c71"]','瘦硬光和字，崔巍太華碑。',48,'全唐诗/poet.song.34000.json','["瘦硬光和字，崔巍太華碑。", "鎸模森骨立，點畫宛鱗差。", "內有通神筆，前無絕妙辭。", "茅齋千載後，玩古獨心知。"]'),
('3a96df24-208a-4e81-87eb-4cb2d845b940','唐賢嶽廟題名','强至','宋','宋诗','song-poetry','','["\u534e\u5c71"]','華嶽金天廟，唐賢石闕題。',48,'全唐诗/poet.song.34000.json','["華嶽金天廟，唐賢石闕題。", "姓名留篆刻，冠劍落耕犁。", "字體諸家雜，函封數驛齎。", "幾行猶壯觀，丞相討淮西。"]'),
('4d808c25-985e-431d-990c-5024a0c39ef7','斷碑','强至','宋','宋诗','song-poetry','','[]','何代經兵火，終年委雪霜。',48,'全唐诗/poet.song.34000.json','["何代經兵火，終年委雪霜。", "文章誰黑白，首尾自參商。", "琬琰那淪翠，塵沙漸變黄。", "人生異堅石，撫汝重蒼茫。"]'),
('b7d06edf-638b-4079-a820-6952caf36816','依韵奉和經略司徒侍中上巳會興慶池','强至','宋','宋诗','song-poetry','','[]','千載蘭亭後，風流宛目前。',48,'全唐诗/poet.song.34000.json','["千載蘭亭後，風流宛目前。", "竹昏煙冉冉，花泣露漣漣。", "筆落詩推將，杯行酒有仙。", "水邊佳麗少，春草謾芊綿。"]'),
('6e28dd30-c0b3-47e0-aacf-cd7c78d57d63','小閣西山落日','强至','宋','宋诗','song-poetry','','[]','天地垂垂暮，殘陽似有情。',48,'全唐诗/poet.song.34000.json','["天地垂垂暮，殘陽似有情。", "未催全嶺暗，猶放半山明。", "遠樹微茫見，孤煙慘澹生。", "流年從此老，對酒急須傾。"]'),
('c197a683-9216-49cd-a400-931c8fbfedb5','翻經臺','强至','宋','宋诗','song-poetry','','[]','失道從僧指，窮高聽鳥呼。',48,'全唐诗/poet.song.34000.json','["失道從僧指，窮高聽鳥呼。", "千山四迴抱，一徑百盤紆。", "人事空今昔，臺基儻有無。", "吟邊嵐氣夕，落日伴猿狐。"]'),
('b4e41857-44e5-4ac3-b02d-1b0a3a68f679','題華藏環峰閣','强至','宋','宋诗','song-poetry','','[]','精藍已塵外，飛閣更雲端。',48,'全唐诗/poet.song.34000.json','["精藍已塵外，飛閣更雲端。", "只見蒼山合，寧知紫宙寬。", "客游追汗漫，詩思等巑岏。", "大士安禪後，何人此倚欄。"]'),
('65153314-46de-4431-91f1-ca34990a0b6b','羽師院假山','强至','宋','宋诗','song-poetry','','[]','累石作危峰，軒然曲沼中。',48,'全唐诗/poet.song.34000.json','["累石作危峰，軒然曲沼中。", "山形在眉睫，人意自衡嵩。", "影駭魚蝦避，路疑猨鳥通。", "宦途尤巧險，匠手莫言工。"]'),
('d4b0ede9-b633-42bf-8f9c-22604292a20a','京兆府初赴同天節宴詩二首  其一','强至','宋','宋诗','song-poetry','','[]','四月薰風轉，三天瑞景舒。',48,'全唐诗/poet.song.34000.json','["四月薰風轉，三天瑞景舒。", "歌從歸啟後，壽起祝堯初。", "詩喜南山對，身甘北闕疏。", "九韶音未作，朝野自歡如。"]'),
('b82657d4-b689-4dc4-89be-b487e35064ed','京兆府初赴同天節宴詩二首  其二','强至','宋','宋诗','song-poetry','','[]','五帝今云六，君王合萬年。',48,'全唐诗/poet.song.34000.json','["五帝今云六，君王合萬年。", "日長遲漏水，風細駐爐烟。", "想像聯朝珮，歡呼捧御筵。", "喜深恩更遠，不竭似秦川。"]'),
('f4f1d457-de16-4396-8996-8684018c018d','哭王仲密四首  其一','强至','宋','宋诗','song-poetry','','[]','相逢初北闕，並試復南宮。',48,'全唐诗/poet.song.34000.json','["相逢初北闕，並試復南宮。", "失意春風裏，謀歸汴水東。", "行藏他日異，笑語此生空。", "不掛青雲籍，聲名野史中。"]'),
('eb3a6e46-9eb6-43cf-b285-d0b53845c64f','哭王仲密四首  其二','强至','宋','宋诗','song-poetry','','[]','群居三益友，再拜十年兄。',48,'全唐诗/poet.song.34000.json','["群居三益友，再拜十年兄。", "一別長南北，相逢遂死生。", "淚流添渭水，心折注江城。", "聞訃悲尤劇，書成僕未行。"]'),
('00040831-0708-4676-af95-f43838048b3a','哭王仲密四首  其三','强至','宋','宋诗','song-poetry','','[]','場屋行遲暮，田廬卧寂寥。',48,'全唐诗/poet.song.34000.json','["場屋行遲暮，田廬卧寂寥。", "壯圖藏翰墨，高行落漁樵。", "會哭諸朋盛，銜哀一奠遥。", "繫舟江岸絕，愁望定山潮。"]'),
('b91bd0ac-ff38-47d7-b8c8-3da186847bf8','哭王仲密四首  其四','强至','宋','宋诗','song-poetry','','[]','多金空舊産，短褐盡平生。',48,'全唐诗/poet.song.34000.json','["多金空舊産，短褐盡平生。", "蒿里閟春色，桐江流哭聲。", "人憐天不與，婦少子猶嬰。", "如有山濤在，應忘顧後情。"]'),
('9bb3db35-705a-48b8-a859-44de98997681','依韵和酬鮮于子駿郎中見寄','强至','宋','宋诗','song-poetry','','[]','昨在王公幕，同時輒仰攀。',48,'全唐诗/poet.song.34000.json','["昨在王公幕，同時輒仰攀。", "論情昆弟等，知己友朋間。", "渭北孤交臂，淮陽慰客顔。", "長卿看駟馬，父老望西還。"]'),
('c7ab4683-c97d-46e3-b518-aea9acb3ad8f','趙龍圖自西川携鹿兒至秦相惠','强至','宋','宋诗','song-poetry','','[]','軟毛金縷暗，細點雪花勻。',48,'全唐诗/poet.song.34000.json','["軟毛金縷暗，細點雪花勻。", "林下遠思母，階前愁傍人。", "澗聲微可聽，野性漸能馴。", "公惠成愚好，他年伴幅巾。"]'),
('9e4aa291-4e8b-4667-ba6b-5b90a28c8ccb','長老鳳師新作四照亭以其環顧洞徹無纖翳礙目故名云從予乞詩因即其說以寄題','强至','宋','宋诗','song-poetry','','[]','大士安禪外，孤亭曠望中。',48,'全唐诗/poet.song.34000.json','["大士安禪外，孤亭曠望中。", "物無形可遁，心與境俱通。", "日月光應倍，江山氣更雄。", "寧須面壁坐，到此即觀空。"]'),
('1d09d297-b599-488f-9084-9d40bc5bb2cd','留題太平寺','强至','宋','宋诗','song-poetry','','[]','鄉落少人煙，精廬獨巋然。',48,'全唐诗/poet.song.34000.json','["鄉落少人煙，精廬獨巋然。", "香花真佛界，棟宇始唐年。", "鳥啄齋餘食，僧參夜半禪。", "清凉數畝地，已是隔塵緣。"]'),
('a2af8ad4-6032-42b7-950b-3197ff15b3b7','留題東巖院','强至','宋','宋诗','song-poetry','','[]','仁祠倚巖腹，無處入囂氛。',48,'全唐诗/poet.song.34000.json','["仁祠倚巖腹，無處入囂氛。", "古像棲深殿，高僧傲白雲。", "山花暖自發，溪溜遠猶聞。", "我正爲名縛，翻羞猿鳥群。"]'),
('b86a04cb-1295-45ef-85ac-b588bfd7dadb','數日前伏蒙吳先生留飲旋辱尊什喜某之來謹依嚴韵奉獻','强至','宋','宋诗','song-poetry','','[]','昔荷齒牙論，今猶骨髓淪。',48,'全唐诗/poet.song.34000.json','["昔荷齒牙論，今猶骨髓淪。", "報知虧國士，高第濫門人。", "牆仞欣重到，眉頭爲一伸。", "却嗟夫子疾，是日卧漳濱。"]'),
('99ccd745-dfb7-497c-accc-5419be8d6fd9','依韵奉和司徒侍中仲春釋奠','强至','宋','宋诗','song-poetry','','[]','先聖祠逾重，尊儒世適丁。',48,'全唐诗/poet.song.34000.json','["先聖祠逾重，尊儒世適丁。", "上公儀最熟，太學祭頻經。", "曉月衣冠凈，春風俎豆馨。", "魏人休請頌，在泮已言形。"]'),
('2eede8bf-2367-4448-b83f-4b593d49507c','梨花','强至','宋','宋诗','song-poetry','','[]','舊愛樂天句，今逢带雨春。',48,'全唐诗/poet.song.34000.json','["舊愛樂天句，今逢带雨春。", "花中都讓潔，月下倍生神。", "翫好張瑶席，攀仍贈玉人。", "莫開紅紫眼，此外盡非真。"]'),
('1940fc5c-a65c-4ade-ba28-bf67e0461e82','雨夜舟中','强至','宋','宋诗','song-poetry','','[]','岸鳴連夜雨，舟繫數家村。',48,'全唐诗/poet.song.34000.json','["岸鳴連夜雨，舟繫數家村。", "防盜頻敲柝，愁吟早閉門。", "呼兒陳小酌，憶弟動歸魂。", "安得晴風起，吹開波浪渾。"]'),
('544bfb41-f107-48e6-84e8-ef38758f83e3','御河舟中','强至','宋','宋诗','song-poetry','','[]','浮舟不用力，一水靜於山。',48,'全唐诗/poet.song.34000.json','["浮舟不用力，一水靜於山。", "沙鳥晴相喚，河雲晚更閑。", "微吟窮有象，清思入無間。", "河策誰云補，從公漫往還。"]'),
('c9de9ef9-797c-4773-8fdf-a836a39dbdfd','屐','强至','宋','宋诗','song-poetry','','[]','好在登高屐，東西類此身。',48,'全唐诗/poet.song.34000.json','["好在登高屐，東西類此身。", "游頻齒幾折，用久蠟還新。", "晚步憐今日，幽尋憶古人。", "莫隨珠履客，且伴白綸巾。"]'),
('c4b2d935-82a4-484c-b13f-f64704d4475f','夜坐','强至','宋','宋诗','song-poetry','','[]','城裏更籌急，窗邊竹影微。',48,'全唐诗/poet.song.34000.json','["城裏更籌急，窗邊竹影微。", "掩書雙淚迸，撫事寸心違。", "歲月辜華紱，風霜感彩衣。", "陶潛空自賦，何處有田歸。"]'),
('1cc77986-929e-436a-900b-5ee9362a9d34','韓魏公生日','强至','宋','宋诗','song-poetry','','[]','三秋開爽氣，七月降元精。',48,'全唐诗/poet.song.34000.json','["三秋開爽氣，七月降元精。", "致主鈞樞遍，尊賢衮鉞輕。", "顯庸歸社稷，陰相在神明。", "漳水流無竭，年年伴壽觥。"]'),
('ab775702-1e9f-4977-8da8-eb6f66d5a283','九日','强至','宋','宋诗','song-poetry','','[]','霜凈乾坤闊，登高極古臺。',48,'全唐诗/poet.song.34000.json','["霜凈乾坤闊，登高極古臺。", "秋聲楓幾落，客眼菊三開。", "短髮頻看帽，寒吟間引杯。", "籬邊空意緒，難得白衣來。"]'),
('6de25b53-964a-45a8-9a54-16c005deeb95','庚戌歲除','强至','宋','宋诗','song-poetry','','[]','薄宦三冬暮，殊方一紀餘。',48,'全唐诗/poet.song.34000.json','["薄宦三冬暮，殊方一紀餘。", "笑歌筋力倦，勛業鬢毛疏。", "道路紛乘傳，軒墀遝曳裾。", "無庸看半百，搔首歲云除。"]'),
('8b81ec88-c1e1-4fb4-a4ce-2083cfbda856','依韵和張文通中舍寄韓師元判官','强至','宋','宋诗','song-poetry','','[]','從容須陛對，蕭灑待家居。',48,'全唐诗/poet.song.34000.json','["從容須陛對，蕭灑待家居。", "近閣從戎筆，閑裁寄舊書。", "青衫逾一紀，黄卷尚三餘。", "聞說山齋好，何時遂曳裾。"]'),
('0ad770bb-4b17-48b9-aef5-5a7b0e0fc7b3','送譚供奉','强至','宋','宋诗','song-poetry','','[]','丹山靈鳳質，偶別帝梧飛。',48,'全唐诗/poet.song.34000.json','["丹山靈鳳質，偶別帝梧飛。", "忽憶華林好，還收倦翼歸。", "綠深宮樹合，紅薄苑花稀。", "重到回翔地，卑棲嘆昨非。"]'),
('a9f824b2-1324-4b57-a180-6bfdc05a347a','次韵仁叟禁中清曉','强至','宋','宋诗','song-poetry','','[]','禁廬休夜直，瑞靄向朝敷。',48,'全唐诗/poet.song.34000.json','["禁廬休夜直，瑞靄向朝敷。", "華闕辨雲氣，紫宸低斗樞。", "帝梧鳴彩鳳，宮漏息銅烏。", "日出將臨扆，天光冒海隅。"]'),
('5ee7c4e0-fab8-4f35-be97-6ff6fa897e07','送陸覃校書赴選西上','强至','宋','宋诗','song-poetry','','[]','朝飲送春酒，暮吟傷別詩。',48,'全唐诗/poet.song.34000.json','["朝飲送春酒，暮吟傷別詩。", "予愁鶑語亂，君興馬蹄遲。", "五府何時辟，三銓會早辭。", "回鞭晉陽道，不負細侯知。"]'),
('53ec547e-66b0-42af-a086-48ea8005e089','次韵盧六員外避暑','强至','宋','宋诗','song-poetry','','[]','城市苦歊暑，尋凉到水窮。',48,'全唐诗/poet.song.34000.json','["城市苦歊暑，尋凉到水窮。", "環林得高蔭，解带取微風。", "渴肺舉杯緩，汗膚兼酒紅。", "當年河朔會，舊事豈全空。"]'),
('f41b66f0-5dd2-416b-9f0b-24008d01d337','中秋京師對月','强至','宋','宋诗','song-poetry','','[]','今夜皇州月，秋光共幾分。',48,'全唐诗/poet.song.34000.json','["今夜皇州月，秋光共幾分。", "未全成皓魄，猶勝隔浮雲。", "白髮愁偏照，清樽喜獨醺。", "遥憐江國弟，北望首殷勤。"]'),
('6f0c1371-9298-41bf-afb2-35f6f58ea076','悼承天月禪老','强至','宋','宋诗','song-poetry','','[]','祖意生來達，詩心老去專。',48,'全唐诗/poet.song.34000.json','["祖意生來達，詩心老去專。", "傳燈與誰子，絕筆在何篇。", "朝客散談席，野禽窺法筵。", "唯應軒北石，秋後自依然。"]'),
('d882aaa6-dfd6-4866-9f5e-201d7fda8442','送蹇磻翁都官赴倅梁門','强至','宋','宋诗','song-poetry','','[]','共昔登龍客，仍今同舍郎。',48,'全唐诗/poet.song.34000.json','["共昔登龍客，仍今同舍郎。", "後先趨帥府，南北重離觴。", "塞角催秋月，邊烽落曉霜。", "軍城看趣召，能久頼王祥。"]'),
('79925e72-6f1a-4788-aa6d-af7de067ec74','久雨初霽對酒偶作','强至','宋','宋诗','song-poetry','','[]','彌月窮山雨，昏昏氣蔽天。',48,'全唐诗/poet.song.34000.json','["彌月窮山雨，昏昏氣蔽天。", "南榮初見日，萬瓦已生煙。", "節物驚殘臘，歡期減去年。", "愁來搔短髮，對酒且陶然。"]'),
('7e43addb-62be-4d2b-a24f-d9565b48107b','仲冬十六日祭馬步','强至','宋','宋诗','song-poetry','','[]','提轡傍險徑，喜隨雙炬紅。',48,'全唐诗/poet.song.34000.json','["提轡傍險徑，喜隨雙炬紅。", "薄雲籠淡月，苦霧捲嚴風。", "馬害誰云屏，神休覬所蒙。", "晨門未開鑰，殘夢續齋宮。"]'),
('cb0782af-4584-4ca1-bcb9-0e59d8c4a893','齋宮獨酌待曉入城','强至','宋','宋诗','song-poetry','','[]','青燈頻照面，黄卷懶低頭。',48,'全唐诗/poet.song.34000.json','["青燈頻照面，黄卷懶低頭。", "危坐自醒醉，孤斟誰獻酬。", "檐前落星宿，城裏息更籌。", "上馬即塵事，欲歸欣少留。"]'),
('abf91c1c-81fb-44cb-b602-980f5fed09a4','贈杜諮秘校','强至','宋','宋诗','song-poetry','','[]','唐代詩人傑，家居世杜陵。',48,'全唐诗/poet.song.34000.json','["唐代詩人傑，家居世杜陵。", "祖風今不墜，君學善相承。", "氣直橫秋鶚，文雄絕漢鵬。", "風騷如命將，壇復讓誰登。"]'),
('4937e1d7-8050-43e6-b792-78f8f422face','杜以詩和答依元韵贈之','强至','宋','宋诗','song-poetry','','[]','子美沒已久，正風幾替陵。',48,'全唐诗/poet.song.34000.json','["子美沒已久，正風幾替陵。", "上天憂道喪，遠裔以詩承。", "駑足輒追駿，鷃心聊慕鵬。", "微之重堂奧，努力願同登。"]'),
('abc062c7-98a4-4b53-bb84-6edafb5592d6','送范令巽之赴陝縣','强至','宋','宋诗','song-poetry','','[]','陝人西望眼，唯認馬蹄東。',48,'全唐诗/poet.song.34000.json','["陝人西望眼，唯認馬蹄東。", "柳縣追陶令，棠郊謁召公。", "問農游手勸，聽訟下情通。", "千載萊蕪後，傳家有素風。"]'),
('c7b4e236-5dc1-45dd-af1f-a35edb47f66f','送同年張正臣赴海陵幕','强至','宋','宋诗','song-poetry','','[]','早年登甲選，從事又東藩。',48,'全唐诗/poet.song.34000.json','["早年登甲選，從事又東藩。", "地與淮流絕，城連海氣昏。", "好山供健筆，暇日樂清樽。", "多著太平策，歸來奏帝閽。"]'),
('f6f66774-f86f-46fd-b9e5-d9211370f2bd','寒爐偶坐戲呈任道','强至','宋','宋诗','song-poetry','','[]','人事車輪轉，年光木葉摧。',48,'全唐诗/poet.song.34000.json','["人事車輪轉，年光木葉摧。", "交情論晚歲，生意共寒灰。", "未足勝寬褐，那能暖凍杯。", "知君尋氣類，不爲附炎來。"]'),
('b87e91bb-84f9-419d-9af1-f4127edad730','依韵和仲靈禪師喜賈丞相趙翰林見稱輔教編之什','强至','宋','宋诗','song-poetry','','[]','浩蕩藤州老，雄文鼓大編。',48,'全唐诗/poet.song.34000.json','["浩蕩藤州老，雄文鼓大編。", "聲名元自重，述作許誰傳。", "成誦慚空久，相逢偶未緣。", "承明內外相，交口譽師賢。"]'),
('36515308-84e7-44ea-8205-76fe49f24af5','送覺上人還霅','强至','宋','宋诗','song-poetry','','[]','卞山風月古，秀發在詩人。',48,'全唐诗/poet.song.34000.json','["卞山風月古，秀發在詩人。", "之子含清骨，禪師託後身。", "千篇取篋藁，一夢繞鄉蘋。", "知己大丞相，無勞揖縉紳。"]'),
('96e40538-1c69-4cf9-ad49-ba6fd72aa441','依韵和彭九及之歸養之什','强至','宋','宋诗','song-poetry','','[]','江南春自好，蜀客亦思歸。',48,'全唐诗/poet.song.34000.json','["江南春自好，蜀客亦思歸。", "淚與花俱落，心隨燕共飛。", "露章還子舍，孝理副宸闈。", "禁署風流後，謀漁未有磯。"]'),
('11de1e9f-dd4b-4130-b111-9e1483cb864d','送宣州太守沈司封','强至','宋','宋诗','song-poetry','','[]','宣城從古勝，謝守擅風流。',48,'全唐诗/poet.song.34000.json','["宣城從古勝，謝守擅風流。", "夫子名當世，君王付此州。", "訟鈴閑郡閣，吟筆動江樓。", "莫憶窗中句，能詩今隠侯。"]'),
('81f6f3c0-1dc5-45d1-b050-d14837cad302','送王天常太祝詩','强至','宋','宋诗','song-poetry','','[]','雨洗春枝冷，鶑愁晚更啼。',48,'全唐诗/poet.song.34000.json','["雨洗春枝冷，鶑愁晚更啼。", "感時雙淚落，送客片帆西。", "淮隰逢鴒羽，京塵縱馬蹄。", "有才無殿課，安穩步通閨。"]'),
('8c62ca17-efaa-47bf-be7f-4f58a5ca05be','方殿省示惠遠祖先生詩集','强至','宋','宋诗','song-poetry','','[]','先生名不死，三百幾年間。',48,'全唐诗/poet.song.34000.json','["先生名不死，三百幾年間。", "白首吟唐世，清風起越山。", "遺編流自久，異代許誰刪。", "遠裔傳能事，斯文氣欲還。"]'),
('8947c37a-1f96-439f-bc5c-27e6054b888f','屬疾','强至','宋','宋诗','song-poetry','','[]','壯懷衰獨早，樂事病全稀。',48,'全唐诗/poet.song.34000.json','["壯懷衰獨早，樂事病全稀。", "靜聽聞花落，欹眠見燕歸。", "冠裳成外累，塵土汩真機。", "强起親曹事，遥慚舊隠扉。"]'),
('09902149-615a-42a4-ad82-2fc1403f1610','予累日卧病適張文通惠教亦云服藥漫成小詩呈之','强至','宋','宋诗','song-poetry','','[]','功名心寸折，歲月鬢雙蓬。',48,'全唐诗/poet.song.34000.json','["功名心寸折，歲月鬢雙蓬。", "病畏酒杯綠，愁憐花蕊紅。", "杖藜成暇日，行樂步春風。", "唯有張公子，翛然此意同。"]'),
('34108cda-a098-4536-8650-ac0b207f82f4','暮春被病感書','强至','宋','宋诗','song-poetry','','[]','孤直難知己，才華反誤身。',48,'全唐诗/poet.song.34000.json','["孤直難知己，才華反誤身。", "流年銷壯節，多病對殘春。", "酒到心如達，花空眼亦貧。", "賢愚通塞理，誰與問洪鈞。"]'),
('f0bbc99c-dac6-431c-959d-ed9cc14ea600','聞升甫南池觀魚所獲無幾戲成小詩奉呈','强至','宋','宋诗','song-poetry','','[]','巨鱗非尺澤，多目漫污池。',48,'全唐诗/poet.song.34000.json','["巨鱗非尺澤，多目漫污池。", "網漏從今日，筌忘復幾時。", "饔人顔慘淡，漁子興參差。", "豈似任公捷，群鰲一釣絲。"]'),
('1d2498cf-ff90-4d0b-8117-75f90b2d595c','病起觀盆魚','强至','宋','宋诗','song-poetry','','[]','戢戢駢頭戲，悠悠掉尾行。',48,'全唐诗/poet.song.34000.json','["戢戢駢頭戲，悠悠掉尾行。", "莫言盆盎窄，猶勝網羅橫。", "競觸浮萍亂，時吹細浪生。", "嗟予遭病縛，羨汝遂微情。"]'),
('90168306-88a5-444b-9aa5-4e2178c74c36','送王明叟起秀州法掾','强至','宋','宋诗','song-poetry','','[]','去去持丹筆，當官議是非。',48,'全唐诗/poet.song.34000.json','["去去持丹筆，當官議是非。", "壯心低仕路，戀涕濕親衣。", "汲浪檣烏急，吳霜稻蟹肥。", "論文杯酒後，從此故人稀。"]'),
('3cfd1f3b-6945-4d2d-9b7b-5c446ac79efc','行叟權秋掾比回正老以詩寄之因次韵奉和','强至','宋','宋诗','song-poetry','','[]','郡獄乏掾屬，君才盛府依。',48,'全唐诗/poet.song.34000.json','["郡獄乏掾屬，君才盛府依。", "犴牢煩暫掌，鸞枳復卑飛。", "盡室輕裝去，新吟滿篋歸。", "風流傷別處，粉淚灑紅衣。"]'),
('00067062-df3a-4e78-a40a-b59e36fe2e9a','送石亢之節推赴廬州幕府','强至','宋','宋诗','song-poetry','','[]','執政昔曾祖，滯才今令孫。',48,'全唐诗/poet.song.34000.json','["執政昔曾祖，滯才今令孫。", "三遷纔大幕，萬石已高門。", "阮瑀妙草檄，毛公深雅言。", "相從賓主樂，淮月共清樽。"]'),
('69cf5521-9987-47df-b74f-b1b02eb261ec','送子立榮侍南歸','强至','宋','宋诗','song-poetry','','[]','有客就征驂，風前別酒酣。',48,'全唐诗/poet.song.34000.json','["有客就征驂，風前別酒酣。", "慈顔依膝下，歸意滿江南。", "去路草初歇，到家梅正含。", "短書無惜寄，別後抵清談。"]'),
('d79e8ba5-1c34-4f6b-a8c1-14000577f177','上何太宰生日二首  其一','强至','宋','宋诗','song-poetry','','[]','斗杓西揭柄，南呂已飛灰。',48,'全唐诗/poet.song.34000.json','["斗杓西揭柄，南呂已飛灰。", "芝室占熊夢，蓬山挺梓材。", "世欣金鷟見，人慶玉麟來。", "天意非難料，行看位上台。"]'),
('c1dd6e6a-69a2-4ead-acbe-4e0501ae155e','上何太宰生日二首  其二','强至','宋','宋诗','song-poetry','','[]','皇穹符寶運，嵩獄降真賢。',48,'全唐诗/poet.song.34000.json','["皇穹符寶運，嵩獄降真賢。", "明月中秋後，黄花九月前。", "潭潭新紫府，疊疊舊青氈。", "遐想靈椿慶，春秋合幾年。"]'),
('675dd6b2-1a32-43e1-a2e2-2a663f557836','漁者','强至','宋','宋诗','song-poetry','','[]','身世扁舟裏，飄颻可奈何。',48,'全唐诗/poet.song.34000.json','["身世扁舟裏，飄颻可奈何。", "萬生勞白日，一笑屬滄波。", "闊網施能幾，閑機用未多。", "余顔自憔悴，莫作楚臣歌。"]'),
('c57a9b94-627f-416b-a940-a165cdaeb959','對雪六首  其一','强至','宋','宋诗','song-poetry','','[]','幾尺江東雪，同時戶北風。',48,'全唐诗/poet.song.34000.json','["幾尺江東雪，同時戶北風。", "全家愁坐外，寄命苦吟中。", "已分書帷冷，偏憎酒盞空。", "漫將豐歲兆，去問白頭翁。"]'),
('d49f764b-ddf9-47cd-a96c-cba16535deb3','對雪六首  其二','强至','宋','宋诗','song-poetry','','[]','草樹驚全失，山河望轉非。',48,'全唐诗/poet.song.34000.json','["草樹驚全失，山河望轉非。", "片時藏地險，底處極天圍。", "樓半輕相逐，檐前急自飛。", "乘風還有意，故去點人衣。"]'),
('5d2bd67c-6a22-4142-aab2-d92d929404e0','對雪六首  其三','强至','宋','宋诗','song-poetry','','[]','飄灑三冬暮，蒼茫一氣凝。',48,'全唐诗/poet.song.34000.json','["飄灑三冬暮，蒼茫一氣凝。", "寒威斗自壯，空色曉逾澄。", "狂走尋岡兔，饑呼失樹鷹。", "年來交態淺，有興即誰乘。"]'),
('f91ada81-5377-4cea-b150-7d3a710a2e8b','對雪六首  其四','强至','宋','宋诗','song-poetry','','[]','影亂侵書幌，花輕輟酒杯。',48,'全唐诗/poet.song.34000.json','["影亂侵書幌，花輕輟酒杯。", "襟懷同落寞，氣象亦崔嵬。", "屢折參雲竹，偏凌照水梅。", "紅爐方爾附，未可論寒灰。"]'),
('602c1f9a-2f93-41f4-8c3b-d621b50bc841','對雪六首  其五','强至','宋','宋诗','song-poetry','','[]','色浮千里白，氣逼萬家寒。',48,'全唐诗/poet.song.34000.json','["色浮千里白，氣逼萬家寒。", "獨鳥饑猶啄，癡兒喜自團。", "向風初舞急，入夜轉聲乾。", "此味同誰冷，吟窗映素冠。"]'),
('b1d3e87d-5304-45e7-818d-f898fe381c91','對雪六首  其六','强至','宋','宋诗','song-poetry','','[]','朔風吹不盡，顥氣入無間。',48,'全唐诗/poet.song.34000.json','["朔風吹不盡，顥氣入無間。", "市井人喧息，江湖鳥翼頑。", "酒邊驚晚歲，吟外失群山。", "溫室便高卧，明朝任塞關。"]'),
('90414460-a0bf-48b5-9d0d-bb43c0b74972','次韵答承天月長老','强至','宋','宋诗','song-poetry','','[]','方外得師晚，相逢出古心。',48,'全唐诗/poet.song.34000.json','["方外得師晚，相逢出古心。", "交成真合水，意在始知琴。", "宦路塵泥久，禪扃歲月深。", "清風貽絕唱，一誦快煩襟。"]'),
('5abe9863-3f37-4c08-a908-6be5f8ddf9fa','塗中書四十言奉寄武陵則師','强至','宋','宋诗','song-poetry','','[]','師有知人術，一言珍萬金。',48,'全唐诗/poet.song.34000.json','["師有知人術，一言珍萬金。", "聖門防取貌，吾道素論心。", "越樹秋聲起，武陵歸思深。", "桃源千載事，此說更難尋。"]'),
('73f66ce6-de09-426f-b3c0-280de2c118cf','書香嚴屋壁呈寺主隆師','强至','宋','宋诗','song-poetry','','[]','莊嚴模浄域，金碧照晴霓。',48,'全唐诗/poet.song.34000.json','["莊嚴模浄域，金碧照晴霓。", "土木有時竭，樓臺無日低。", "林泉藏好處，巾屨得安棲。", "我愧陶彭澤，煩師數過溪。"]'),
('6e78ad31-0e0b-4ad4-afb3-5bbedda56bcc','詩送長老芝公歸靈洞','强至','宋','宋诗','song-poetry','','[]','昔以醫名著，今茲祖意傳。',48,'全唐诗/poet.song.34000.json','["昔以醫名著，今茲祖意傳。", "衆生如不病，大士自安禪。", "貌等澗松古，性同山月圓。", "應防猿鳥憶，却指舊林泉。"]'),
('b40a486b-c3c9-4a6f-b631-e618f95dd7dc','贈凈土嵩長老','强至','宋','宋诗','song-poetry','','[]','林泉久安住，心境兩無塵。',48,'全唐诗/poet.song.34000.json','["林泉久安住，心境兩無塵。", "禪外牽餘想，詩中老此身。", "虛懷延海衆，雄辯服談賓。", "偉特如師少，相逢悟宿因。"]'),
('2d0f4934-ce88-45c8-bb5f-2eea31521746','贈霞長老','强至','宋','宋诗','song-poetry','','[]','大士本宿植，妙年離世紛。',48,'全唐诗/poet.song.34000.json','["大士本宿植，妙年離世紛。", "定心馴海鳥，詩語淡秋雲。", "與物曾無著，收聲恐有聞。", "唯將諸祖意，晚歲導迷群。"]'),
('e2a79143-fb99-4a97-a70c-ae6f9c985a72','酬齊上人','强至','宋','宋诗','song-poetry','','[]','不見湯師久，病眠時序深。',48,'全唐诗/poet.song.34000.json','["不見湯師久，病眠時序深。", "忽驚朱夏過，真負碧雲吟。", "他日虎溪約，同時鳳闕心。", "未論應去住，杖屨且相尋。"]'),
('0ba68c4c-4399-4863-88d8-fc758d51b19f','景山無思二大師垂和鄙詩復依前韵奉答','强至','宋','宋诗','song-poetry','','[]','西北塵游倦，東南野興深。',48,'全唐诗/poet.song.34000.json','["西北塵游倦，東南野興深。", "帳空慚鶴怨，山暝憶猨吟。", "大士真交臂，連篇契夙心。", "會須携蠟屐，雲嶠陟千尋。"]'),
('dfede204-2ac7-4912-96c1-17ba98938c7b','送臻上人還雲山','强至','宋','宋诗','song-poetry','','[]','半歲風埃地，終朝雲水情。',48,'全唐诗/poet.song.34000.json','["半歲風埃地，終朝雲水情。", "身兼飛錫健，眼向故山明。", "不改禪衣色，從來野橐輕。", "煩師伴猨鳥，兩耳厭車聲。"]'),
('f4abf663-a666-4aff-abb7-a950f33d274b','詩贈圓公大士','强至','宋','宋诗','song-poetry','','[]','恐是逃名客，因爲出世流。',48,'全唐诗/poet.song.34000.json','["恐是逃名客，因爲出世流。", "人間雲不定，心外佛何求。", "醉喜形骸放，詩嫌偶對囚。", "我應遭竊笑，聲利乃身讎。"]'),
('20f7fa1d-d3a3-4349-a86b-ecb355d17b7b','仲靈禪師以詩見邀輒走筆依韵附還使奉和','强至','宋','宋诗','song-poetry','','[]','世好元難合，便甘或棄辛。',48,'全唐诗/poet.song.34000.json','["世好元難合，便甘或棄辛。", "喜師同肺腑，偶爾異衣巾。", "文約牽常俗，詩情遠過人。", "相邀松下別，山意入秋新。"]'),
('a9ba6457-f66e-4ca3-9c61-cfe3bb05ad10','送李講主還維揚','强至','宋','宋诗','song-poetry','','[]','定憶婆娑樹，雙垂滿地陰。',48,'全唐诗/poet.song.34000.json','["定憶婆娑樹，雙垂滿地陰。", "春風吹社燕，歸意逐淮禽。", "帆落橫江盡，門開小院深。", "先撾大法鼓，續震海潮音。"]'),
('228a0557-bb39-4520-94fa-cf31946ba3a1','仁宗皇帝挽歌辭四首  其一','强至','宋','宋诗','song-poetry','','[]','未乾宮硯墨，猶暖御爐烟。',96,'全唐诗/poet.song.34000.json','["未乾宮硯墨，猶暖御爐烟。", "鷄唱空催曉，龍飛忽上天。", "攀髯三月暮，灑淚五雲邊。", "盛德無容報，塵埃萬壽篇。", "飛帚飄宸翰，賡歌縱睿才。", "歌歡三閤燕，聲轉兩宮哀。", "人世金縢祕，天門玉鎖開。", "年年初夏月，寂寞壽山杯。"]'),
('750c4dda-dce2-4784-9216-34f6022c7a97','仁宗皇帝挽歌辭四首  其二','强至','宋','宋诗','song-poetry','','[]','輕徭寬日力，橫費惜秋毫。',48,'全唐诗/poet.song.34000.json','["輕徭寬日力，橫費惜秋毫。", "臨諫天容睟，尊賢聖體勞。", "乾坤收化育，弓劍入悲號。", "十月西陵仗，愁雲隔赭袍。"]'),
('5d82dc63-6517-4df1-a1d3-27e2e5cffc39','仁宗皇帝挽歌辭四首  其三','强至','宋','宋诗','song-poetry','','[]','聖運一千載，君臨四十春。',48,'全唐诗/poet.song.34000.json','["聖運一千載，君臨四十春。", "寶圖先與子，妙斷獨如神。", "瑞表虛南極，哀聲動北辰。", "天鍾堯舜性，廟號訖稱仁。"]'),
('6f32f20b-f5df-47a5-abd9-05092cd28002','石太保挽詞','强至','宋','宋诗','song-poetry','','[]','許國三朝老，傳家萬石君。',48,'全唐诗/poet.song.34000.json','["許國三朝老，傳家萬石君。", "乞骸章未報，沒齒訃先聞。", "挽鐸摇秋露，銘旌卷暮雲。", "龍岡逢吉壤，馬鬣寄高墳。"]'),
('b8156c9e-4af0-478a-b7e0-9798a4c640fc','王廣淵郎中挽詞','强至','宋','宋诗','song-poetry','','[]','一門新茹痛，八座近云亡。',48,'全唐诗/poet.song.34000.json','["一門新茹痛，八座近云亡。", "禍故近賢者，風流失望郎。", "葬帷籠淡月，挽鐸訴清霜。", "祖烈繫誰紹，三槐老北堂。"]'),
('c4a0b881-3ba0-41a3-b705-4f82526538c9','王子直挽詞二首  其一','强至','宋','宋诗','song-poetry','','[]','流水身飄忽，青雲意闊疏。',48,'全唐诗/poet.song.34000.json','["流水身飄忽，青雲意闊疏。", "儒林看作傳，使者合求書。", "野月隨丹旐，山煙濕素車。", "寢門今日淚，一灑爲無餘。"]'),
('f257ba31-beaa-44e3-b72b-a94c80a2e353','王子直挽詞二首  其二','强至','宋','宋诗','song-poetry','','[]','王氏仍淮水，賢人減潁川。',48,'全唐诗/poet.song.34000.json','["王氏仍淮水，賢人減潁川。", "風流今盡矣，天理舊茫然。", "親涕霑封篋，交情動絕絃。", "公卿誰不到，偏夭賈生年。"]'),
('6237a4ef-2055-47b7-b41c-4272354ae9fd','晉陽郡君挽詞  其一','强至','宋','宋诗','song-poetry','','[]','法度居無失，圖書動有稽。',48,'全唐诗/poet.song.34000.json','["法度居無失，圖書動有稽。", "不偕君子老，空美大夫妻。", "淡月臨新兆，清風在舊閨。", "哭聲摧隴水，山鳥學人啼。"]'),
('0d88a302-7ce2-402a-ac10-e28a24401efe','晉陽郡君挽詞  其二','强至','宋','宋诗','song-poetry','','[]','夫賢微子後，身貴畢公孫。',48,'全唐诗/poet.song.34000.json','["夫賢微子後，身貴畢公孫。", "獨棄斑衣養，空餘象服尊。", "悲風纏挽鐸，苦霧濕銘旛。", "誰謂靈香驗，何曾見反魂。"]'),
('f675f272-760d-4db8-823b-46879f14b7a7','立春','强至','宋','宋诗','song-poetry','','[]','北風已作東風客，昨日何如今日暄。',64,'全唐诗/poet.song.34000.json','["北風已作東風客，昨日何如今日暄。", "造化有期尋萬木，陽和無迹走千門。", "土牛陌上摧花杖，玉燕釵頭墜綵旛。", "獨我題詩添意緒，又看殘臘委冰痕。"]'),
('31e87dfd-cc7f-4c26-84ae-f6912a72ff85','春日山中感懷','强至','宋','宋诗','song-poetry','','[]','春中酣酣破宿霾，春心衮衮瀉長淮。',64,'全唐诗/poet.song.34000.json','["春中酣酣破宿霾，春心衮衮瀉長淮。", "無情草樹相看久，得意親朋一笑乖。", "世俗冰霜誰暖眼，古人金石已枯骸。", "愁來獨對青山坐，唯有東風入舊懷。"]'),
('fd88e433-0f52-41e6-9293-6a6cd8d1d840','贈楊尉純甫','强至','宋','宋诗','song-poetry','','[]','君家茂族出關西，壯氣長干萬丈霓。',64,'全唐诗/poet.song.34000.json','["君家茂族出關西，壯氣長干萬丈霓。", "斥鷃羨鵬舒海翼，駑駘觀驥騁霜蹄。", "詩才多慕謫仙逸，宦緒猶嫌梅福低。", "千里霄程方策足，莫云今日是卑棲。"]'),
('0e64076a-63c6-462e-92cd-36898225cd29','若師院咏笋','强至','宋','宋诗','song-poetry','','[]','戢戢新芽迸舊林，纔生有節便虛心。',64,'全唐诗/poet.song.34000.json','["戢戢新芽迸舊林，纔生有節便虛心。", "已鄰佛界黄金地，更學仙家碧玉簪。", "失灌要須防倦僕，偷餐切莫聽饑禽。", "憑師養取成修竹，截管終令作鳳吟。"]'),
('33924375-1a31-4dc9-af86-b22f4742db67','席上次韵純甫牡丹','强至','宋','宋诗','song-poetry','','[]','絕艷濃香一倍繁，青春歸去已珊珊。',64,'全唐诗/poet.song.34000.json','["絕艷濃香一倍繁，青春歸去已珊珊。", "障風護恐檀心損，和雨攀應玉手寒。", "今日我來頻舉爵，明年誰共憑欄干。", "盛傳京雒多名品，未得尋芳洗眼看。"]'),
('5fb088e3-c80e-4a4a-9cb0-3e723ccf1634','寄湖掾楊浩然','强至','宋','宋诗','song-poetry','','[]','新持手版苕溪掾，應恨浮名別故鄉。',64,'全唐诗/poet.song.34000.json','["新持手版苕溪掾，應恨浮名別故鄉。", "澤國幾瞻飛雁序，春風自入墜鱣堂。", "坐曹未改平生好，開卷能如往日忙。", "龍首主人監郡樂，定蒙賓禮考文章。"]'),
('7d25f4e2-0170-491e-b2b1-9d7fa315bcd8','送春','强至','宋','宋诗','song-poetry','','[]','年年不會春來處，疑自深紅嫩白間。',64,'全唐诗/poet.song.34000.json','["年年不會春來處，疑自深紅嫩白間。", "今日却從何處去，明年依舊待君還。", "不堪眼見鶑花老，安得心同木石頑。", "身外韶華猶可再，其如綠鬢與朱顔。"]'),
('93fe3454-767f-4196-a3c2-6e6d5ae70383','經和靖林先生舊隠','强至','宋','宋诗','song-poetry','','[]','獨行先生舊隠荒，大名寧受一棺藏。',64,'全唐诗/poet.song.34000.json','["獨行先生舊隠荒，大名寧受一棺藏。", "能詩秀骨應無朽，近塚閑花亦自香。", "卷軸門人收篋笥，歲時族子奉烝嘗。", "逸民未許先賢傳，猶說梁鴻有孟光。"]'),
('f0297495-fbc1-4d3d-89de-5bad99dbf74d','贈陸元象文學','强至','宋','宋诗','song-poetry','','[]','漢世最優文學掾，因君官稱復榮今。',64,'全唐诗/poet.song.34000.json','["漢世最優文學掾，因君官稱復榮今。", "青春事業收名路，白首光華照士林。", "風月每邀花底醉，乾坤共老水邊吟。", "安車正好追先烈，子舍唯增二百金。"]'),
('620e908d-137d-4516-b11d-e0eef1622e71','依韵和陸丈瑞香花','强至','宋','宋诗','song-poetry','','[]','花下詩翁已富情，愛花相咏句還成。',64,'全唐诗/poet.song.34000.json','["花下詩翁已富情，愛花相咏句還成。", "纔開秀格能殊衆，到老清香不負名。", "世上流芳歸幾處，江南傳價入中京。", "乾坤定是憐馨德，那許風前趁落英。"]'),
('001bb021-c0b9-4c5f-8981-d3b2f16f24cc','競渡','强至','宋','宋诗','song-poetry','','[]','畫鷁追風千楫動，錦標翻日萬人呼。',64,'全唐诗/poet.song.34000.json','["畫鷁追風千楫動，錦標翻日萬人呼。", "驕龍戰水爭先後，采蜃橫川半有無。", "波底魚蝦愁破窟，岸傍車馬看盈塗。", "競心猶出功名下，吟倚扁舟爲一呼。"]'),
('e488faa6-3b84-4202-bb1b-09bf68cff5ce','謝純甫惠筆','强至','宋','宋诗','song-poetry','','[]','管勁毫尖匠製宜，故人珍贈我何爲。',64,'全唐诗/poet.song.34000.json','["管勁毫尖匠製宜，故人珍贈我何爲。", "分殊定遠初投日，得似文通舊夢時。", "大手愧無才翰用，正心惟見友朋規。", "紛紛紙尾方勞署，辜負詞林視草詞。"]'),
('ae524bcf-f964-4d1c-8c25-27eab8adb859','次韵和純甫秋陰悶書','强至','宋','宋诗','song-poetry','','[]','乾坤泱漭作秋容，節物情懷兩莫窮。',64,'全唐诗/poet.song.34000.json','["乾坤泱漭作秋容，節物情懷兩莫窮。", "山雨欲來陰竟日，溪雲不斷氣浮空。", "頼存樽酒時傾綠，更有歌裙可醉紅。", "偶爾登臨愈興感，朱顔容易變衰翁。"]'),
('2def5f01-3e3e-4eda-ac3e-7ce174a47a8f','再次前韵','强至','宋','宋诗','song-poetry','','[]','晻曖秋旻氣象濃，對時覽物兩無窮。',64,'全唐诗/poet.song.34000.json','["晻曖秋旻氣象濃，對時覽物兩無窮。", "纔開又合煙光重，欲落還收雨意空。", "直恐客頭先老白，却思日脚带斜紅。", "天真不擾無餘感，誰似前溪下釣翁。"]'),
('ebb3feee-8db2-48c9-ad4f-d55c057f6713','純甫出近郊以梅花未開成篇見貽因次元韵奉酬','强至','宋','宋诗','song-poetry','','[]','朔吹鳴時萬葉黄，獨留瓊蕊擅幽芳。',64,'全唐诗/poet.song.34000.json','["朔吹鳴時萬葉黄，獨留瓊蕊擅幽芳。", "水邊野外開雖晚，臘後春前賞未忙。", "素艷若敷應雪妬，嫩心猶閟已風香。", "此花更是梅仙咏，消得花間飲百觴。"]'),
('90ebf5c4-5eb9-4b7a-8433-7210555c4545','過練湖','强至','宋','宋诗','song-poetry','','[]','湖畔難尋使者麾，湖光猶照旅人衣。',64,'全唐诗/poet.song.34000.json','["湖畔難尋使者麾，湖光猶照旅人衣。", "氣蒸澤國能無潤，堤貯雲天別有圍。", "楊柳經霜相對老，鳬鷖飽食自由飛。", "繫舟索紙題詩句，更把閑愁付落暉。"]'),
('e0de4a71-62c2-4fda-82af-30c164588bfb','題吳山伍子胥祠','强至','宋','宋诗','song-poetry','','[]','江上胥山古木陰，祠堂氣象亦蕭森。',64,'全唐诗/poet.song.34000.json','["江上胥山古木陰，祠堂氣象亦蕭森。", "江雲不散憂君色，山月猶明死國心。", "遷史簡編今斷缺，吳人牲酒日肥深。", "鄙懷異代悲忠烈，一拜威靈淚滿襟。"]'),
('58f2c7d3-8fca-48ea-85fa-044d0f8a1387','資國山口石橋','强至','宋','宋诗','song-poetry','','[]','前日枯槎接斷溪，今朝白石跨完堤。',64,'全唐诗/poet.song.34000.json','["前日枯槎接斷溪，今朝白石跨完堤。", "牧兒靜立牛磨角，詩客閑驚馬駐蹄。", "澗雨漲來流淺瀨，山風掃過斷纖泥。", "十家豈乏相如輩，當有人從柱上題。"]'),
('04a907e4-9266-4021-9449-2dd63e56d732','立春','强至','宋','宋诗','song-poetry','','[]','魚尋細脈上輕澌，鳥趁微和哢好枝。',64,'全唐诗/poet.song.34000.json','["魚尋細脈上輕澌，鳥趁微和哢好枝。", "多病强傾春日酒，苦吟還接暮冬詩。", "江南信息梅應蕊，京國風流柳未絲。", "最有佳人隨節序，釵頭綵勝競垂垂。"]'),
('9de334b0-e533-4008-807c-62341c2aeeb0','送朱郎中得謝歸淮南二首  其一','强至','宋','宋诗','song-poetry','','[]','一束衣冠四十春，公今收得自由身。',64,'全唐诗/poet.song.34000.json','["一束衣冠四十春，公今收得自由身。", "朱顔出仕看同輩，白髮歸榮有幾人。", "何處覓金分素里，只聞行路羨清塵。", "扁舟急解隨河纜，猶恐京埃汙葛巾。"]'),
('fac1cbd8-e050-4f69-8028-125130c7258a','送朱郎中得謝歸淮南二首  其二','强至','宋','宋诗','song-poetry','','[]','天香猶在入朝衣，早見都門解綬歸。',64,'全唐诗/poet.song.34000.json','["天香猶在入朝衣，早見都門解綬歸。", "晚歲高風增慷慨，今宵列宿動光輝。", "誰供白酒開談笑，自向滄洲洗是非。", "從此淮禽相看喜，沙邊不復背公飛。"]'),
('e6d93dc0-fd3c-457d-be58-e83652e21d06','次韵酬答胡一之','强至','宋','宋诗','song-poetry','','[]','六科頓網索豪雄，巖穴賢群爲一空。',64,'全唐诗/poet.song.34000.json','["六科頓網索豪雄，巖穴賢群爲一空。", "夫子獨沈窮巷底，故人多列要塗中。", "志行應在功名早，欲大難爲富貴充。", "年未平津學晁董，佇觀畫並耀江東。"]'),
('fc188e9c-c86a-4e57-96e0-3584ac810c10','立春輦下作','强至','宋','宋诗','song-poetry','','[]','雪意徘徊收臘尾，風光迤邐上花梢。',64,'全唐诗/poet.song.34000.json','["雪意徘徊收臘尾，風光迤邐上花梢。", "强傾浮蟻嘗春酌，終似南禽憶舊巢。", "愁裏年華侵短髮，吟邊生意滿東郊。", "玉盤絲菜無消息，索寞空齋畏客嘲。"]'),
('913bbea4-c8b0-4647-9154-124588b42f3c','依韵和擇之惜春','强至','宋','宋诗','song-poetry','','[]','何門織婦爲春魔，幾聽啼鶑暗輟梭。',64,'全唐诗/poet.song.34000.json','["何門織婦爲春魔，幾聽啼鶑暗輟梭。", "美釀入唇宜莫算，芳期屈指已無多。", "迎風柳絮飄都盡，著雨花枝落半過。", "正好狂歌對餘景，休因節物嘆蹉跎。"]'),
('36dab8db-f62d-4e67-b6e3-7ad4862c1479','寄陳介進士','强至','宋','宋诗','song-poetry','','[]','聖門顔子最稱貧，猶有簞瓢奉一身。',64,'全唐诗/poet.song.34000.json','["聖門顔子最稱貧，猶有簞瓢奉一身。", "罕似饑腸游太學，獨將生意託洪鈞。", "常時閔笑遭流俗，今日依歸得主人。", "早夜從容諮道誼，切防事業去青春。"]'),
('49c9f581-b826-4d8c-918a-d0bab794d9a0','次韵和秋扇','强至','宋','宋诗','song-poetry','','[]','形如圓月色欺霜，曾許佳人掩面藏。',64,'全唐诗/poet.song.34000.json','["形如圓月色欺霜，曾許佳人掩面藏。", "袁守揚風方慰愜，班姬中道忽悲凉。", "自知掌握初經用，豈顧塵埃此暫傷。", "只恐來年清暑殿，別將紈素上君堂。"]'),
('9cf02a09-7dbe-4b66-8b3c-1798838b18c8','月卿大師以書抵予言到自永嘉今將還杭因索詩送行聊書短章塞來請之勤','强至','宋','宋诗','song-poetry','','[]','京洛多年作意游，撇然歸思滿林丘。',64,'全唐诗/poet.song.34000.json','["京洛多年作意游，撇然歸思滿林丘。", "塵衣纔洗吳中水，吟錫還尋海畔州。", "獨夜揮弦泣山鬼，幾旬談妙動藩侯。", "孤雲高迹真無定，又理輕裝買客舟。"]'),
('7b692399-c9b2-416b-bb51-645d9b24f693','菊','强至','宋','宋诗','song-poetry','','[]','花濃新出黄金礦，枝軟輕垂綠玉條。',64,'全唐诗/poet.song.34000.json','["花濃新出黄金礦，枝軟輕垂綠玉條。", "正色逢人何太晚，清香到酒亦終朝。", "籬邊此意同蕭瑟，霜後無言對寂寥。", "凡卉不爲孤艷地，淵明真賞欲爭邀。"]'),
('d75c28e8-8633-4fc0-a7ac-68477fd1eb65','立春','强至','宋','宋诗','song-poetry','','[]','殘臘新春判此朝，斗寒猶未動寅杓。',64,'全唐诗/poet.song.34000.json','["殘臘新春判此朝，斗寒猶未動寅杓。", "白催曉色融冰片，綠轉風光入柳條。", "絲菜落盤隨玉手，鏤花垂勝壓金翹。", "六年不見江梅影，長覺歸心似旆摇。"]'),
('285715b5-1738-4462-89cf-aa0bfbd2caa5','次韵丁評事春雨','强至','宋','宋诗','song-poetry','','[]','溪樓燕子懶飛飛，一鼓輕雷漸作威。',64,'全唐诗/poet.song.34000.json','["溪樓燕子懶飛飛，一鼓輕雷漸作威。", "細濯林花紅抹淺，低濛岸柳翠光微。", "偶穿縱步尋山屐，且解銷憂貰酒衣。", "華表有人還未得，更堪取次送春歸。"]'),
('8c58faeb-cbe3-49c9-b93f-cbe1cafb279a','送王文玉歸浙','强至','宋','宋诗','song-poetry','','[]','插旗打鼓放船頭，二紀蓬萊一夢游。',64,'全唐诗/poet.song.34000.json','["插旗打鼓放船頭，二紀蓬萊一夢游。", "回首誰能顧庭鷺，收心自可近江鷗。", "盤堆玉縷鱸初膾，盞溢金波酒旋篘。", "摩詰定懷廊廟弟，新詩未免到皇州。"]'),
('b081f364-fcd3-4cb9-9781-e822979e94f5','依韵和達夫泛湖之作','强至','宋','宋诗','song-poetry','','[]','雨氣隨雲却上天，山頭已掃欲晴煙。',64,'全唐诗/poet.song.34000.json','["雨氣隨雲却上天，山頭已掃欲晴煙。", "柳條不盡空圍岸，荷葉猶新未礙船。", "時序百年催樂事，乾坤一笑入詩篇。", "主人著姓平原後，莫惜金樽醉綺筵。"]'),
('79f781ca-d95b-46d3-b110-b9ba6cb5044b','賈麟自睦來杭復將如蘇戲贈短句','强至','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','春風那解繫狂遊，朝醉桐江暮柳洲。',64,'全唐诗/poet.song.34000.json','["春風那解繫狂遊，朝醉桐江暮柳洲。", "大手千篇隨電掃，孤蹤四海學雲浮。", "榮名不落閑宵夢，退築聊爲晚歲謀。", "老橘殘鱸猶有興，片心還起洞庭舟。"]'),
('f2e38458-79e5-4281-9242-ceda9f1ea521','題於潛張明甫愛拙堂','强至','宋','宋诗','song-poetry','','[]','高灑潛川愛拙翁，堂閒雅與拙情同。',64,'全唐诗/poet.song.34000.json','["高灑潛川愛拙翁，堂閒雅與拙情同。", "宦塗恥用機心達，聖世寧爲直道窮。", "千載奸纖羞白骨，一時夷坦擅清風。", "邑人三歲觀賢化，巧詆銷萌訟缿空。"]'),
('a5eba80c-cdb5-4bfe-92d6-591d47d8890c','月夜與陳行父楊公濟吳常甫出詣蔡子難','强至','宋','宋诗','song-poetry','','[]','月色無雲喜共看，葛衣藜杖到君邊。',64,'全唐诗/poet.song.34000.json','["月色無雲喜共看，葛衣藜杖到君邊。", "宦遊易作浮雲散，人事難同好月圓。", "菊露凄清吟可老，竹風幽灑坐疑仙。", "明年席上天南北，合破高齋此夜眠。"]'),
('5840540e-d22e-4fe9-ab1f-3921908dd886','丈人生辰','强至','宋','宋诗','song-poetry','','[]','纔過中元九日期，人間最重早秋時。',64,'全唐诗/poet.song.34000.json','["纔過中元九日期，人間最重早秋時。", "當年間傑凝天粹，此際生賢作吏師。", "候屬金行資義節，氣鍾庚宿究兵奇。", "願公大用齡盈百，歲歲長吟祝壽詩。"]'),
('d7c0fd92-1483-4c0a-a560-60530b7cfcd3','依韵和楊公濟喜嘉定帥王待制移成都','强至','宋','宋诗','song-poetry','','[]','把詔心先劍外飛，一身與國繫安危。',64,'全唐诗/poet.song.34000.json','["把詔心先劍外飛，一身與國繫安危。", "玉關落日辭金印，錦水春風轉繡旗。", "歷見本朝歸秉軸，多由全蜀出分麾。", "少陵漫爲知音喜，行到花溪已恐遲。"]'),
('4babc955-26fb-409c-a331-2635c7db5d0f','聞楊公濟冒寒訪契嵩上人','强至','宋','宋诗','song-poetry','','[]','凍雲朝濕萬峰寒，鑿齒辛勤訪道安。',64,'全唐诗/poet.song.34000.json','["凍雲朝濕萬峰寒，鑿齒辛勤訪道安。", "世外更無吳水石，林中還有晉衣冠。", "襟期飄灑隨煙靄，詩句縱橫出肺肝。", "見說松門長不鎖，夜凉猶過別山看。"]'),
('b02ba5e7-1d4b-439d-812d-7175a54fcca3','楊公濟歲暮惠酒','强至','宋','宋诗','song-poetry','','[]','紺瓶白酒下吟堂，洗盞傾甆肯漫嘗。',64,'全唐诗/poet.song.34000.json','["紺瓶白酒下吟堂，洗盞傾甆肯漫嘗。", "寒屋自融春日面，煖杯能轉少年腸。", "山妻相對驚愁破，稚子無端笑飲狂。", "百歲光陰空自遠，醉時苦短醒時長。"]'),
('cdc2be98-beda-4921-bd9e-4717a187fdd8','經春久雨未嘗尋芳舟次黎驛始見桃李紅白成陣愛而有題','强至','宋','宋诗','song-poetry','','[]','春風不散三冬雪，暖日猶明五月霞。',64,'全唐诗/poet.song.34000.json','["春風不散三冬雪，暖日猶明五月霞。", "病眼漫開常見雨，客顔新破始逢花。", "故園何在情還劇，舊驛空存使轉賒。", "白白朱朱今頗驗，退之詩句亦天葩。"]'),
('5a68a238-9aab-41da-9d4f-c56769c400b1','曉出','强至','宋','宋诗','song-poetry','','[]','一聲殘角繞千門，霜氣涵空亂宿氛。',64,'全唐诗/poet.song.34000.json','["一聲殘角繞千門，霜氣涵空亂宿氛。", "車馬往來無僻地，星河收去有閑雲。", "余生慘淡身宜佚，人事崎嶇足反勤。", "漸喜太陽浮海面，群鴉鳴噪尚紛紛。"]'),
('55f37f64-32c7-44a5-9e7e-ce8506dc1799','依韵和酬楊公濟澄江見寄長句','强至','宋','宋诗','song-poetry','','[]','子美幕中贍暇日，喜傳幽事到京華。',64,'全唐诗/poet.song.34000.json','["子美幕中贍暇日，喜傳幽事到京華。", "地偏浙水開孤壘，風散江雲覆萬家。", "日出魚蝦來早市，潮空鳬雁落晴沙。", "羨君吏隠能終歲，却恨吾游未有涯。"]'),
('3a0184c1-cba8-4c66-8641-c4721ac16d5b','九日至嘉禾','强至','宋','宋诗','song-poetry','','[]','登高時節異鄉中，回首家山隔亂峰。',64,'全唐诗/poet.song.34000.json','["登高時節異鄉中，回首家山隔亂峰。", "白酒莫辭今日醉，黄花不似故園逢。", "苦嗟節物經秋老，贏得情懷爲別濃。", "却愛紫微詩意好，笑歌開口强爲容。"]'),
('0c97b877-1c15-4176-9af7-68e8a60adf25','知郡都官示答盱眙周令詩有感而作','强至','宋','宋诗','song-poetry','','[]','臨淮郡事素稱繁，太守才明此典藩。',64,'全唐诗/poet.song.34000.json','["臨淮郡事素稱繁，太守才明此典藩。", "每歲欲甄群吏狀，是人思出大賢門。", "孤生自恨方趨走，末跡無緣被薦論。", "異日願公持大柄，畢身猶足望洪恩。"]'),
('cf8b6278-f7a2-400e-be33-c35e924ee1c3','送前水監王仲賢郎中赴闕','强至','宋','宋诗','song-poetry','','[]','素節清明照水臺，夷塗行騁忽徘徊。',64,'全唐诗/poet.song.34000.json','["素節清明照水臺，夷塗行騁忽徘徊。", "驚人險句何妨露，向闕丹心未可灰。", "馬勒春風朝弁集，雞呼曉日禁門開。", "從來早賜清閒對，不信君王肯棄才。"]'),
('9bffe512-eec9-469d-b548-8749f3e212b2','病起偶書','强至','宋','宋诗','song-poetry','','[]','病眠官舍趣方高，强起區區視冗曹。',64,'全唐诗/poet.song.34000.json','["病眠官舍趣方高，强起區區視冗曹。", "當世纖機漫蝸角，除身萬事盡鴻毛。", "田園歸去古稱達，軒冕儻來人自勞。", "汩沒青衫逾壯歲，窮通一任大鈞陶。"]'),
('ef60b275-2089-4305-b447-f02e71b8e3d4','感懷寄楊公濟','强至','宋','宋诗','song-poetry','','[]','身世飄颻水上萍，時情暗淡草邊螢。',64,'全唐诗/poet.song.34000.json','["身世飄颻水上萍，時情暗淡草邊螢。", "百年日月空憂喜，一笑乾坤任醉醒。", "此外浮沈俱委命，相逢汝我即忘形。", "尋山各有襄陽馬，莫遣題詩筆暫停。"]'),
('03bed7b0-b7a9-4205-8aff-4af1ba615acb','冬盡日睢陽感事','强至','宋','宋诗','song-poetry','','[]','天邊愁緒細如毛，眼底詩情付濁醪。',64,'全唐诗/poet.song.34000.json','["天邊愁緒細如毛，眼底詩情付濁醪。", "張許忠魂空日月，鄒枚樂事委蓬蒿。", "積成鄉思心頻折，送盡年華首重搔。", "杜子南賓猶此日，主人恩意覺徒勞。"]'),
('c9887036-dd79-4b27-9cd6-d862962f1cfa','依韵和尹嗣復仲春會食船場','强至','宋','宋诗','song-poetry','','[]','野色寬圍四繚牆，一穿林徑百憂忘。',64,'全唐诗/poet.song.34000.json','["野色寬圍四繚牆，一穿林徑百憂忘。", "濃花細草青春半，語燕游蜂白日長。", "寄興不知詩筆倦，惜時猶喜酒杯香。", "席間數點殘英墜，萬片隨風此濫觴。"]'),
('dba55178-7cf7-4fd2-b883-8aa87c0ec1ef','次韵酬禮之見貽','强至','宋','宋诗','song-poetry','','[]','慶曆天王設網羅，君時遺俊我登科。',64,'全唐诗/poet.song.34000.json','["慶曆天王設網羅，君時遺俊我登科。", "當時未識名猶熟，此日相逢分固多。", "摩戛青雲知志在，驚嗟素業怵時過。", "朱顔皓齒偷歡處，暫置功名任酒酡。"]');
